insert into questions(id,section_id,prompt,justification) values (1,1,'¿Qué significa que GBM Advisory sea asesoría personalizada?','Advisory personaliza la estrategia al plan de vida y a los objetivos de cada cliente; no aplica recetas iguales para todos ni se limita a un segmento patrimonial. Su esencia es la planeación financiera y de ahorro adaptada a la situación particular de la persona.');
insert into questions(id,section_id,prompt,justification) values (2,1,'¿Qué rol cumple el coaching conductual en Advisory?','El coaching conductual ayuda al cliente a sostener su plan y a evitar decisiones emocionales en momentos de volatilidad, dándole certeza frente a la incertidumbre del mercado. Es una de las mayores fuentes de valor del asesor (Advisor&#x27;s Alpha), no un sustituto del análisis de datos.');
insert into questions(id,section_id,prompt,justification) values (3,1,'¿Cuál es el primer paso de la metodología Invierte con Propósito?','La metodología &#x27;Invierte con Propósito&#x27; parte de definir objetivos y un plan financiero claro antes de elegir cualquier instrumento. Sin un plan que dé rumbo, las decisiones de inversión se vuelven reactivas y desordenadas.');
insert into questions(id,section_id,prompt,justification) values (4,1,'¿Qué representa el Portafolio 1 en Invierte con Propósito?','El Portafolio 1 cubre las necesidades inmediatas o de corto plazo, es decir, la liquidez para el día a día. Es la base de la pirámide, previa a los cajones de emergencia, objetivos y crecimiento.');
insert into questions(id,section_id,prompt,justification) values (5,1,'¿Qué portafolio debe cubrir al menos 3–6 meses de gastos básicos?','El fondo de emergencia debe cubrir de 3 a 6 meses de gastos básicos en instrumentos líquidos y seguros. Su función es proteger al cliente ante imprevistos sin obligarlo a liquidar inversiones de largo plazo en un mal momento.');
insert into questions(id,section_id,prompt,justification) values (6,1,'¿Cuál es el horizonte mínimo recomendado para el portafolio de diversificación global?','La diversificación global en renta variable requiere un horizonte mínimo de alrededor de 5 años para absorber la volatilidad de corto plazo y capturar la prima de las acciones. Plazos menores exponen al cliente a tener que vender en una caída.');
insert into questions(id,section_id,prompt,justification) values (7,1,'Un cliente quiere ahorrar para la universidad de su hijo en 15 años. ¿Qué portafolio usar?','Una meta a 15 años, como la universidad de un hijo, corresponde al portafolio de objetivos específicos, con horizonte y asignación acordes a esa meta concreta. No es ni el fondo de emergencia ni el de necesidades inmediatas.');
insert into questions(id,section_id,prompt,justification) values (8,1,'¿Qué significa la metodología &quot;págate a ti primero&quot;?','&#x27;Págate a ti primero&#x27; significa apartar el ahorro y la inversión al recibir el ingreso, antes de gastar. Convierte el ahorro en un hábito automático en lugar de dejarlo como un residuo incierto al final del mes.');
insert into questions(id,section_id,prompt,justification) values (9,1,'¿Cuál es la ventaja del interés compuesto al invertir?','El interés compuesto reinvierte los rendimientos, generando rendimientos sobre los rendimientos ya acumulados. Con el tiempo, este efecto acelera de forma exponencial el crecimiento del capital, premiando al inversionista paciente.');
insert into questions(id,section_id,prompt,justification) values (10,1,'¿Cuánto valor puede añadir un asesor financiero por año según estudios de Vanguard y Russell?','Estudios de Vanguard (Advisor&#x27;s Alpha) y Russell estiman que un asesor puede añadir alrededor de 3% anual, principalmente a través del coaching conductual, el rebalanceo, la gestión de costos y la eficiencia fiscal. Es valor neto potencial, no una garantía de rendimiento.');
insert into questions(id,section_id,prompt,justification) values (11,1,'¿Qué frase de Warren Buffett se asocia a la paciencia en inversión?','La frase &#x27;el mercado transfiere dinero de los impacientes a los pacientes&#x27; resume que la disciplina y la paciencia son recompensadas en la inversión de largo plazo. Refuerza el papel del asesor como coach conductual del cliente.');
insert into questions(id,section_id,prompt,justification) values (12,1,'¿Qué significa riesgo sistemático?','El riesgo sistemático afecta a todo el mercado (tasas, recesiones, geopolítica) y no se puede eliminar diversificando. Es precisamente el riesgo por el que el inversionista recibe una prima de rendimiento.');
insert into questions(id,section_id,prompt,justification) values (13,1,'¿Qué significa riesgo idiosincrático?','El riesgo idiosincrático es propio de una empresa o sector y sí se reduce mediante la diversificación. Por eso el mercado no paga una prima por asumirlo de forma concentrada: es un riesgo evitable.');
insert into questions(id,section_id,prompt,justification) values (14,1,'¿Qué postula la Hipótesis de los Mercados Eficientes (EMH)?','La Hipótesis de los Mercados Eficientes sostiene que los precios reflejan toda la información disponible, lo que hace muy difícil batir al mercado de forma consistente. Es el fundamento teórico de la inversión indexada y de bajo costo.');
insert into questions(id,section_id,prompt,justification) values (15,1,'¿Por qué ganarle al mercado es un juego de suma cero?','Antes de costos, el conjunto de inversionistas activos no puede superar al mercado: por cada uno que gana de más, otro gana de menos. Tras descontar comisiones, el agregado queda por debajo del mercado (ver Fama-French 2010, Sección 18).');
insert into questions(id,section_id,prompt,justification) values (16,1,'¿Cuál es la diferencia clave entre inversión activa y pasiva?','La gestión activa intenta superar al mercado seleccionando valores, mientras que la pasiva simplemente lo replica a bajo costo. La evidencia muestra que superar al mercado de forma consistente y neta de comisiones es muy difícil.');
insert into questions(id,section_id,prompt,justification) values (17,1,'¿Qué impacto tienen los fees en la inversión a largo plazo?','Las comisiones se restan año con año y, por el efecto del interés compuesto, su impacto se magnifica en el largo plazo. Minimizar costos es una de las palancas más directas y confiables del rendimiento neto (Advisor&#x27;s Alpha).');
insert into questions(id,section_id,prompt,justification) values (18,1,'¿Qué significa que un SMA esté etiquetado como SMA_ICP?','La etiqueta ICP indica que el SMA es exclusivo de Advisory y está vinculado al plan financiero (Inversión con Propósito) del cliente. No es un producto de trading abierto ni de libre acceso.');
insert into questions(id,section_id,prompt,justification) values (19,1,'¿Qué debe hacer Advisory si un cliente pide stock picks?','Advisory no hace selección de acciones; si el cliente busca stock picks, se le canaliza al producto adecuado de Soluciones de Inversión (por ejemplo, Top Picks). Así se respeta la naturaleza de cada servicio.');
insert into questions(id,section_id,prompt,justification) values (20,1,'¿Cuál es la diferencia clave entre Advisory y Soluciones de Inversión?','Advisory es el servicio de planeación financiera y de ahorro, mientras que Soluciones de Inversión distribuye los productos. Son complementarios: el plan financiero define qué productos conviene utilizar.');
insert into questions(id,section_id,prompt,justification) values (21,1,'¿Qué objetivo cumple la optimización en Advisory?','La optimización en Advisory busca mejorar el resultado neto del cliente ajustando la asignación de activos, las divisas, la fiscalidad y la custodia. No se trata de elegir acciones de moda, sino de eficientar el portafolio integral.');
insert into questions(id,section_id,prompt,justification) values (22,1,'¿Cuál es la principal consecuencia de invertir sin un plan financiero?','Sin un plan financiero, el inversionista tiende a reaccionar emocionalmente a la volatilidad, lo que suele destruir valor (el llamado behavior gap). El plan ancla la conducta y mejora los resultados de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (23,1,'¿Cuál es el principal aporte de un asesor financiero al cliente?','El mayor aporte del asesor no es elegir las inversiones &#x27;más rentables&#x27; ni garantizar que no haya pérdidas, sino acompañar al cliente con planeación, disciplina y coaching conductual. Ahí reside la mayor parte de su valor agregado.');
insert into questions(id,section_id,prompt,justification) values (24,1,'¿Qué beneficio tiene diversificar un portafolio de inversión?','La diversificación reduce el riesgo idiosincrático y mejora la relación rendimiento/riesgo, pero no elimina el riesgo sistemático ni garantiza ganarle al mercado. Es la única &#x27;comida gratis&#x27; ampliamente reconocida en finanzas.');
insert into questions(id,section_id,prompt,justification) values (25,1,'¿Qué enseñanza práctica transmite Advisory sobre paciencia?','Advisory enseña a sostener el plan a través de los ciclos de mercado en lugar de operar por impulso. La paciencia es lo que permite capturar la prima de largo plazo y evitar el costo de un mal timing.');
insert into questions(id,section_id,prompt,justification) values (26,2,'¿Cuál es la función principal de Soluciones de Inversión en GBM?','Soluciones de Inversión es el área que distribuye todo el catálogo de productos de inversión de GBM (fondos, SMAs, etc.). Advisory, en cambio, se encarga de la planeación financiera del cliente.');
insert into questions(id,section_id,prompt,justification) values (27,2,'Cliente trader que pide stock picks constantes: ¿qué producto le corresponde?','Un cliente que pide stock picks constantes encaja con Top Picks (ideas de acciones de los analistas de GBM), no con un SMA conservador ni con fondos de deuda. Es la vía adecuada para una necesidad activa de selección de acciones.');
insert into questions(id,section_id,prompt,justification) values (28,2,'Un cliente busca deuda global en pesos con cobertura cambiaria a MXN. ¿Qué fondo cumple esto?','GBMDINT ofrece renta fija global con cobertura cambiaria a pesos, es decir, exposición a deuda internacional sin el riesgo del tipo de cambio. Además, tiene la ventaja fiscal de tributar como renta variable.');
insert into questions(id,section_id,prompt,justification) values (29,2,'En GBMDOL, el inversionista acepta:','Al invertir en instrumentos denominados en dólares sin cobertura, el inversionista de GBMDOL asume el riesgo de que el tipo de cambio peso-dólar se mueva en su contra. Su resultado medido en pesos depende del USD/MXN.');
insert into questions(id,section_id,prompt,justification) values (30,2,'El GBMUSD se distingue de GBMDOL porque:','GBMUSD se distingue de GBMDOL por enfocarse en bonos corporativos de mediano plazo en dólares, con mayor duración y riesgo de crédito. Ambos están denominados en dólares, pero su perfil de riesgo difiere.');
insert into questions(id,section_id,prompt,justification) values (31,2,'Caso práctico: cliente conservador quiere solo bonos del gobierno mexicano. ¿Qué fondo recomendarías?','Para un cliente que solo quiere deuda del gobierno mexicano, GBMGUB invierte 100% en instrumentos gubernamentales, lo que elimina el riesgo de crédito. Es la opción más conservadora del anaquel para ese mandato.');
insert into questions(id,section_id,prompt,justification) values (32,2,'La diferencia entre GMP y GMP+ está en:','GMP y GMP+ se diferencian en la proporción de bonos y acciones globales que mantienen (GMP+ con mayor peso en renta variable). Esto permite escalar el nivel de riesgo según el perfil del cliente.');
insert into questions(id,section_id,prompt,justification) values (33,2,'Si un cliente busca mezcla 70% bonos / 30% acciones globales, ¿qué fondo aplicar?','Una mezcla aproximada de 70% bonos y 30% acciones globales corresponde al perfil más balanceado-conservador (GMP) frente a GMP+, que lleva más acciones. La proporción entre clases define el nivel de riesgo del fondo.');
insert into questions(id,section_id,prompt,justification) values (34,2,'¿Qué estrategia sigue GBMINT?','GBMINT busca superar al S&amp;P 500 invirtiendo en empresas estadounidenses de alto crecimiento. Es una estrategia activa de renta variable, no un fondo de deuda.');
insert into questions(id,section_id,prompt,justification) values (35,2,'El fondo GBMTRV se centra en:','GBMTRV se centra en acciones globales con momentum positivo (tendencia de precios al alza). Aplica en la práctica el factor momentum revisado en la Sección 13.');
insert into questions(id,section_id,prompt,justification) values (36,2,'GBMAAA (Global Thematic) invierte en:','GBMAAA (Global Thematic) invierte en torno a seis megatendencias globales, no en bonos AAA. Es renta variable temática, con mayor concentración y volatilidad que un fondo de mercado amplio.');
insert into questions(id,section_id,prompt,justification) values (37,2,'¿Qué busca GBMALFA?','GBMALFA busca generar alfa superando al IPC mediante la selección activa de las mejores ideas de inversión en México. Es una estrategia activa de renta variable local.');
insert into questions(id,section_id,prompt,justification) values (38,2,'El fondo más asociado al fenómeno de nearshoring en México es:','GBMNEAR es el fondo asociado a la tesis de nearshoring en México, es decir, a las empresas beneficiadas por la relocalización de cadenas productivas. Conecta con las FIBRAs industriales vistas en la Sección 11.');
insert into questions(id,section_id,prompt,justification) values (39,2,'¿Qué NO corresponde a un fondo de renta fija como GBMDINT o GBMGUB?','Un fondo de renta fija como GBMDINT o GBMGUB se caracteriza por baja volatilidad, posible cobertura cambiaria y horizontes acotados; el apalancamiento en acciones de EUA NO le corresponde, pues sería propio de una estrategia de renta variable.');
insert into questions(id,section_id,prompt,justification) values (40,2,'¿Qué SMA ofrece bonos globales de corto plazo con cobertura a MXN?','El SMA International Peso-Hedged de Corto Plazo ofrece bonos globales de corto plazo con cobertura a pesos. Su mecánica financiera (paridad de tasas de interés cubierta) se detalla a profundidad en la Sección 27.');
insert into questions(id,section_id,prompt,justification) values (41,2,'La diferencia entre Peso-Hedged Corto Plazo y Peso-Hedged Mediano Plazo es:','Peso-Hedged Corto Plazo y Mediano Plazo se diferencian por la duración de los bonos subyacentes y, por tanto, por su riesgo de tasa y su rendimiento. El de mediano plazo añade más duración y algo de deuda corporativa.');
insert into questions(id,section_id,prompt,justification) values (42,2,'¿Qué SMA replica todos los activos del mundo según su tamaño?','El SMA Global Market Portfolio replica el portafolio de mercado mundial ponderado por el tamaño (capitalización) de cada activo. Es la materialización práctica de la idea de &#x27;comprar el mercado&#x27; completo.');
insert into questions(id,section_id,prompt,justification) values (43,2,'¿Qué caracteriza al SMA Opportunistic US Equities?','Opportunistic US Equities emplea apalancamiento variable sobre renta variable estadounidense (enhanced beta), en línea con el factor de baja volatilidad/BAB de la Sección 13. No es un fondo de deuda mexicana ni replica el IPC.');
insert into questions(id,section_id,prompt,justification) values (44,2,'El SMA adecuado para empresas globales con momentum en precios es:','Para empresas globales con momentum en precios, el SMA Global Equity Factor aplica factores de inversión (incluido el momentum) a un universo de acciones globales. Es la estrategia factorial del anaquel.');
insert into questions(id,section_id,prompt,justification) values (45,2,'Cliente con 5M MXN líquidos busca deuda local superior a CETES 28 días. ¿Qué SMA recomendar?','Para deuda local con rendimiento superior a los CETES a 28 días, Smart Income es el SMA indicado, pues gestiona deuda local buscando batir a los CETES. No es renta variable ni una estrategia con cobertura cambiaria.');
insert into questions(id,section_id,prompt,justification) values (46,2,'Target Income se caracteriza por:','Target Income combina aproximadamente 50% acciones globales y 50% bonos gubernamentales, distribuyendo pagos periódicos por encima de los CETES. Está diseñado para generar un ingreso recurrente para el cliente.');
insert into questions(id,section_id,prompt,justification) values (47,2,'Diferencia entre Top Picks México y Top Picks Global:','La diferencia clave es el universo de inversión: Top Picks México invierte en acciones mexicanas y Top Picks Global en acciones globales. Ambos son carteras de las mejores ideas de acciones de los analistas de GBM.');
insert into questions(id,section_id,prompt,justification) values (48,2,'Cliente quiere ideas globales de analistas GBM. ¿Qué SMA elegir?','Para obtener ideas globales de los analistas de GBM, el SMA adecuado es Top Picks Global. Top Picks México se limitaría a acciones locales, sin la exposición internacional que el cliente busca.');
insert into questions(id,section_id,prompt,justification) values (49,2,'¿Qué producto tiene el arancel más alto para persona física excluyendo SMA&#x27;s ICP?','Entre las opciones señaladas (excluyendo los SMAs ICP), GBMDINT tiene el arancel más alto, acorde con su gestión de renta fija global con cobertura cambiaria. Conviene siempre ponderar el costo frente al valor agregado del producto.');
insert into questions(id,section_id,prompt,justification) values (50,2,'Producto ideal para exposición a Crypto:','Dentro de Advisory, el Blockchain SMA es el vehículo gestionado adecuado para dar exposición a cripto (IBIT es un ETF que se accede vía Soluciones/Trading, no un SMA de Advisory). Conecta con los cripto-ETFs de la Sección 12.');
insert into questions(id,section_id,prompt,justification) values (51,3,'La frontera eficiente se define como:','La frontera eficiente es el subconjunto <em>dominante</em> del conjunto factible. Cualquier portafolio por debajo de ella está dominado: existe otro con mayor rendimiento al mismo riesgo, o con menor riesgo al mismo rendimiento.');
insert into questions(id,section_id,prompt,justification) values (52,3,'Un portafolio invierte 60% en el activo A (σ = 20%) y 40% en B (σ = 10%), con correlación ρ = 0.30. La desviación estándar del portafolio es aproximadamente:','σ<sup>2</sup>p = (0.6<sup>2</sup>)(0.20<sup>2</sup>) + (0.4<sup>2</sup>)(0.10<sup>2</sup>) + 2(0.6)(0.4)(0.30)(0.20)(0.10) = 0.0144 + 0.0016 + 0.00288 = 0.01888 → σp ≈ 13.7%. El resultado es menor que el promedio ponderado de las volatilidades (16%) gracias al beneficio de diversificación, porque ρ &lt; 1.');
insert into questions(id,section_id,prompt,justification) values (53,3,'En el marco de Markowitz, el principal motor de la reducción de riesgo de un portafolio es:','Al crecer el número de activos, los términos de covarianza dominan la varianza del portafolio. Combinar activos con correlación baja o negativa reduce el riesgo total más que simplemente sumar posiciones.');
insert into questions(id,section_id,prompt,justification) values (54,3,'El portafolio de mínima varianza global (GMVP) es:','El GMVP es el punto más a la izquierda de la frontera. No coincide necesariamente con el activo de menor varianza individual, porque los efectos de covarianza pueden reducir el riesgo por debajo del de cualquier activo aislado.');
insert into questions(id,section_id,prompt,justification) values (55,3,'Al incorporar un activo libre de riesgo, el inversionista óptimo combina:','Teorema de separación de dos fondos (Tobin): todos los inversionistas mantienen el mismo portafolio riesgoso óptimo —el tangente— y ajustan su nivel de riesgo prestando o pidiendo prestado a la tasa libre de riesgo.');
insert into questions(id,section_id,prompt,justification) values (56,3,'A medida que se añaden activos a un portafolio bien diversificado:','La diversificación elimina el riesgo idiosincrático, pero el riesgo de mercado (sistemático) no es diversificable y constituye el límite inferior de la varianza del portafolio.');
insert into questions(id,section_id,prompt,justification) values (57,3,'Con Rf = 4%, rendimiento esperado del mercado E(Rm) = 10% y β = 1.3, el rendimiento esperado del activo según el CAPM es:','E(R) = Rf + β·[E(Rm) − Rf] = 4% + 1.3·(10% − 4%) = 4% + 7.8% = 11.8%.');
insert into questions(id,section_id,prompt,justification) values (58,3,'Un activo con β = 0 tiene, según el CAPM:','E(R) = Rf + 0·(prima de mercado) = Rf. Un beta de cero implica nula correlación con el mercado, pero el activo puede tener riesgo idiosincrático: su riesgo total no es necesariamente cero.');
insert into questions(id,section_id,prompt,justification) values (59,3,'La diferencia clave entre la Línea del Mercado de Capitales (CML) y la Línea del Mercado de Valores (SML) es:','El eje horizontal de la CML es σ (riesgo total); el de la SML es β (riesgo sistemático). Por eso la SML permite valuar activos individuales aunque no sean eficientes.');
insert into questions(id,section_id,prompt,justification) values (60,3,'¿Cuál NO es un supuesto del CAPM?','El CAPM se construye sobre mercados eficientes y expectativas homogéneas. Batir al mercado de forma sistemática contradice directamente sus supuestos.');
insert into questions(id,section_id,prompt,justification) values (61,3,'Un activo tiene un rendimiento requerido por CAPM de 11.8%, pero el análisis fundamental proyecta un rendimiento esperado de 13.5%. El activo está:','Alfa de Jensen = rendimiento esperado − rendimiento requerido = 13.5% − 11.8% = +1.7%. Un alfa positivo señala un activo atractivo/subvaluado, que gráficamente se ubica por encima de la SML.');
insert into questions(id,section_id,prompt,justification) values (62,3,'La prima de riesgo de mercado se define como:','Es el exceso de rendimiento esperado del mercado sobre la tasa libre de riesgo. La opción d) corresponde a la prima de riesgo del <em>activo</em>, no del mercado.');
insert into questions(id,section_id,prompt,justification) values (63,3,'Un ejemplo de riesgo sistemático es:','El riesgo sistemático afecta a todo el mercado (tasas, inflación, recesión, shocks geopolíticos) y no se diversifica. Los demás son eventos idiosincráticos, propios de una empresa.');
insert into questions(id,section_id,prompt,justification) values (64,3,'El riesgo no sistemático (idiosincrático):','Como puede eliminarse mediante diversificación, el mercado no paga prima por asumirlo. Solo se recompensa el riesgo sistemático (no diversificable).');
insert into questions(id,section_id,prompt,justification) values (65,3,'El riesgo total de un activo se descompone en:','σ<sup>2</sup>total = riesgo sistemático (β<sup>2</sup>·σ<sup>2</sup>m) + riesgo específico (varianza de los residuales). La diversificación reduce el segundo componente, no el primero.');
insert into questions(id,section_id,prompt,justification) values (66,3,'En equilibrio CAPM, dos activos con el mismo beta pero distinto riesgo total tendrán:','El CAPM solo premia el riesgo no diversificable. La diferencia en riesgo total proviene del componente idiosincrático, que el mercado no recompensa.');
insert into questions(id,section_id,prompt,justification) values (67,3,'El modelo de tres factores de Fama-French (1993) añade al factor de mercado:','FF3: exceso de mercado (Rm − Rf) + SMB (<em>small minus big</em>, tamaño) + HML (<em>high minus low</em> book-to-market, valor).');
insert into questions(id,section_id,prompt,justification) values (68,3,'El factor SMB captura:','SMB = <em>small minus big</em>: rendimiento de un portafolio de empresas pequeñas menos uno de empresas grandes. Recoge la prima de tamaño.');
insert into questions(id,section_id,prompt,justification) values (69,3,'El factor HML representa el rendimiento de:','HML = <em>high minus low</em> book-to-market. Un B/M alto identifica acciones de valor; el factor captura la prima histórica de <em>value</em> sobre <em>growth</em>.');
insert into questions(id,section_id,prompt,justification) values (70,3,'El modelo de cinco factores de Fama-French (2015) incorpora, además de mercado, tamaño y valor:','RMW = <em>robust minus weak</em> (rentabilidad operativa); CMA = <em>conservative minus aggressive</em> (política de inversión/crecimiento de activos). El factor momentum (WML) pertenece al modelo de cuatro factores de Carhart (1997), no al FF5.');
insert into questions(id,section_id,prompt,justification) values (71,4,'La diferencia fundamental entre un error cognitivo y un sesgo emocional es que:','Es la dicotomía central del CFA. La implicación práctica para el asesor: ante errores cognitivos se <em>educa y corrige</em>; ante sesgos emocionales con frecuencia se <em>acomoda</em> el plan al sesgo en lugar de combatirlo de frente.');
insert into questions(id,section_id,prompt,justification) values (72,4,'Según la prospect theory, la función de valor es:','Kahneman y Tversky muestran que las personas evalúan resultados como ganancias o pérdidas frente a un <em>punto de referencia</em>, no como niveles de riqueza absoluta (a diferencia de la teoría de utilidad esperada). De ahí la forma en &quot;S&quot; de la función de valor.');
insert into questions(id,section_id,prompt,justification) values (73,4,'El concepto de aversión a las pérdidas implica que:','La función de valor es más empinada en pérdidas que en ganancias (relación cercana a 2:1 en los estudios de K&amp;T). Por eso la pendiente del tramo de pérdidas excede la del de ganancias.');
insert into questions(id,section_id,prompt,justification) values (74,4,'Un inversionista vende rápidamente las acciones que han subido pero conserva las que están en pérdida esperando &quot;recuperarse&quot;. Este patrón es:','El <em>disposition effect</em> describe vender ganadores demasiado pronto y mantener perdedores demasiado tiempo, para no &quot;realizar&quot; la pérdida. Es fiscalmente subóptimo (difiere ganancias y retiene pérdidas no aprovechadas).');
insert into questions(id,section_id,prompt,justification) values (75,4,'La teoría de utilidad esperada se distingue de la prospect theory principalmente porque:','Diferencias clave: dependencia del punto de referencia, asimetría ganancia/pérdida y <em>probability weighting</em> (sobreponderar probabilidades pequeñas y subponderar las grandes).');
insert into questions(id,section_id,prompt,justification) values (76,4,'Un analista mantiene su recomendación de &quot;compra&quot; y solo busca noticias que la respalden, ignorando los reportes que la contradicen. Esto es:','El <em>confirmation bias</em> lleva a buscar y sobrevalorar evidencia que confirma la creencia previa y a descartar la que la refuta.');
insert into questions(id,section_id,prompt,justification) values (77,4,'Un cliente concluye que &quot;es una empresa excelente, por lo tanto es una excelente inversión&quot;, sin analizar la valuación. Comete:','La <em>representatividad</em> clasifica algo por su parecido con un estereotipo. Confundir &quot;buena empresa&quot; con &quot;buena inversión&quot; ignora el precio pagado —enlaza directamente con el deck <em>Buena empresa vs. buena inversión</em>.');
insert into questions(id,section_id,prompt,justification) values (78,4,'Un analista fija su estimación de precio objetivo demasiado cerca de la cotización actual y la ajusta de forma insuficiente ante nueva información relevante. Esto es:','El <em>anchoring and adjustment</em> hace que un valor de referencia inicial domine el juicio, y los ajustes posteriores resulten insuficientes.');
insert into questions(id,section_id,prompt,justification) values (79,4,'Un inversionista separa mentalmente su &quot;dinero de dividendos&quot; (para gastar) de su &quot;capital&quot; (intocable) y los gestiona con reglas distintas e incoherentes. Comete:','El <em>mental accounting</em> trata el dinero de forma distinta según su origen o etiqueta, en vez de evaluar el portafolio de manera integral; puede llevar a estructuras subóptimas (p. ej., perseguir rendimiento por dividendos descuidando el rendimiento total).');
insert into questions(id,section_id,prompt,justification) values (80,4,'Tras una caída de mercado muy difundida en los medios, un cliente sobreestima la probabilidad de un nuevo desplome y reduce su exposición. Esto refleja:','La <em>disponibilidad</em> lleva a estimar probabilidades por la facilidad con que vienen ejemplos a la mente; eventos recientes y mediáticos se sobrevaloran.');
insert into questions(id,section_id,prompt,justification) values (81,4,'Un inversionista tarda en incorporar a su tesis un cambio estructural confirmado por datos nuevos y se aferra a su visión previa. Esto es:','El <em>conservadurismo</em> es lo opuesto a la sobrerreacción: las creencias previas se actualizan con demasiada lentitud frente a evidencia nueva válida.');
insert into questions(id,section_id,prompt,justification) values (82,4,'Después de un evento, un inversionista afirma &quot;era obvio que iba a pasar&quot;, sobrestimando su capacidad previa de predecirlo. Esto es:','El <em>hindsight bias</em> (&quot;lo sabía desde el principio&quot;) distorsiona la memoria de lo que realmente se anticipó e infla la confianza en la propia habilidad predictiva.');
insert into questions(id,section_id,prompt,justification) values (83,4,'Un asesor presenta la misma estrategia a dos clientes: a uno le dice que &quot;tiene 90% de probabilidad de conservar el capital&quot; y al otro que &quot;tiene 10% de probabilidad de perder&quot;. El segundo la rechaza. Esto ilustra:','El <em>framing</em> (encuadre de ganancia vs. pérdida) altera la elección pese a tratarse de información equivalente. Es un error cognitivo de procesamiento de información.');
insert into questions(id,section_id,prompt,justification) values (84,4,'El exceso de confianza en la inversión se clasifica como sesgo emocional y suele manifestarse en:','El <em>overconfidence</em> (en sus formas de predicción y de certeza) lleva a intervalos de confianza demasiado estrechos, rotación elevada que erosiona el rendimiento neto y carteras poco diversificadas.');
insert into questions(id,section_id,prompt,justification) values (85,4,'Un cliente cree que operar con mayor frecuencia y &quot;estar encima del mercado&quot; mejora sus resultados, atribuyéndose un control que no tiene. Comete:','La <em>ilusión de control</em> hace creer que se puede influir en resultados esencialmente aleatorios; alimenta el trading excesivo y la subdiversificación.');
insert into questions(id,section_id,prompt,justification) values (86,4,'Un cliente se niega a vender acciones heredadas de su padre, a las que asigna un valor superior al que pagaría por ellas hoy. Esto es:','El <em>endowment effect</em> hace que se valore más un activo por el solo hecho de poseerlo; genera concentración y resistencia a rebalancear.');
insert into questions(id,section_id,prompt,justification) values (87,4,'Un inversionista evita tomar decisiones de inversión por temor a equivocarse y lamentarlo después, por lo que se mantiene en exceso de liquidez o sigue a la mayoría. Esto es:','La <em>aversión al arrepentimiento</em> lleva a la inacción (errores de omisión) o a refugiarse en el consenso (herding) para diluir la responsabilidad de una decisión que pudiera salir mal.');
insert into questions(id,section_id,prompt,justification) values (88,4,'En un plan de retiro con asignación por defecto, la mayoría de los empleados nunca la modifica, aun cuando no se ajusta a su perfil. Esto ilustra:','El <em>status quo bias</em> describe la inercia a mantener la situación actual o la opción por defecto. Es la base del diseño de <em>defaults</em> y autoenrolamiento en sistemas de pensiones.');
insert into questions(id,section_id,prompt,justification) values (89,4,'Un cliente posterga sistemáticamente el ahorro para el retiro y prioriza el consumo presente, en contra de sus propias metas de largo plazo. Esto es:','El <em>self-control bias</em> privilegia la gratificación inmediata sobre los objetivos de largo plazo; deriva en subahorro y en sobreponderar activos de ingreso corriente para &quot;gastar sin tocar el capital&quot;.');
insert into questions(id,section_id,prompt,justification) values (90,4,'La razón principal por la que las desviaciones de precio de origen conductual pueden persistir y no ser corregidas de inmediato por los arbitrajistas es:','Aun habiendo arbitrajistas racionales, los <em>límites al arbitraje</em> (Shleifer y Vishny) impiden corregir el mispricing: el horizonte y el capital del arbitrajista son finitos, y la posición contraria puede volverse más cara antes de converger al valor justo.');
insert into questions(id,section_id,prompt,justification) values (91,5,'En el marco Vanguard Advisor&#x27;s Alpha, &quot;alpha del asesor&quot; significa:','El concepto reencuadra el &quot;valor&quot; del asesor: no es generar alfa de mercado (juego de suma cero y difícil por la EMH), sino las decisiones de wealth management que mejoran el resultado neto del cliente. Conecta directamente con la pregunta 23 del examen base.');
insert into questions(id,section_id,prompt,justification) values (92,5,'Según el marco de Vanguard, el módulo que aporta el mayor valor potencial es:','El <em>behavioral coaching</em> es el componente más grande y más variable (Vanguard lo estima hasta ~1.5%), porque evita que el cliente abandone el plan en momentos de pánico o euforia —el error más costoso del inversionista.');
insert into questions(id,section_id,prompt,justification) values (93,5,'Una característica clave del valor agregado del asesor según Vanguard es que:','Vanguard advierte que el &quot;~3%&quot; no es un rendimiento adicional garantizado cada año; gran parte del valor (sobre todo el coaching) aparece de forma concentrada cuando el cliente está más tentado a equivocarse.');
insert into questions(id,section_id,prompt,justification) values (94,5,'¿Cuál es la diferencia entre &quot;alfa&quot;, &quot;Advisor&#x27;s Alpha&quot; y &quot;Gamma&quot;?','Tres conceptos distintos: alfa de inversión (mercado), Advisor&#x27;s Alpha (valor de la asesoría) y Gamma (eficiencia de la planeación, sobre todo en decumulación).');
insert into questions(id,section_id,prompt,justification) values (95,5,'El principal objetivo del rebalanceo periódico, al que Vanguard asigna ~0.14% de valor anual, es:','El rebalanceo es ante todo una herramienta de <em>control de riesgo</em>: evita que la cartera derive a una exposición no deseada. Su valor en rendimiento es modesto; su valor en gestión de riesgo y disciplina conductual es mayor.');
insert into questions(id,section_id,prompt,justification) values (96,5,'La &quot;implementación de bajo costo&quot; (Vanguard la estima en hasta ~0.30% anual) se refiere a:','El costo es uno de los pocos predictores robustos del rendimiento neto futuro: cada punto base ahorrado en comisiones se traslada directamente al rendimiento del cliente. Enlaza con la pregunta 17 del examen base (fees).');
insert into questions(id,section_id,prompt,justification) values (97,5,'Vanguard estima que el coaching conductual puede aportar:','Es el módulo de mayor magnitud y mayor dispersión, porque depende de cuántos errores conductuales (vender en pánico, perseguir modas) logre evitar el asesor en cada cliente.');
insert into questions(id,section_id,prompt,justification) values (98,5,'El principio de &quot;ubicación de activos&quot; (asset location), al que Vanguard asigna 0%–0.60%, consiste en:','<em>Asset location</em> ≠ <em>asset allocation</em>. La asignación define el qué; la ubicación define en qué tipo de cuenta (gravable vs. con beneficio fiscal) se aloja cada activo para minimizar la carga fiscal del portafolio total.');
insert into questions(id,section_id,prompt,justification) values (99,5,'La &quot;estrategia de gasto/retiro&quot; (spending strategy), a la que Vanguard asigna 0%–1.10%, agrega valor principalmente en la etapa de:','En el retiro, la <em>secuencia de retiros</em> entre tipos de cuenta tiene un impacto fiscal grande; un orden adecuado puede prolongar significativamente la vida del portafolio.');
insert into questions(id,section_id,prompt,justification) values (100,5,'¿Por qué Vanguard reporta los módulos de &quot;asignación de activos adecuada&quot; y &quot;rendimiento total vs. inversión por ingreso&quot; como &quot;&gt;0&quot; y no con una cifra puntual?','Su aporte es real pero idiosincrático: depende del punto de partida del cliente. Por eso se expresa como &quot;mayor que cero&quot; en lugar de una cifra fija.');
insert into questions(id,section_id,prompt,justification) values (101,5,'La fórmula &quot;Value of an Advisor&quot; de Russell descompone el valor del asesor en componentes que típicamente incluyen:','Russell estructura el valor como la suma de varios servicios; su total suele situarse por encima del de Vanguard (alrededor de ~5%, según el año) por diferencias de metodología y de componentes considerados.');
insert into questions(id,section_id,prompt,justification) values (102,5,'En la fórmula de Russell, el componente que suele aportar el mayor valor es:','Coincide con Vanguard: el mayor valor proviene de evitar las decisiones emocionales del inversionista, no de la selección de instrumentos.');
insert into questions(id,section_id,prompt,justification) values (103,5,'El concepto de &quot;Gamma&quot; de Morningstar (Blanchett y Kaplan) mide:','Gamma se centra en la <em>eficiencia de la planeación</em> (sobre todo en decumulación) más que en el rendimiento de la inversión; se expresa como ingreso de retiro adicional ajustado por utilidad.');
insert into questions(id,section_id,prompt,justification) values (104,5,'¿Cuál de las siguientes NO es uno de los componentes del Gamma de Morningstar?','Los componentes de Gamma son de planeación (asignación sobre riqueza total, retiros dinámicos, asignación a ingreso garantizado/anualidades, eficiencia fiscal en ubicación/secuencia y optimización relativa a pasivos). La selección activa de acciones no forma parte del concepto.');
insert into questions(id,section_id,prompt,justification) values (105,5,'El &quot;behavior gap&quot; (brecha de comportamiento) que documentan estudios como &quot;Mind the Gap&quot; de Morningstar describe:','El inversionista típico subdesempeña al fondo en el que invierte por mal timing de aportaciones y retiros. Cerrar esa brecha es, precisamente, lo que captura el coaching conductual.');
insert into questions(id,section_id,prompt,justification) values (106,5,'Un fondo promedió 7.0% anual en una década, pero el inversionista promedio en ese fondo obtuvo 5.5%. El behavior gap anual es de:','Behavior gap = rendimiento del fondo − rendimiento del inversionista = 7.0% − 5.5% = 1.5%. Esa brecha es el valor que el coaching conductual busca recuperar manteniendo al cliente invertido y disciplinado.');
insert into questions(id,section_id,prompt,justification) values (107,5,'El coaching conductual agrega valor sobre todo porque ayuda al cliente a:','El coaching opera directamente sobre los sesgos del Bloque 4 (aversión a las pérdidas, efecto disposición, representatividad, herding). Su valor es conductual, no predictivo.');
insert into questions(id,section_id,prompt,justification) values (108,5,'Aplicando la ubicación de activos a un cliente mexicano con una cuenta de inversión gravable y un PPR (Plan Personal de Retiro), el criterio general sería:','El principio de asset location busca minimizar la carga fiscal del portafolio total: el ingreso gravado de forma recurrente se beneficia más del escudo fiscal. (Ajustar siempre a las reglas vigentes de LISR y a los límites de aportación deducible del PPR.)');
insert into questions(id,section_id,prompt,justification) values (109,5,'Una cartera objetivo 60/40 derivó a 70/30 tras un rally accionario y hoy vale 1,000,000 MXN. Para rebalancear a la meta, el asesor debe:','Rebalancear impone disciplina de &quot;vender lo que subió y comprar lo que se quedó atrás&quot;: 70% de 1,000,000 = 700k en acciones; la meta es 600k, así que se venden 100k de acciones y se llevan a renta fija (300k → 400k). Reduce el riesgo de vuelta al perfil objetivo.');
insert into questions(id,section_id,prompt,justification) values (110,5,'¿Cómo se conecta el módulo de &quot;optimización&quot; de GBM Advisory (eficientizar asset allocation, divisas, impuestos y custodia) con el marco Advisor&#x27;s Alpha?','Los cuatro ejes de optimización de GBM (asset allocation, divisas, impuestos, custodia) son módulos de Advisor&#x27;s Alpha traducidos al contexto mexicano; junto con el coaching conductual conforman la propuesta de valor de Advisory frente a Soluciones de Inversión (preguntas 20 y 21 del examen base).');
insert into questions(id,section_id,prompt,justification) values (111,6,'La asignación estratégica de activos (SAA) o &quot;portafolio de política&quot; se define como:','La SAA es la decisión de política de largo plazo (el <em>policy portfolio</em>), derivada del perfil de riesgo-rendimiento y las restricciones del cliente. Es el punto de referencia frente al cual se mide cualquier desviación.');
insert into questions(id,section_id,prompt,justification) values (112,6,'La diferencia entre asignación estratégica (SAA) y táctica (TAA) es que la TAA:','La TAA se mueve <em>alrededor</em> de la SAA: son apuestas activas de corto plazo (sobre clases de activos) que buscan valor agregado, asumiendo más riesgo activo respecto al ancla estratégica.');
insert into questions(id,section_id,prompt,justification) values (113,6,'El conocido hallazgo de Brinson (y la precisión posterior de Ibbotson y Kaplan) sobre la asignación de activos establece correctamente que:','Es la interpretación más malentendida del estudio. La asignación explica ~90% de la <em>variabilidad temporal</em> de los rendimientos de un fondo; explica una fracción mucho menor (~40%) de las diferencias <em>entre</em> fondos, y en promedio ~100% del nivel (porque la gestión activa es, en agregado, un juego de suma cero antes de costos).');
insert into questions(id,section_id,prompt,justification) values (114,6,'El Investment Policy Statement (IPS) de un cliente debe especificar principalmente:','El IPS formaliza objetivos (rendimiento/riesgo) y restricciones (horizonte temporal, liquidez, impuestos, marco legal y necesidades únicas). Es el documento del que se deriva la SAA.');
insert into questions(id,section_id,prompt,justification) values (115,6,'La asignación basada en metas (goals-based), como la de Invierte con Propósito, se distingue de la optimización media-varianza tradicional porque:','El enfoque por metas usa de forma <em>constructiva</em> la contabilidad mental: cada cajón (necesidades inmediatas, emergencia, objetivos, etc.) tiene su propio horizonte y perfil de riesgo. Es menos eficiente en teoría de cartera pura, pero más alineado con la conducta y los objetivos reales del cliente.');
insert into questions(id,section_id,prompt,justification) values (116,6,'Cuando la capacidad de un cliente para asumir riesgo (situación financiera) y su disposición (psicológica) entran en conflicto, la práctica recomendada es:','Tomar el menor de los dos es prudente; si la disposición es el factor limitante (subjetivo), el asesor puede educar para acercarla a la capacidad, pero no debe imponer un riesgo que el cliente no tolerará en una caída.');
insert into questions(id,section_id,prompt,justification) values (117,6,'A igualdad de otros factores, un mayor horizonte de inversión normalmente justifica:','Coincide con la lógica de Invierte con Propósito: el cajón de objetivos a 15 años (pregunta 7) admite más renta variable que el de necesidades inmediatas. Mayor horizonte = mayor capacidad de asumir volatilidad.');
insert into questions(id,section_id,prompt,justification) values (118,6,'En un enfoque de asignación guiado por pasivos (asset-liability / liability-driven), la cartera se construye principalmente para:','El enfoque ALM define el riesgo como la posibilidad de no cubrir el pasivo/objetivo, no como volatilidad absoluta. Es la lógica detrás de emparejar cada cajón de metas con su horizonte y necesidad.');
insert into questions(id,section_id,prompt,justification) values (119,6,'Un cliente con un salario estable de empleado público tiene un capital humano de tipo &quot;bono&quot;. La implicación para su cartera financiera es que:','En el enfoque de riqueza total, capital humano + capital financiero. Un capital humano estable (bond-like) deja espacio para más riesgo en el portafolio financiero; uno volátil (equity-like, p. ej. un comisionista) sugiere lo contrario.');
insert into questions(id,section_id,prompt,justification) values (120,6,'Un glidepath (senda de inversión) de ciclo de vida, como el de un fondo de retiro objetivo o una AFORE, consiste en:','El glidepath refleja la caída del capital humano con la edad: menos años para recuperarse de caídas → menor tolerancia al riesgo → mayor peso en renta fija. Es el diseño de los SIEFORES generacionales y los target-date funds.');
insert into questions(id,section_id,prompt,justification) values (121,6,'Los tres insumos que requiere la optimización media-varianza (MVO) para cada clase de activo son:','La MVO de Markowitz necesita rendimientos esperados, varianzas/volatilidades y la matriz de correlaciones (covarianzas) para trazar la frontera eficiente.');
insert into questions(id,section_id,prompt,justification) values (122,6,'La principal crítica práctica a la optimización media-varianza es que:','La MVO sobrepondera activos con rendimiento esperado sobreestimado y correlación subestimada (&quot;error maximization&quot;). Por eso en la práctica se usan restricciones, <em>resampling</em>, Black-Litterman o asignaciones basadas en metas.');
insert into questions(id,section_id,prompt,justification) values (123,6,'¿Cómo afecta una menor correlación entre dos clases de activos al beneficio de diversificación?','Cuanto menor (o más negativa) la correlación, más se &quot;arquea&quot; la frontera hacia la izquierda y mayor es el beneficio de combinar los activos. Con correlación = 1 no hay beneficio de diversificación.');
insert into questions(id,section_id,prompt,justification) values (124,6,'Una nueva clase de activos tiene un Sharpe de 0.30; el portafolio existente tiene un Sharpe de 0.40 y la correlación entre ambos es 0.50. Según la regla de incorporación, ¿conviene añadirla?','Una clase de activos mejora el Sharpe del portafolio si Sharpe(nuevo) &gt; Sharpe(existente) × correlación. Aquí 0.30 &gt; 0.20, así que sí agrega valor pese a tener un Sharpe individual menor: su baja correlación lo compensa.');
insert into questions(id,section_id,prompt,justification) values (125,6,'La diferencia entre rebalanceo por calendario y rebalanceo por bandas (corredores) es:','Calendario = disciplina temporal simple; bandas = disciplina basada en desviación, que rebalancea solo cuando es necesario. Muchas prácticas combinan ambos (revisar en calendario, actuar si se rompe la banda).');
insert into questions(id,section_id,prompt,justification) values (126,6,'En un mercado fuertemente tendencial (al alza o a la baja sin reversión), ¿qué estrategia de rebalanceo tiende a desempeñarse mejor?','La CPPI es pro-cíclica (momentum): compra fuerza, vende debilidad, por lo que captura tendencias y ofrece un piso. La constant-mix es contraria (buy low/sell high) y brilla en mercados oscilantes/de reversión a la media, pero sufre en tendencias sostenidas.');
insert into questions(id,section_id,prompt,justification) values (127,6,'La estrategia constant-mix (rebalancear de vuelta a pesos fijos) implica un comportamiento:','Rebalancear a una mezcla fija obliga a recortar lo que se apreció (ahora sobreponderado) y reforzar lo rezagado: comportamiento contrario que también controla el riesgo de la cartera. Enlaza con el rebalanceo 60/40 de la pregunta 109.');
insert into questions(id,section_id,prompt,justification) values (128,6,'Un cliente tiene una meta de 60% renta variable con un corredor de ±5%. Tras un rally, la renta variable representa 67% de la cartera. El asesor debe:','El corredor 55%–65% se rompió al alza (67%). La regla de bandas exige rebalancear para devolver la cartera a su perfil de riesgo objetivo, no perseguir la tendencia.');
insert into questions(id,section_id,prompt,justification) values (129,6,'El &quot;home bias&quot; (sesgo doméstico) en la asignación de activos describe:','El home bias reduce los beneficios de diversificación global. Productos como GMP / Global Market Portfolio (pregunta 42) buscan precisamente exponer al cliente a los activos del mundo según su tamaño, mitigando ese sesgo.');
insert into questions(id,section_id,prompt,justification) values (130,6,'Para un objetivo de largo plazo como el retiro, fijar el objetivo de rendimiento en términos reales (ajustado por inflación) es importante porque:','En horizontes largos, la inflación erosiona el poder adquisitivo de forma compuesta. La asignación debe garantizar un rendimiento real positivo suficiente para cubrir la meta; de ahí el papel de la renta variable y los activos reales en carteras de retiro.');
insert into questions(id,section_id,prompt,justification) values (131,7,'La analogía del &quot;médico del dinero&quot; captura mejor la idea de que el asesor financiero:','El paper <em>Money Doctors</em> sostiene que el inversionista paga por confianza y tranquilidad —no por garantías de rendimiento—, igual que un paciente confía en su médico. El valor está en el proceso y la relación, no en &quot;vencer al mercado&quot;.');
insert into questions(id,section_id,prompt,justification) values (132,7,'Según el enfoque de &quot;money doctors&quot;, la confianza es central porque:','La confianza habilita la toma de riesgo. Es la misma idea de &quot;dar certeza al cliente frente a la incertidumbre&quot; (pregunta 2) y la base del coaching conductual.');
insert into questions(id,section_id,prompt,justification) values (133,7,'El principio médico &quot;primum non nocere&quot; (primero, no hacer daño) se traduce en asesoría como:','Es el deber de idoneidad (suitability): evitar el daño tiene prioridad sobre perseguir rendimiento. Un producto rentable pero inadecuado para el cliente es una &quot;mala praxis&quot;.');
insert into questions(id,section_id,prompt,justification) values (134,7,'La distinción entre un médico general y un especialista se refleja en GBM como:','El médico general coordina la salud integral y refiere al especialista cuando hace falta. Enlaza con las preguntas 19 y 20: Advisory planea; Soluciones provee el producto puntual.');
insert into questions(id,section_id,prompt,justification) values (135,7,'Antes de &quot;prescribir&quot; cualquier producto, el médico del dinero debe:','No hay prescripción sin diagnóstico. Equivale al fact-finding / KYC del que se deriva el plan (IPS). Recomendar antes de diagnosticar es mala praxis.');
insert into questions(id,section_id,prompt,justification) values (136,7,'Un cliente dice: &quot;perdí dinero en la última caída y ahora quiero algo totalmente seguro&quot;. El médico del dinero debe:','Tratar el síntoma (mover a efectivo en el peor momento) sin atender la causa (desajuste de riesgo/horizonte o falta de plan) suele cristalizar la pérdida y repetir el ciclo.');
insert into questions(id,section_id,prompt,justification) values (137,7,'Ante un cliente que opera en exceso y entra en pánico en cada caída, el &quot;diagnóstico diferencial&quot; consiste en:','Como en medicina, síntomas iguales pueden tener causas distintas. La intervención correcta (educar, reperfilar o cambiar producto) depende del diagnóstico diferencial.');
insert into questions(id,section_id,prompt,justification) values (138,7,'Los &quot;signos vitales&quot; financieros que el médico del dinero revisa antes de optimizar inversiones son:','Son la base de salud financiera. Sin esa base estable (cajones 1 y 2 de Invierte con Propósito), optimizar la cartera de inversión es prematuro.');
insert into questions(id,section_id,prompt,justification) values (139,7,'Un cliente llega con un &quot;autodiagnóstico&quot; hecho con un tip de un conocido y videos de internet. El asesor debe:','El autodiagnóstico con información genérica ignora el contexto particular del paciente. El valor profesional está en la evaluación personalizada, como una segunda opinión calificada.');
insert into questions(id,section_id,prompt,justification) values (140,7,'La &quot;receta personalizada&quot; en asesoría significa que:','Igual que un fármaco se dosifica al paciente, la asignación se ajusta al cliente. Es la esencia de &quot;asesoría personalizada&quot; (pregunta 1).');
insert into questions(id,section_id,prompt,justification) values (141,7,'La &quot;dosis&quot; o posología en la implementación de un plan sugiere:','La implementación gradual administra el riesgo de timing de entrada y la comodidad conductual del cliente, facilitando la adherencia. (No siempre maximiza el rendimiento esperado vs. invertir todo de inmediato, pero sí gestiona riesgo y conducta.)');
insert into questions(id,section_id,prompt,justification) values (142,7,'En la analogía médica, los &quot;efectos secundarios&quot; y las &quot;contraindicaciones&quot; de un producto financiero corresponden a:','Todo producto tiene riesgos que deben revelarse, y hay perfiles para los que está contraindicado. Recetar sin advertir riesgos o pese a una contraindicación es mala praxis.');
insert into questions(id,section_id,prompt,justification) values (143,7,'La &quot;adherencia al tratamiento&quot; es crítica en asesoría porque:','Como un tratamiento solo funciona si el paciente lo cumple, un buen plan solo da resultados si el cliente lo sostiene. Aquí se concentra el mayor valor del asesor (Advisor&#x27;s Alpha, Bloque 5).');
insert into questions(id,section_id,prompt,justification) values (144,7,'La &quot;medicina preventiva&quot; en finanzas se refiere a:','La prevención (protección de la base financiera) evita daños mayores y costosos. Refuerza los primeros cajones de Invierte con Propósito antes de buscar crecimiento.');
insert into questions(id,section_id,prompt,justification) values (145,7,'El &quot;chequeo periódico&quot; del médico del dinero implica que:','La situación del cliente y los mercados cambian; el seguimiento (incluido el rebalanceo) mantiene el plan alineado con los objetivos, sin sobrerreaccionar.');
insert into questions(id,section_id,prompt,justification) values (146,7,'&quot;No cambiar el tratamiento ante cada síntoma pasajero&quot; significa, en inversión:','Cambiar de estrategia constantemente (over-trading) erosiona el resultado, como interrumpir un tratamiento a la primera molestia. Conecta con la paciencia (pregunta 25) y el efecto disposición.');
insert into questions(id,section_id,prompt,justification) values (147,7,'Aplicando el concepto de &quot;triage&quot; (priorización de urgencias), el orden correcto suele ser:','El triage atiende lo más urgente primero. Una deuda de tarjeta al 40% anual o la falta de colchón de emergencia son &quot;urgencias&quot; que ningún rendimiento de cartera compensa.');
insert into questions(id,section_id,prompt,justification) values (148,7,'El médico del dinero practica una &quot;medicina basada en evidencia&quot;, lo que implica:','La asesoría seria se basa en evidencia, no en anécdotas o promesas. Las &quot;curas milagrosas&quot; (rendimientos garantizados, tips infalibles) son señales de charlatanería, no de asesoría.');
insert into questions(id,section_id,prompt,justification) values (149,7,'El equivalente al &quot;consentimiento informado&quot; en asesoría es:','Un buen médico explica el tratamiento y obtiene consentimiento informado. El objetivo es un cliente que entiende su plan, no uno que delega a ciegas; eso fortalece la adherencia y la relación.');
insert into questions(id,section_id,prompt,justification) values (150,7,'Síntesis. Un cliente llega diciendo: &quot;quiero meter todos mis ahorros en la acción de moda de la que todos hablan&quot;. Como médico del dinero, lo correcto es:','La respuesta integra todo el bloque: diagnóstico antes de prescribir, atención a la causa y la base financiera, educación sobre el riesgo (concentración, representatividad), idoneidad y dosificación, y derivación al &quot;especialista&quot; (Soluciones) con position sizing prudente. Ni complacencia ciega ni rechazo tajante: asesoría.');
insert into questions(id,section_id,prompt,justification) values (151,8,'Para un portafolio de N activos, ¿cuántas covarianzas únicas se requieren, y por qué importa?','La matriz Σ es N×N simétrica; su diagonal son las N varianzas y fuera de diagonal hay N(N−1)/2 covarianzas únicas. El número crece de forma cuadrática, y el <em>estimation error</em> asociado es la principal debilidad práctica del MVO.');
insert into questions(id,section_id,prompt,justification) values (152,8,'En el espacio media-varianza (sin activo libre de riesgo), la frontera eficiente con activos riesgosos tiene la forma de:','σ<sup>2</sup> = (Aμ₀<sup>2</sup> − 2Bμ₀ + C)/D describe una parábola en varianza, que es una hipérbola en desviación estándar. Solo al añadir un activo libre de riesgo la frontera relevante se vuelve una recta (la CML).');
insert into questions(id,section_id,prompt,justification) values (153,8,'¿Qué son los &quot;corner portfolios&quot; en la construcción de la frontera eficiente?','Los corner portfolios marcan cambios en el conjunto de activos con peso positivo. Por la linealidad entre ellos, son una forma eficiente de caracterizar toda la frontera.');
insert into questions(id,section_id,prompt,justification) values (154,8,'La pendiente de la Línea del Mercado de Capitales (CML) corresponde a:','La CML conecta Rf con el portafolio tangente, que es el de mayor Sharpe; la pendiente de esa recta es precisamente ese Sharpe ratio (exceso de rendimiento por unidad de riesgo total).');
insert into questions(id,section_id,prompt,justification) values (155,8,'En la formulación por utilidad cuadrática (maximizar wᵀμ − ½λ·wᵀΣw), el parámetro λ representa:','λ pondera la penalización por riesgo frente al rendimiento esperado. A mayor λ, el optimizador sacrifica rendimiento para reducir varianza.');
insert into questions(id,section_id,prompt,justification) values (156,8,'¿Por qué el portafolio de mínima varianza global (GMV) a menudo se desempeña mejor que el MVO completo fuera de muestra?','Al prescindir de μ̂, el GMV evita el insumo más ruidoso del MVO. DeMiguel et al. y Jagannathan-Ma documentan su mejor robustez out-of-sample.');
insert into questions(id,section_id,prompt,justification) values (157,8,'Según Chopra y Ziemba (1993), los errores de estimación en los rendimientos esperados (μ):','Por eso enfoques como Black-Litterman (que derivan μ del equilibrio) o Risk Parity/HRP (que no usan μ) reducen el problema atacando justo el insumo más sensible.');
insert into questions(id,section_id,prompt,justification) values (158,8,'El hallazgo de DeMiguel, Garlappi y Uppal (2009) sobre la estrategia 1/N (equiponderada) es que:','La ganancia teórica de optimizar se anula por el estimation error cuando la ventana de datos es corta frente al número de activos. 1/N es un benchmark formidable porque no estima nada.');
insert into questions(id,section_id,prompt,justification) values (159,8,'¿Por qué la restricción de no venta en corto (wᵢ ≥ 0) suele MEJORAR el desempeño fuera de muestra del MVO?','Irónicamente, una restricción vista como limitación teórica estabiliza el portafolio. Además, en México la regulación (CNBV) prohíbe posiciones cortas en la mayoría de fondos regulados, así que la restricción es también una realidad operativa.');
insert into questions(id,section_id,prompt,justification) values (160,8,'La frontera eficiente resampleada de Michaud (1998) consiste en:','El resampling promedia sobre la incertidumbre paramétrica, reduciendo la concentración extrema del MVO clásico, aunque sigue dentro del paradigma media-varianza y carece de fundamentación bayesiana formal.');
insert into questions(id,section_id,prompt,justification) values (161,8,'La diferencia central del modelo de Merton (1969/1973) frente a Markowitz es que Merton:','Markowitz es estático (un periodo); Merton es dinámico e intertemporal: el agente decide simultáneamente cuánto consumir y cómo asignar su riqueza en cada instante, con oportunidades de inversión que cambian estocásticamente.');
insert into questions(id,section_id,prompt,justification) values (162,8,'El &quot;hedging demand&quot; (demanda de cobertura) que surge en Merton y no en Markowitz se refiere a:','El peso óptimo de Merton = componente miópico (idéntico a Markowitz) + componente de cobertura. Este último protege al inversionista frente al deterioro futuro de su set de oportunidades.');
insert into questions(id,section_id,prompt,justification) values (163,8,'En la solución de Merton, ¿cómo afecta el horizonte temporal a la asignación?','El horizonte deja de ser un dato secundario y se vuelve un determinante principal de la asignación óptima (Merton; Campbell y Viceira). Es la base teórica del glidepath.');
insert into questions(id,section_id,prompt,justification) values (164,8,'En la inversión por ciclo de vida, el capital humano (valor presente del ingreso futuro) de un inversionista joven actúa como:','Si el capital humano se comporta como un bono, el patrimonio total ya tiene una base estable, dejando espacio para más riesgo financiero en la juventud; ese peso se reduce conforme el capital humano se consume con la edad.');
insert into questions(id,section_id,prompt,justification) values (165,8,'El ejemplo del &quot;volado&quot; (un activo que crece 0% combinado 50/50 con efectivo y rebalanceado genera +6%) ilustra que:','CAGR = exp(E[ln(1+r)]) ≠ E[r]. La aritmética de la diversificación genera el crecimiento mecánicamente: combinar activos volátiles e imperfectamente correlacionados y rebalancear convierte la dispersión en crecimiento compuesto.');
insert into questions(id,section_id,prompt,justification) values (166,8,'El retorno de diversificación que captura el rebalanceo es positivo siempre que los activos sean:','DR = ½[Σ(wᵢσᵢ<sup>2</sup>) − σₚ<sup>2</sup>] &gt; 0 bajo volatilidad y correlación imperfecta. La reversión en retornos reales aporta un extra menor (~11% del efecto); la mayor parte es &quot;cosecha de volatilidad&quot; pura.');
insert into questions(id,section_id,prompt,justification) values (167,8,'¿Por qué el rebalanceo a pesos fijos captura el retorno de diversificación y el buy-and-hold no?','La regla mecánica de restaurar pesos es contraria por construcción y convierte la dispersión transversal en crecimiento compuesto; dejar derivar los pesos renuncia a esa prima matemática.');
insert into questions(id,section_id,prompt,justification) values (168,8,'La evidencia de Plyakha, Uppal y Vilkov (S&amp;P 500, 1967–2009) sobre el portafolio equiponderado (EW) muestra que:','La fuente del exceso es la <em>operación de rebalanceo</em>, no los pesos iguales: a 12 meses la ventaja se vuelve indistinguible del VW/PW. El alfa sobrevive a ~50 bps de costos, pero es compensación por varianza y rotación.');
insert into questions(id,section_id,prompt,justification) values (169,8,'La idea central de la &quot;optimización inversa&quot; (reverse optimization) en Black-Litterman (1992) es:','Si el mercado es eficiente, los pesos actuales implican rendimientos de equilibrio (Π = δΣw_mkt). Partir de Π reduce drásticamente la sensibilidad al estimation error frente a estimar μ subjetivamente.');
insert into questions(id,section_id,prompt,justification) values (170,8,'En el modelo Black-Litterman, si el asesor no expresa ninguna view, el portafolio resultante:','El prior es el equilibrio de mercado; sin views que lo desplacen, el posterior bayesiano permanece en el mercado. Las views inclinan el portafolio de forma controlada según su confianza (Ω) y el peso del prior (τ).');
insert into questions(id,section_id,prompt,justification) values (171,8,'&quot;El S&amp;P 500 superará al IPC por 3% anual&quot; es un ejemplo de:','Una view absoluta fija el nivel de un activo (&quot;el IPC rendirá 12%&quot;); una relativa fija un diferencial. Las relativas suelen ser más robustas porque expresan una opinión comparativa, no un nivel puntual.');
insert into questions(id,section_id,prompt,justification) values (172,8,'La Behavioral Portfolio Theory (Shefrin y Statman, 2000) sostiene que los inversionistas reales construyen:','A diferencia del MVO normativo, BPT es descriptiva: refleja cómo la gente realmente segrega su dinero por propósito, asumiendo distinto riesgo en cada capa.');
insert into questions(id,section_id,prompt,justification) values (173,8,'El criterio &quot;safety-first&quot; (Roy, 1952) aplicado por capa en BPT implica que el inversionista:','Cada capa h optimiza con su propio nivel de aspiración Aₕ, piso de seguridad Sₕ y tolerancia máxima a la pérdida αₕ. La capa de seguridad prioriza no caer por debajo del piso; la de aspiración tolera mucho más riesgo.');
insert into questions(id,section_id,prompt,justification) values (174,8,'La teoría SP/A de Lopes describe tres motivaciones simultáneas que gobiernan la decisión financiera:','SP/A integra en BPT por qué los portafolios reales combinan activos ultra-seguros (Security) con apuestas especulativas (Potential), ancladas a un nivel de Aspiración que varía por cliente.');
insert into questions(id,section_id,prompt,justification) values (175,8,'Das, Markowitz, Scheid y Statman (2010) demostraron que:','El enfoque integrado aplica MVO <em>dentro</em> de cada capa BPT: óptimo y psicológicamente realista a la vez, comunicable al cliente y con menor behavioral gap. Es exactamente la lógica de los cajones de Invierte con Propósito.');
insert into questions(id,section_id,prompt,justification) values (176,8,'El principio de Risk Parity (Qian, 2005) consiste en:','Si no sabemos qué activo rendirá más, al menos evitamos que uno domine el riesgo. Al prescindir de μ (el insumo más ruidoso), Risk Parity es más robusto que el MVO. El Bridgewater All Weather es su implementación más conocida.');
insert into questions(id,section_id,prompt,justification) values (177,8,'Una diferencia clave entre Risk Parity y la estrategia 1/N (equiponderada) es que:','Equiponderar capital ≠ equiponderar riesgo. Un activo de alta volatilidad aporta más riesgo por unidad de capital, así que Risk Parity le reduce el peso para igualar contribuciones.');
insert into questions(id,section_id,prompt,justification) values (178,8,'El método Hierarchical Risk Parity (HRP) de López de Prado (2016) se construye en tres pasos:','HRP agrupa activos similares en un dendrograma, reordena Σ para hacerla quasi-diagonal y reparte capital recursivamente entre sub-clusters según su varianza inversa, sin recurrir a la optimización media-varianza.');
insert into questions(id,section_id,prompt,justification) values (179,8,'La ventaja fundamental de HRP frente a MVO, Black-Litterman y Risk Parity es que HRP:','Invertir una Σ mal condicionada amplifica errores exponencialmente —la falla típica del MVO. HRP usa la estructura jerárquica de Σ sin invertirla, logrando mayor estabilidad out-of-sample y preservando la diversificación entre clusters.');
insert into questions(id,section_id,prompt,justification) values (180,8,'Síntesis — framework de decisión. ¿Qué emparejamiento modelo-situación es el más adecuado según el deck?','En la práctica los modelos se complementan: BL para la visión estratégica con views, RP/HRP para la implementación robusta, GMV/RP para perfiles conservadores sin pronósticos, y BPT para comunicar y estructurar por objetivos. El asesor no necesita implementar la matemática, sino saber cuándo y por qué aplicar cada uno.');
insert into questions(id,section_id,prompt,justification) values (181,9,'¿Por qué los seguros y las inversiones son complementarios, no competidores?','Los seguros no compiten con las inversiones: las blindan. Un portafolio construido en 20 años puede desmoronarse en meses sin la protección adecuada. El riesgo central que cubre el seguro es de liquidez, no de mercado.');
insert into questions(id,section_id,prompt,justification) values (182,9,'El &quot;ciclo financiero completo&quot; que integra una estrategia sólida consta de:','Los cuatro elementos se refuerzan mutuamente: la protección garantiza la continuidad del plan, la optimización fiscal libera capital, y los beneficios reinvertidos aceleran el interés compuesto.');
insert into questions(id,section_id,prompt,justification) values (183,9,'En la pirámide de aseguramiento (análoga a la de Maslow), la base —el seguro más indispensable— es:','El GMM es el más indispensable: un cáncer cuesta ~$2.68 MDP en promedio en México, y sin cobertura una familia puede quebrar ante una enfermedad grave. Es la base sobre la que se construyen las demás coberturas.');
insert into questions(id,section_id,prompt,justification) values (184,9,'&quot;Los seguros no se venden: se diagnostican.&quot; Esta idea implica que el asesor:','Conecta con el rol de &quot;médico del dinero&quot; (Sección 7): cuando un médico detecta un problema, no pregunta si el paciente quiere escuchar el diagnóstico; lo comunica por responsabilidad profesional. Además, proteger al cliente protege al asesor: un cliente sin cobertura puede retirar toda su cartera ante una crisis.');
insert into questions(id,section_id,prompt,justification) values (185,9,'¿En qué consiste la &quot;creación inmediata de patrimonio&quot; que distingue al seguro de vida?','Es la &quot;magia&quot; del seguro. Garantizar $3 MDP combinando $2M invertidos + $1M asegurado (prima ~$48K/año) cuesta ~$952K menos que acumular los $3M, y el legado está disponible desde el primer mes de vigencia, no cuando se acumula el total.');
insert into questions(id,section_id,prompt,justification) values (186,9,'Los &quot;riesgos existenciales&quot; (longevidad, incapacidad, sucesión, quebranto empresarial, cese productivo) se distinguen de los financieros porque:','A diferencia del riesgo de mercado (que se gestiona con asignación y diversificación), los riesgos existenciales requieren transferencia vía seguro. La clave operativa vuelve a ser la liquidez.');
insert into questions(id,section_id,prompt,justification) values (187,9,'¿Qué función cumple el seguro de vida en la planeación sucesoria de un patrimonio consolidado?','&quot;Los impuestos no pagados se heredan.&quot; Sin liquidez, los herederos se ven obligados a malvender propiedades o activos para liquidar la sucesión; el seguro de vida aporta esa liquidez en el momento exacto en que se necesita.');
insert into questions(id,section_id,prompt,justification) values (188,9,'En un seguro de &quot;persona clave&quot; para un empresario, ¿cuál es una ventaja distintiva?','El seguro de persona clave blinda la capacidad generadora de ingresos del negocio frente a la pérdida de un ejecutivo crítico, con la ventaja fiscal de la deducibilidad de la prima.');
insert into questions(id,section_id,prompt,justification) values (189,9,'La &quot;triple ventaja fiscal&quot; del PPR se manifiesta en tres etapas:','Cada peso aportado es deducible; los rendimientos (dividendos e intereses) crecen sin retención mientras permanecen invertidos; y al retiro hay montos exentos. Los tres beneficios se acumulan a lo largo del ciclo de vida de la inversión.');
insert into questions(id,section_id,prompt,justification) values (190,9,'El límite de deducción de las aportaciones al PPR es:','Es el menor de los dos topes. Importante: este límite del PPR es <strong>independiente</strong> del límite de las demás deducciones personales (GMM, intereses hipotecarios), así que pueden aprovecharse ambos simultáneamente.');
insert into questions(id,section_id,prompt,justification) values (191,9,'Al retirar el PPR a los 65 años, el tratamiento fiscal (2025) contempla:','El beneficio al retiro combina montos exentos (atados a la UMA) con una retención fija moderada sobre el excedente, lo que premia el ahorro disciplinado de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (192,9,'Respecto a la deducción de primas de seguros de gastos médicos mayores (Art. 151 LISR, CFDI clave D07):','La deducibilidad depende del cumplimiento formal del CFDI (clave D07, RFC correcto, póliza a nombre del declarante, pago por transferencia/tarjeta/cheque nominativo), no del uso de los servicios.');
insert into questions(id,section_id,prompt,justification) values (193,9,'La deducción de primas de GMM aplica para el contribuyente y:','La cobertura del beneficio fiscal se extiende a la familia directa bajo la condición de que el dependiente no perciba ingresos por encima del umbral establecido para el ejercicio.');
insert into questions(id,section_id,prompt,justification) values (194,9,'¿Cuál de los siguientes NO es deducible como deducción personal, y cómo se relacionan los límites?','Distinción clave: las primas de vida no entran en deducciones personales; el ahorro para retiro tiene su propio vehículo (PPR) con límite separado. Aprovechar ambos límites (GMM + PPR) en la misma declaración es legítimo y maximiza el beneficio fiscal.');
insert into questions(id,section_id,prompt,justification) values (195,9,'El &quot;problema del retiro en México&quot; se caracteriza por:','La esperanza de vida ha aumentado sin que la edad de jubilación ni el ahorro lo hayan hecho proporcionalmente. La aportación voluntaria al PPR es la herramienta para cerrar la brecha de la tasa de reemplazo.');
insert into questions(id,section_id,prompt,justification) values (196,9,'El PPR de GBM se distingue de las aseguradoras tradicionales por:','El PPR de GBM ofrece flexibilidad y transparencia de costos frente a las aseguradoras, con rebalanceo que reduce el riesgo conforme se acerca a los 65 años (como un target-date fund). El PPR Premium (desde $1 MDP) permite portafolios a la medida, y la alianza GBM-Prudential complementa con seguro de vida.');
insert into questions(id,section_id,prompt,justification) values (197,9,'El paper seminal de Yaari (1965) demuestra que un individuo racional con incertidumbre sobre su fecha de fallecimiento demanda:','Yaari formaliza que el seguro es la solución óptima al problema de incertidumbre vital: las anualidades cubren vivir demasiado y el seguro de vida cubrir morir demasiado pronto. Ambos derivan directamente de la maximización de utilidad esperada.');
insert into questions(id,section_id,prompt,justification) values (198,9,'Hubbard (1994) demuestra empíricamente que el seguro:','Un cliente sin cobertura adecuada debe mantener mayores reservas líquidas &quot;por si acaso&quot;, sacrificando rendimiento de largo plazo. El seguro, al transferir el riesgo, permite invertir ese capital de forma más eficiente.');
insert into questions(id,section_id,prompt,justification) values (199,9,'Según el marco de capital humano (Ibbotson, Milevsky, Chen &amp; Zhu, 2007), el seguro de vida es:','El capital humano es el activo más grande —pero ilíquido e inasegurable por los mercados— de las personas jóvenes. El seguro de vida protege ese activo aún no &quot;convertido&quot; en capital financiero. Conecta con el ciclo de vida de Merton (Sección 8): la asignación óptima cambia con el horizonte y la edad.');
insert into questions(id,section_id,prompt,justification) values (200,9,'El consenso de los estándares profesionales (CFP Board, CFA Institute, Rejda &amp; McNamara) sobre la relación seguro-inversión es que:','Los tres marcos convergen: no se puede diseñar un portafolio sin saber primero qué riesgos existenciales están cubiertos. El portafolio total del cliente = capital financiero + capital humano, y las decisiones de seguro son inseparables del asset allocation porque ambas determinan el riesgo neto total.');
insert into questions(id,section_id,prompt,justification) values (201,10,'La fecha que divide los dos regímenes del SAR es:','El parteaguas es la entrada en vigor de la nueva Ley del Seguro Social. Un trabajador puede verificar su régimen con la Constancia de Vigencia de Derechos del IMSS.');
insert into questions(id,section_id,prompt,justification) values (202,10,'La Ley 73 es un régimen de:','En Ley 73 la pensión depende del salario promedio y los años cotizados, no del monto ahorrado. Por eso trabajadores con salarios altos y muchos años pueden obtener pensiones generosas.');
insert into questions(id,section_id,prompt,justification) values (203,10,'La Ley 97 es un régimen de:','En Ley 97 el trabajador asume el riesgo de inversión y la pensión es función del saldo de su cuenta individual, gestionada por una AFORE privada supervisada por CONSAR.');
insert into questions(id,section_id,prompt,justification) values (204,10,'Las aportaciones a la cuenta individual bajo Ley 97 (tras la reforma) son tripartitas:','La reforma 2020 elevó gradualmente la cuota patronal (de 5.15% hasta 13.875% entre 2023 y 2030); el trabajador mantiene su 1.125% y el Estado refuerza la cuota social para salarios bajos.');
insert into questions(id,section_id,prompt,justification) values (205,10,'El requisito de semanas cotizadas para acceder a pensión bajo Ley 97:','La reforma redujo el requisito original de 1,250 a 750 semanas en 2021 y estableció un incremento gradual de 25 semanas anuales hasta estabilizarse en 1,000 semanas en 2031.');
insert into questions(id,section_id,prompt,justification) values (206,10,'Entre Ley 73 y Ley 97, ¿quién asume el riesgo de inversión y qué ocurre con la herencia?','Diferencia estructural clave: la contribución definida traslada el riesgo de inversión (y la propiedad heredable del saldo) al trabajador, a diferencia del beneficio definido estatal.');
insert into questions(id,section_id,prompt,justification) values (207,10,'Una AFORE es:','Las AFOREs son privadas pero estrictamente reguladas por CONSAR, que fija comisiones máximas, el régimen de inversión y publica rankings de rendimiento.');
insert into questions(id,section_id,prompt,justification) values (208,10,'¿Cuál es la función supervisora de CONSAR?','CONSAR es el órgano regulador del SAR: fija las reglas del juego (comisiones, régimen de inversión) y da transparencia mediante rankings y el Indicador de Rendimiento Neto.');
insert into questions(id,section_id,prompt,justification) values (209,10,'Respecto a la elección y portabilidad de AFORE:','Existe asignación automática para quienes no eligen, y portabilidad anual gratuita, lo que incentiva la competencia entre administradoras por rendimiento neto.');
insert into questions(id,section_id,prompt,justification) values (210,10,'El Indicador de Rendimiento Neto (IRN) que publica CONSAR es:','El IRN integra rendimiento, comisiones y riesgo en una sola métrica comparable, por lo que es la referencia central para decidir entre AFOREs (por encima de mirar solo el rendimiento bruto o la comisión aislada).');
insert into questions(id,section_id,prompt,justification) values (211,10,'Sobre las comisiones de las AFOREs (2026):','Las comisiones se cobran como porcentaje sobre el saldo y están topadas por CONSAR; su efecto compuesto a largo plazo es relevante, de ahí que el IRN (neto de comisiones) sea el criterio correcto.');
insert into questions(id,section_id,prompt,justification) values (212,10,'Como inversionistas institucionales, las AFOREs:','Con ~$8.7 billones administrados, las Siefores canalizan ahorro de largo plazo hacia el financiamiento productivo del país (infraestructura, FIBRAs, deuda corporativa, OPIs, energía).');
insert into questions(id,section_id,prompt,justification) values (213,10,'El SAR representa, dentro del sistema financiero mexicano:','Su escala (~24% del PIB) lo convierte en un pilar del sistema financiero y en un actor determinante de los mercados de capitales locales.');
insert into questions(id,section_id,prompt,justification) values (214,10,'Las Siefores Generacionales funcionan bajo el principio de:','Son el equivalente mexicano de los target-date funds: el mismo principio de ciclo de vida (Merton) que vimos en asset allocation, ahora institucionalizado en el régimen de pensiones.');
insert into questions(id,section_id,prompt,justification) values (215,10,'La reforma cambió la estructura de Siefores de:','El esquema previo escalonaba por bandas de edad (con saltos bruscos al cambiar de banda); el generacional asigna una trayectoria continua por cohorte, evitando reasignaciones abruptas.');
insert into questions(id,section_id,prompt,justification) values (216,10,'Comparando la SB Inicial (jóvenes) con la SB Pensiones (cercanos al retiro), el límite máximo de renta variable es:','El régimen permite más renta variable a quien tiene mayor horizonte (mayor capacidad de recuperarse de caídas) y la restringe drásticamente para quien está por pensionarse.');
insert into questions(id,section_id,prompt,justification) values (217,10,'El &quot;glidepath regulatorio&quot; de las Siefores implica que, conforme se acerca el retiro:','Los límites máximos por clase de activo se reducen de la SB Inicial a la SB Pensiones (RV 60%→15%, divisas 35%→20%, estructurados 30%→10%, FIBRAs 12.5%→5%), un glidepath impuesto por regulación.');
insert into questions(id,section_id,prompt,justification) values (218,10,'La Siefore Básica de Pensiones (perfil conservador) debe mantener, según el régimen:','Cerca y durante el retiro, proteger el poder adquisitivo es prioritario; de ahí el piso regulatorio en instrumentos indexados a la inflación (UDIBONOs). Conecta con el objetivo de rendimiento real visto en asset allocation.');
insert into questions(id,section_id,prompt,justification) values (219,10,'En la composición agregada de las Siefores, el componente predominante es:','Las Siefores mantienen ~50%+ en deuda gubernamental (buena parte en bonos a tasa fija nominal de largo plazo), y la exposición a valores extranjeros está topada en 20% por regulación.');
insert into questions(id,section_id,prompt,justification) values (220,10,'Un cambio central de la reforma de pensiones de 2020 (DOF 16 dic 2020) fue:','El alza de la cuota patronal busca elevar el saldo acumulado y, con ello, las tasas de reemplazo, sin cargar más al trabajador.');
insert into questions(id,section_id,prompt,justification) values (221,10,'Tras la reforma, la Pensión Mínima Garantizada (PMG):','La PMG pasó a expresarse en UMAs (no en salarios mínimos) y a escalar según las semanas cotizadas y la edad de retiro, mejorando el piso de pensión para trabajadores de salarios bajos.');
insert into questions(id,section_id,prompt,justification) values (222,10,'El requisito de semanas cotizadas, tras la reforma, evoluciona así:','La transición gradual busca equilibrar el acceso a la PMG (que se redujo desde 1,250) con la sostenibilidad del sistema, subiendo el requisito de forma escalonada.');
insert into questions(id,section_id,prompt,justification) values (223,10,'La reforma fijó como objetivo elevar la tasa de reemplazo, y la referencia internacional de la OCDE es:','La tasa de reemplazo es el porcentaje del último salario que cubre la pensión. La OCDE recomienda al menos 60%; el sistema mexicano históricamente quedaba por debajo, lo que motivó la reforma y refuerza la importancia de las aportaciones voluntarias.');
insert into questions(id,section_id,prompt,justification) values (224,10,'La Pensión Mínima Garantizada (PMG) se otorga cuando el trabajador:','La PMG es una red de protección: condicionada a edad y semanas cotizadas, garantiza un piso (2.5–3.289 UMAs) cuando el ahorro individual resulta insuficiente.');
insert into questions(id,section_id,prompt,justification) values (225,10,'La &quot;tasa de reemplazo&quot; se define como:','Una tasa de reemplazo baja significa una caída fuerte del nivel de vida al retirarse. Solo con la aportación obligatoria suele quedar insuficiente, de ahí el rol del ahorro voluntario y el PPR.');
insert into questions(id,section_id,prompt,justification) values (226,10,'El retiro parcial por desempleo de la AFORE permite disponer de:','Es un retiro acotado y condicionado, pensado como apoyo temporal; reduce el saldo destinado al retiro, por lo que debe usarse con cautela.');
insert into questions(id,section_id,prompt,justification) values (227,10,'El retiro por matrimonio de la AFORE:','Es una prestación histórica única y de monto acotado, vinculada a recursos de la cuenta individual.');
insert into questions(id,section_id,prompt,justification) values (228,10,'Las aportaciones voluntarias al SAR:','Las aportaciones voluntarias combinan beneficio fiscal y flexibilidad; cada peso adicional incrementa el saldo y, por el interés compuesto a 25–30 años, su impacto en la pensión es exponencial.');
insert into questions(id,section_id,prompt,justification) values (229,10,'La diferencia fundamental entre retiro programado y renta vitalicia es:','El eje es quién asume el riesgo de longevidad: en el retiro programado lo asume el pensionado (puede agotar el fondo si vive mucho); en la renta vitalicia lo asume la aseguradora, a cambio de irrevocabilidad. Conecta con Yaari (Sección 9): la anualidad cubre el riesgo de vivir más de lo previsto.');
insert into questions(id,section_id,prompt,justification) values (230,10,'¿Cuándo conviene típicamente cada modalidad de pensión?','La decisión depende del saldo, la aversión al riesgo de longevidad y el deseo de heredar. Un asesor debe explicar el trade-off entre flexibilidad/herencia (retiro programado) y certeza de por vida (renta vitalicia).');
insert into questions(id,section_id,prompt,justification) values (231,11,'Una FIBRA es:','La FIBRA da exposición a real estate con liquidez bursátil y gestión profesional en un solo instrumento, vía CBFIs (Certificados Bursátiles Fiduciarios Inmobiliarios) listados en BMV/BIVA.');
insert into questions(id,section_id,prompt,justification) values (232,11,'Para mantener su régimen fiscal preferente (Art. 187 LISR), una FIBRA debe cumplir, entre otros, que:','Los tres requisitos centrales (70% en inmuebles, 95% de distribución anual, 4 años mínimo de tenencia) son la contraparte del beneficio fiscal del vehículo y aseguran que sea un instrumento inmobiliario de largo plazo que reparte sus flujos.');
insert into questions(id,section_id,prompt,justification) values (233,11,'Los tres tipos de FIBRAs que existen en México son:','La inmobiliaria domina el mercado; la FIBRA-E financia infraestructura/energía; la hipotecaria (FHipo) invierte en portafolios hipotecarios residenciales y es la única de su tipo.');
insert into questions(id,section_id,prompt,justification) values (234,11,'Una diferencia estructural entre las FIBRAs mexicanas y los REITs estadounidenses es que las mexicanas:','El mercado mexicano está en etapa más temprana y concentrado en real estate productivo; en EE.UU. ~60% de la capitalización está en clases inexistentes aún en México, lo que marca el espacio de crecimiento del sector local.');
insert into questions(id,section_id,prompt,justification) values (235,11,'El marco legal que rige a las FIBRAs en México se encuentra principalmente en:','Los Art. 187-188 LISR establecen los requisitos del vehículo y su tratamiento fiscal, incluyendo el régimen de la distribución y la exención en la enajenación de CBFIs.');
insert into questions(id,section_id,prompt,justification) values (236,11,'¿Cuáles son las ventajas estructurales de una FIBRA frente a la inversión inmobiliaria tradicional?','Estas cinco ventajas convierten una clase de activo tradicionalmente ilíquida, intensiva en capital y de gestión activa en un instrumento accesible, líquido y profesionalmente administrado.');
insert into questions(id,section_id,prompt,justification) values (237,11,'Comparado con comprar un departamento para rentar, invertir en FIBRAs ofrece:','La FIBRA democratiza el acceso al real estate: elimina las barreras de capital, liquidez, diversificación y gestión propias del inmueble directo, con yields típicamente superiores (6–9% + apreciación vs. 4–6% del inmueble directo).');
insert into questions(id,section_id,prompt,justification) values (238,11,'La &quot;distribución obligatoria&quot; de una FIBRA significa que:','El piso de 95% del resultado fiscal es lo que hace de la FIBRA un instrumento generador de flujo recurrente, y es condición del régimen fiscal preferente (Art. 187 LISR).');
insert into questions(id,section_id,prompt,justification) values (239,11,'Según la evidencia institucional de CEM Benchmarking (2024), los REITs/FIBRAs frente a los bienes raíces privados:','El estudio (patrocinado por Nareit, ~$4T USD AUM, 1998-2022) muestra que el real estate cotizado supera al privado con mejor rendimiento ajustado por riesgo, además de aportar liquidez y transparencia.');
insert into questions(id,section_id,prompt,justification) values (240,11,'El término técnicamente correcto para lo que reparte una FIBRA a sus tenedores es:','Aunque coloquialmente se hable de &quot;dividendos&quot; o &quot;yield&quot;, el término preciso conforme a la LISR es <strong>distribución de resultado fiscal</strong>. Usar la terminología correcta es parte del rigor técnico y de la fidelidad a la normativa.');
insert into questions(id,section_id,prompt,justification) values (241,11,'Sobre la distribución de resultado fiscal que recibe una persona física:','La distribución es ingreso acumulable con retención del 30% que opera como pago provisional acreditable; el inversionista la integra a su declaración anual en el apartado de arrendamiento.');
insert into questions(id,section_id,prompt,justification) values (242,11,'Respecto a la ganancia de capital al vender los CBFIs de una FIBRA en bolsa, una persona física residente:','La exención en la ganancia de capital de los CBFIs (cuando se adquirieron siendo la FIBRA pública y se venden en bolsa) es un diferenciador fiscal poco conocido pero decisivo frente al inmueble directo, donde la plusvalía sí se grava.');
insert into questions(id,section_id,prompt,justification) values (243,11,'¿Cómo se clasifica fiscalmente cada tipo de ingreso de una FIBRA para el tenedor?','Distinguir entre estos cuatro tratamientos es clave para una asesoría fiscal correcta: la distribución y la venta de inmuebles son acumulables, el reembolso de capital reduce el costo y no acumula, y la plusvalía de los CBFIs es exenta bajo las condiciones del Art. 188.');
insert into questions(id,section_id,prompt,justification) values (244,11,'El segmento dominante de las FIBRAs mexicanas y su principal catalizador estructural son:','El sector industrial es el mayor componente y el de mayor tesis de crecimiento: el nearshoring eleva la demanda de naves, con rentas en dólares (&gt;$11 USD/m<sup>2</sup> en corredores clave) y contratos NNN que trasladan costos al inquilino.');
insert into questions(id,section_id,prompt,justification) values (245,11,'En el perfil riesgo-retorno por sector, ¿cuál afirmación es correcta?','Cada segmento tiene su propia dinámica: industrial estable y dolarizado, comercial/oficinas atado al ciclo y consumo, hotelero volátil por estacionalidad y turismo; autoalmacenamiento y educativo tienden a ser estables por contratos recurrentes/largos.');
insert into questions(id,section_id,prompt,justification) values (246,11,'¿Cuál es un catalizador relevante de la tesis de nearshoring para las FIBRAs industriales?','La escasez de espacio industrial, los flujos de capital (~$5B USD), la consolidación y la certidumbre comercial (T-MEC) sostienen la tesis. La revisión del T-MEC es un evento clave para la certidumbre manufacturera.');
insert into questions(id,section_id,prompt,justification) values (247,11,'El desempeño reciente del sector FIBRAs en México muestra:','El sector alcanzó niveles récord de ocupación y un desempeño destacado, favorecido además por el ciclo de baja de tasas de Banxico (de 11.25% a 6.75%), que reduce el costo de capital e impulsa las valuaciones.');
insert into questions(id,section_id,prompt,justification) values (248,11,'La presencia institucional en el sector FIBRAs se evidencia en que:','La fuerte participación de las AFOREs (que vimos como inversionistas institucionales en la Sección 10) respalda la estabilidad, el gobierno corporativo y los estándares ASG del sector.');
insert into questions(id,section_id,prompt,justification) values (249,11,'En el universo global de REITs, México:','El modelo REIT tiene 65+ años y &gt;$2 billones USD de capitalización global. México sobresale entre emergentes por el tamaño e institucionalidad de sus emisoras, comparable con estándares del FTSE EPRA Nareit.');
insert into questions(id,section_id,prompt,justification) values (250,11,'Las vías para invertir en FIBRAs a través de GBM incluyen:','GBM ofrece rutas complementarias según el perfil: control total (FIBRAs individuales), diversificación pasiva de bajo costo (ETF FIBRATC) o gestión profesional (SMA FIBRAs), todas con la liquidez bursátil característica del vehículo.');
insert into questions(id,section_id,prompt,justification) values (251,12,'Un ETF (Exchange-Traded Fund) es:','El ETF combina la diversificación de un fondo con la negociabilidad de una acción: se opera en tiempo real durante la sesión, a diferencia de un fondo mutuo tradicional.');
insert into questions(id,section_id,prompt,justification) values (252,12,'¿Cuáles son las características clave de un ETF?','La publicación diaria de holdings (transparencia) y la negociación intradía distinguen al ETF; sus comisiones suelen ser menores que las de los fondos mutuos tradicionales.');
insert into questions(id,section_id,prompt,justification) values (253,12,'La diferencia principal entre un ETF y un fondo mutuo tradicional es que el ETF:','El ETF cotiza intradía como una acción; el fondo mutuo se compra/vende al NAV de cierre. Esta negociabilidad y la menor comisión son ventajas centrales del ETF.');
insert into questions(id,section_id,prompt,justification) values (254,12,'El primer ETF de la historia fue:','SPY fue pionero: permitió acceder a las 500 mayores empresas de EE.UU. en una sola operación y sentó las bases de la democratización de la inversión indexada.');
insert into questions(id,section_id,prompt,justification) values (255,12,'La filosofía de la inversión indexada vía ETFs (&quot;no busques la aguja en el pajar; compra el pajar&quot;, de Jack Bogle) implica:','Es la lógica de la gestión pasiva (conecta con la inversión activa vs. pasiva y la EMH de las Secciones 1 y 3): comprar el mercado entero a bajo costo, en lugar de pagar por intentar superarlo.');
insert into questions(id,section_id,prompt,justification) values (256,12,'Respecto a los costos de administración de los ETFs:','Dado que varios ETFs siguen el mismo índice (p. ej., SPY, VOO, IVV para el S&amp;P 500), elegir el de menor costo y mejor liquidez es clave; enlaza con el módulo de costos de Advisor&#x27;s Alpha (Sección 5).');
insert into questions(id,section_id,prompt,justification) values (257,12,'¿Cuál de los siguientes NO es un tipo de ETF mencionado en el universo de productos?','El universo de ETFs abarca indexados (SPY, VOO), sectoriales (XLK), temáticos (BOTZ), de bonos (TLT), commodities (GLD), divisas (FXE), regionales (FXI), inversos (SQQQ), apalancados (TQQQ) y buffer (BUFR); no existen &quot;ETFs de depósito bancario garantizado&quot;.');
insert into questions(id,section_id,prompt,justification) values (258,12,'Un ETF inverso (p. ej., SQQQ):','Los ETFs inversos ofrecen exposición contraria al índice; se usan tácticamente para beneficiarse de caídas o como cobertura, no como inversión de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (259,12,'¿Cuál es el riesgo clave de mantener un ETF apalancado (p. ej., TQQQ, 3x) en el largo plazo?','Los ETFs apalancados e inversos buscan multiplicar el rendimiento <em>diario</em>; el reajuste diario compuesto hace que, sostenidos varios días, su resultado difiera (a menudo desfavorablemente) del múltiplo del movimiento total del índice. Es un matiz crítico para advertir al cliente.');
insert into questions(id,section_id,prompt,justification) values (260,12,'Empareja correctamente cada ETF con su tipo:','TLT (iShares 20+ Year Treasury), GLD (SPDR Gold Shares) y XLK (Technology Select Sector SPDR) ejemplifican, respectivamente, las categorías de bonos, commodities y sectorial.');
insert into questions(id,section_id,prompt,justification) values (261,12,'Un &quot;buffer ETF&quot; se caracteriza por:','Los buffer ETFs (p. ej., BUFR) usan estructuras de opciones para acotar tanto las pérdidas como las ganancias dentro de un periodo, atractivos para perfiles que priorizan proteger el capital a cambio de renunciar a parte del alza.');
insert into questions(id,section_id,prompt,justification) values (262,12,'Un ETF temático (p. ej., de IA, energía limpia, espacio o biotecnología):','Los temáticos apuestan a megatendencias (IA, sostenibilidad, fintech, espacio). El deck muestra su alta dispersión de resultados (algunos +45%, otros -68% desde una base común), lo que ilustra su mayor volatilidad y riesgo de concentración: hay que dimensionar la posición con cuidado.');
insert into questions(id,section_id,prompt,justification) values (263,12,'Los ETFs UCITS se diferencian de los ETFs &quot;regulares&quot; estadounidenses en que:','UCITS prioriza la protección al inversionista con límites de concentración y transparencia; a cambio, restringe ciertas estrategias y puede implicar costos algo mayores por los requisitos regulatorios.');
insert into questions(id,section_id,prompt,justification) values (264,12,'La diferencia entre un ETF UCITS de acumulación (&quot;Acc&quot;) y uno de distribución (&quot;Dist&quot;) es que el de acumulación:','La versión de acumulación capitaliza los dividendos internamente, posponiendo el evento fiscal hasta la venta; la de distribución entrega el flujo, generando el evento fiscal al recibirlo.');
insert into questions(id,section_id,prompt,justification) values (265,12,'Una ventaja de los ETFs UCITS de acumulación para un inversionista enfocado en el largo plazo es:','Diferir el impuesto permite que el capital completo siga componiéndose. Es un punto de eficiencia fiscal relevante, aunque el tratamiento concreto debe validarse con la normativa aplicable al inversionista.');
insert into questions(id,section_id,prompt,justification) values (266,12,'Sobre los emisores y el tamaño del mercado de ETFs:','El mercado está dominado por unos pocos grandes emisores (BlackRock, Vanguard, State Street), con un crecimiento explosivo en número y activos durante las últimas dos décadas.');
insert into questions(id,section_id,prompt,justification) values (267,12,'Entre SPY y VOO (ambos siguen al S&amp;P 500):','Que varios productos repliquen el mismo índice obliga a elegir según comisión, liquidez y error de seguimiento; SPY destaca por liquidez/volumen y VOO por menor costo y activos.');
insert into questions(id,section_id,prompt,justification) values (268,12,'Los cinco criterios clave para invertir en ETFs son:','Estos cinco factores estructuran una decisión informada: qué replica, para cuánto tiempo, a qué costo, con qué riesgo y con qué relación riesgo/rendimiento histórica.');
insert into questions(id,section_id,prompt,justification) values (269,12,'Al comparar dos ETFs que replican exactamente el mismo índice, el criterio de desempate más relevante suele ser:','Si el índice es el mismo, la diferencia de resultado proviene principalmente de costo, liquidez y precisión de réplica; el costo bajo es el predictor más robusto del rendimiento neto futuro.');
insert into questions(id,section_id,prompt,justification) values (270,12,'¿Cuál es la diferencia entre un ETF de Bitcoin spot, uno de futuros y uno de empresas relacionadas?','La distinción es clave para la idoneidad: el spot da exposición directa al precio; el de futuros puede divergir por la estructura de los contratos; y los de empresas dan exposición indirecta al sector, con su propio riesgo accionario.');
insert into questions(id,section_id,prompt,justification) values (271,12,'Un hito regulatorio relevante para los cripto-ETFs fue:','Tras años de rechazos (el primer intento de los Winklevoss en 2013 fue denegado), la aprobación de los spot ETFs en enero de 2024 marcó un punto de inflexión en la adopción de cripto como activo invertible.');
insert into questions(id,section_id,prompt,justification) values (272,12,'El iShares Bitcoin Trust (IBIT) se caracteriza por:','IBIT permite exposición a Bitcoin desde una cuenta de inversión tradicional, delegando la custodia (Coinbase) y la operación; se volvió el cripto-ETF más negociado desde su lanzamiento en enero de 2024.');
insert into questions(id,section_id,prompt,justification) values (273,12,'Comparando la inversión directa en Ethereum con un ETF de Ethereum:','El ETF traslada la complejidad técnica y de custodia al emisor, a costa de la comisión y de renunciar a la utilidad on-chain (staking, DeFi). La elección depende del perfil y los conocimientos del cliente.');
insert into questions(id,section_id,prompt,justification) values (274,12,'Para un cliente que pide exposición a cripto sin manejar llaves privadas ni custodia, la solución más adecuada (consistente con el examen base) es:','Enlaza con la pregunta 50 del examen base (IBIT / Blockchain SMA para exposición a cripto): la vía idónea para un cliente que no quiere operar custodia directa es un vehículo regulado como un ETF spot o el SMA correspondiente.');
insert into questions(id,section_id,prompt,justification) values (275,12,'El acceso a ETFs a través de GBM se caracteriza por:','GBM da acceso a un universo amplio de ETFs que cubre todo el espectro de riesgo; el rol del asesor es seleccionar, según el perfil y objetivos del cliente, el vehículo adecuado dentro de esa oferta.');
insert into questions(id,section_id,prompt,justification) values (276,13,'El &quot;scientific beta&quot; o factor investing se sitúa, dentro del espectro de gestión, como:','El smart/scientific beta sistematiza (como lo pasivo) la búsqueda de fuentes de retorno que históricamente generaron exceso (como lo activo). Es &quot;invertir con el método científico&quot;: reglas explícitas respaldadas por evidencia.');
insert into questions(id,section_id,prompt,justification) values (277,13,'En la descomposición del rendimiento de una estrategia, los tres componentes de riesgo son:','El rendimiento se descompone en el beta de mercado, las exposiciones a factores (beta factorial) y el alfa residual atribuible a la habilidad. El factor investing busca capturar de forma sistemática y barata lo que antes se cobraba como &quot;alfa&quot;.');
insert into questions(id,section_id,prompt,justification) values (278,13,'Que los factores ofrezcan primas no contradice la EMH porque:','Conecta con la EMH (Secciones 1 y 3): capturar la prima de valor, tamaño o momentum implica asumir el riesgo asociado a ese factor. No es alfa libre de riesgo; es la remuneración por una exposición sistemática.');
insert into questions(id,section_id,prompt,justification) values (279,13,'Las tres formas de la Hipótesis de los Mercados Eficientes son:','Es la taxonomía de Fama (1970). La evidencia es fuerte para la forma débil, mixta para la semi-fuerte y débil para la fuerte (la información privilegiada sí parece dar ventaja en algunos estudios).');
insert into questions(id,section_id,prompt,justification) values (280,13,'¿Cuáles son los beneficios que se atribuyen a la inversión por factores, y su principal exigencia?','Los factores no pagan de forma constante: pueden tener años de rezago (p. ej., el &quot;value winter&quot;). Su captura requiere disciplina y horizonte —&quot;time in the market, not timing the market&quot;—.');
insert into questions(id,section_id,prompt,justification) values (281,13,'El factor de mercado (MKT), base de todos los modelos de factores, establece que:','El factor de mercado, formalizado por Sharpe (1964) y Lintner (1965), es el cimiento sobre el que Fama-French (1993) y los modelos posteriores añaden los demás factores.');
insert into questions(id,section_id,prompt,justification) values (282,13,'Respecto al factor tamaño (SMB), un matiz importante del debate académico actual es:','El factor decay del tamaño (Asness, Frazzini, Pedersen) es un recordatorio de que las primas documentadas pueden debilitarse tras su publicación, sea por arbitraje o por cambios estructurales del mercado.');
insert into questions(id,section_id,prompt,justification) values (283,13,'El factor valor (HML) captura que:','HML (&quot;high minus low&quot; book-to-market) tiene raíces conceptuales en Graham y Dodd. La evidencia internacional (Asness, Moskowitz, Pedersen) muestra que la prima de valor está presente globalmente, con magnitud aún mayor fuera de EE.UU.');
insert into questions(id,section_id,prompt,justification) values (284,13,'El &quot;value winter&quot; se refiere a:','El value winter es el ejemplo paradigmático de que un factor con evidencia sólida puede rezagarse por años. Abandonarlo en el peor momento (conducta) destruye su captura de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (285,13,'El &quot;factor rotation&quot; entre growth y value implica que:','La rotación factorial es una decisión activa (con sus riesgos de timing). El deck la asocia a vehículos como GBMINT (growth) cuando value atraviesa un invierno prolongado.');
insert into questions(id,section_id,prompt,justification) values (286,13,'El factor momentum (UMD, &quot;up minus down&quot;) fue formalizado por:','El momentum es el cuarto factor de Carhart. A diferencia de value/size (con explicaciones de riesgo y conductuales), el momentum tiene una base predominantemente conductual.');
insert into questions(id,section_id,prompt,justification) values (287,13,'La construcción estándar del factor momentum (&quot;12-1&quot;) consiste en:','Se excluye el mes más reciente porque a un mes opera la reversión de corto plazo, que contaminaría la señal. Y como el momentum se revierte a largo plazo, es un factor que requiere rotación periódica.');
insert into questions(id,section_id,prompt,justification) values (288,13,'El factor de calidad por rentabilidad (RMW, &quot;robust minus weak&quot;) captura que:','Novy-Marx (2012/2013) mostró que la rentabilidad bruta predice rendimientos; Fama-French lo formalizaron como RMW en su modelo de cinco factores (2015).');
insert into questions(id,section_id,prompt,justification) values (289,13,'El factor de inversión (CMA, &quot;conservative minus aggressive&quot;) establece que:','CMA recoge que un crecimiento agresivo de activos suele asociarse a peores rendimientos futuros; junto con RMW completa la dimensión de &quot;calidad&quot; del modelo de cinco factores.');
insert into questions(id,section_id,prompt,justification) values (290,13,'El factor QMJ (&quot;quality minus junk&quot;) de Asness, Frazzini y Pedersen:','QMJ sintetiza la calidad en dimensiones como rentabilidad, crecimiento, seguridad y payout. Su robustez internacional (23/24 países) lo hace uno de los factores con evidencia más sólida.');
insert into questions(id,section_id,prompt,justification) values (291,13,'El factor de baja volatilidad / BAB (&quot;betting against beta&quot;, Frazzini-Pedersen 2014) se explica porque:','La restricción de apalancamiento es la clave: quien sí puede apalancar bajo-beta (como el &quot;Opportunistic US Equities&quot;, que sube apalancamiento de 1.4x a 2x de forma contraria al mercado) explota esta anomalía —enhanced beta—.');
insert into questions(id,section_id,prompt,justification) values (292,13,'El modelo de cinco factores de Fama-French (2015), respecto al poder explicativo:','El FF5 mejora el poder explicativo del FF3 al incorporar las dos dimensiones de calidad; su rango de varianza explicada (71-94%) lo convierte en un marco de referencia para atribución de rendimientos.');
insert into questions(id,section_id,prompt,justification) values (293,13,'El enfoque integrado de construcción multifactor:','Al integrar señales en una sola optimización, una acción puede ser atractiva por valor y por calidad a la vez, evitando que las posiciones de un factor anulen las de otro (exposiciones compensatorias).');
insert into questions(id,section_id,prompt,justification) values (294,13,'El enfoque mixto de construcción multifactor:','El enfoque mixto (Vogel, 2025) mantiene cada factor &quot;puro&quot; en su propio portafolio, lo que da transparencia y permite reasignar tácticamente; históricamente, 50/50 value+momentum mostró buen desempeño por la baja correlación entre ambos.');
insert into questions(id,section_id,prompt,justification) values (295,13,'La principal diferencia entre el enfoque integrado y el mixto es:','No hay un ganador universal: el integrado tiende a ser más eficiente en captura de prima neta; el mixto es más transparente y flexible. La elección depende de los objetivos y la sofisticación del inversionista.');
insert into questions(id,section_id,prompt,justification) values (296,13,'El &quot;factor quilt&quot; (tabla de desempeño anual por factor, estilo Morningstar) ilustra que:','La ciclicidad y rotación de liderazgo entre factores es el argumento central a favor de la diversificación factorial: combinar factores poco correlacionados suaviza el camino y reduce el riesgo de quedar atrapado en el invierno de un solo factor.');
insert into questions(id,section_id,prompt,justification) values (297,13,'La &quot;persistencia y paciencia&quot; en la inversión por factores significa que:','Conecta con las finanzas conductuales (Sección 4) y el coaching (Secciones 5 y 7): el mayor enemigo de la captura de factores es la impaciencia conductual del inversionista, no la teoría.');
insert into questions(id,section_id,prompt,justification) values (298,13,'El &quot;factor decay&quot; y el riesgo de crowding implican que:','La economía de los factores no es estática. Por eso se privilegian factores con fundamentación teórica sólida y evidencia internacional amplia (como QMJ en 23/24 países), más resistentes al decaimiento que anomalías frágiles.');
insert into questions(id,section_id,prompt,justification) values (299,13,'¿Cómo se mapean los factores a los vehículos de GBM?','GBM ofrece vehículos para implementar cada factor o combinaciones, permitiendo construir exposiciones factoriales diversificadas desde la app, ya sea con enfoque integrado o mixto.');
insert into questions(id,section_id,prompt,justification) values (300,13,'Síntesis (capstone). Un cliente con horizonte largo quiere &quot;invertir como los profesionales, con base científica&quot;. El enfoque factorial correcto sería:','Integra todo el bloque y el banco: inversión sistemática basada en evidencia (+60 años y Premios Nobel), diversificación factorial para suavizar la ciclicidad, atención a costos (Advisor&#x27;s Alpha) y disciplina conductual (la verdadera fuente de fracaso). El rol del asesor —médico del dinero— es sostener al cliente en el plan cuando un factor atraviesa su invierno.');
insert into questions(id,section_id,prompt,justification) values (301,14,'Según la teoría de portafolios por ciclo de vida, la riqueza total del inversionista es:','El marco de Ibbotson, Milevsky, Chen y Zhu (2007) integra capital humano y financiero. En la juventud domina el capital humano; con la edad este se &quot;convierte&quot; en capital financiero, lo que justifica (en la teoría tradicional) reducir el riesgo de la cartera con el tiempo.');
insert into questions(id,section_id,prompt,justification) values (302,14,'El principio de Bodie, Merton y Samuelson (1992) sobre la flexibilidad laboral establece que:','La flexibilidad laboral es una opción implícita: quien puede trabajar más o posponer el retiro ante un mal escenario tiene mayor capacidad de absorber riesgo financiero, igual que un capital humano &quot;tipo bono&quot; estable lo permite.');
insert into questions(id,section_id,prompt,justification) values (303,14,'Los dos &quot;dogmas&quot; tradicionales de la inversión por ciclo de vida —precisamente los que el paper de Anarkulova et al. cuestiona— son:','Estos dos principios son la base de los target-date funds y de los glidepath regulatorios (como las Siefores generacionales). El paper los somete a una &quot;evaluación crítica&quot;.');
insert into questions(id,section_id,prompt,justification) values (304,14,'La &quot;aversión miópica a las pérdidas&quot; (Benartzi y Thaler, 1995) implica que:','En el experimento, quienes veían resultados anuales invertían ~60% en acciones vs. ~40% de quienes los veían a diario, ante la misma volatilidad. Ver menos el portafolio (automatizar) reduce el dolor de la volatilidad de corto plazo y favorece mantener más renta variable. Conecta con la aversión a las pérdidas (Sección 4).');
insert into questions(id,section_id,prompt,justification) values (305,14,'El portafolio óptimo que propone Anarkulova, Cederburg y O&#x27;Doherty (2023) para todo el ciclo de vida es:','El hallazgo central es que una cartera 100% de renta variable, repartida mitad doméstica/mitad internacional y sostenida toda la vida, supera ampliamente a las estrategias por edad (acciones-bonos).');
insert into questions(id,section_id,prompt,justification) values (306,14,'¿En qué dimensiones encuentra el paper que la estrategia all-equity supera a los glidepath por edad?','El paper documenta superioridad de la estrategia all-equity en las cuatro dimensiones simultáneamente, no solo en acumulación de riqueza.');
insert into questions(id,section_id,prompt,justification) values (307,14,'La estrategia all-equity del paper desafía directamente la práctica de los target-date funds porque:','El segundo dogma cuestionado es precisamente &quot;reducir acciones con la edad&quot;. El paper sostiene que incluso el jubilado obtiene mejores resultados manteniendo all-equity, en contra del diseño de los TDFs.');
insert into questions(id,section_id,prompt,justification) values (308,14,'La metodología del paper se basa principalmente en:','El remuestreo por bloques conserva las no-normalidades y la dependencia temporal de los rendimientos sin tener que especificar de antemano qué propiedades importan; el uso de 38 países mitiga el sesgo de supervivencia y el &quot;easy-data bias&quot;.');
insert into questions(id,section_id,prompt,justification) values (309,14,'¿Por qué el paper concluye que las acciones internacionales diversifican mejor que los bonos en horizontes largos?','Uno de los argumentos clave (Cederburg) es que la correlación bonos-acciones aumenta en horizontes largos, erosionando el beneficio de diversificación de los bonos; la inflación añade riesgo real a la renta fija de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (310,14,'Un resultado contraintuitivo del paper es que la estrategia all-equity, pese a su mayor volatilidad de corto plazo:','La intuición tradicional asocia más acciones con más riesgo de quedarse sin dinero; el paper encuentra lo contrario en el largo plazo, porque el mayor rendimiento esperado de la renta variable más que compensa su volatilidad bajo la distribución empírica de retornos.');
insert into questions(id,section_id,prompt,justification) values (311,14,'La magnitud de las &quot;ganancias de bienestar&quot; que estima el paper para los estadounidenses al adoptar la estrategia all-equity es:','El paper cuantifica las ganancias de bienestar potenciales en &quot;trillions of dollars&quot; (billones en español) para los ahorradores estadounidenses, lo que motivó gran parte del debate público. (Recordatorio de terminología: <em>trillion</em> en inglés = billón en español.)');
insert into questions(id,section_id,prompt,justification) values (312,14,'Respecto a la composición geográfica de la renta variable, el paper advierte que:','Conecta con el home bias (Sección 6): los autores enfatizan evitar la sobreconcentración doméstica. El reparto 50/50 doméstico/internacional es central a su resultado, no un detalle accesorio.');
insert into questions(id,section_id,prompt,justification) values (313,14,'La estrategia all-equity del paper se compara, entre otras, contra:','El paper evalúa la all-equity frente al abanico de opciones por defecto de los planes de retiro (TDFs, balanceadas, money market/bills), mostrando su superioridad en las métricas de bienestar consideradas.');
insert into questions(id,section_id,prompt,justification) values (314,14,'La principal crítica de Cliff Asness (AQR) en &quot;Why Not 100% Equities&quot; es que:','Asness defiende el principio media-varianza: lo relevante es el rendimiento ajustado por riesgo. Si se acepta apalancamiento, una cartera de mayor Sharpe apalancada domina a la de 100% acciones; sin él, la conclusión depende de las preferencias del inversionista.');
insert into questions(id,section_id,prompt,justification) values (315,14,'El argumento del Sharpe ratio contra el &quot;100% acciones&quot; sostiene que:','Es la lógica de la Línea del Mercado de Capitales (Secciones 3 y 8): el inversionista óptimo combina el portafolio de mayor Sharpe con el activo libre de riesgo, no necesariamente el de mayor rendimiento absoluto. La objeción práctica es que muchos inversionistas no pueden apalancarse (lo que reconecta con el factor BAB de la Sección 13).');
insert into questions(id,section_id,prompt,justification) values (316,14,'Un punto en el que incluso críticos como Asness coinciden parcialmente con el paper es:','Asness se muestra escéptico del glidepath automático por edad: la tolerancia al riesgo del jubilado depende de su riqueza y de su motivo de legado, no solo de su edad. El debate no es &quot;todo o nada&quot;.');
insert into questions(id,section_id,prompt,justification) values (317,14,'¿Cuál es la lectura epistemológicamente correcta del debate ACO vs. críticos?','Es un debate vivo. Lo robusto es la evidencia sobre el comportamiento de los activos en el largo plazo; lo discutible es saltar de ahí a una receta universal. La asignación adecuada sigue siendo específica al cliente.');
insert into questions(id,section_id,prompt,justification) values (318,14,'El &quot;volatility laundering&quot; (lavado de volatilidad) describe que:','La falta de marcaje a mercado de los activos ilíquidos disfraza su riesgo. El deck señala que el inversionista mexicano promedio concentra patrimonio en alternativos ilíquidos de alto riesgo (México es 3.º mundial en negocios familiares) creyéndolos más seguros que la bolsa.');
insert into questions(id,section_id,prompt,justification) values (319,14,'El estudio de Barber y Odean (2000) sobre el costo del overtrading encontró que:','El overtrading, alimentado por la sobreconfianza (Sección 4), erosiona el rendimiento vía costos y mal timing. Refuerza el principio &quot;replicar el mercado completo&quot; en lugar de hacer stock picking activo.');
insert into questions(id,section_id,prompt,justification) values (320,14,'El &quot;costo del market timing&quot; se ilustra con que, en el S&amp;P 500 (2000–2024):','La cercanía entre los mejores y peores días hace casi imposible salir y reentrar con acierto; intentarlo arriesga perderse la recuperación. La disciplina de permanecer invertido es lo que captura la prima de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (321,14,'El &quot;equity premium puzzle&quot; y la evidencia internacional sugieren que:','La prima de riesgo de la renta variable es real pero variable y no garantizada; la evidencia internacional (clave en el paper ACO) muestra primas más modestas que la experiencia estadounidense, lo que matiza el optimismo basado solo en datos de EE.UU.');
insert into questions(id,section_id,prompt,justification) values (322,14,'En la elicitación de tolerancia al riesgo, expresar la aversión &quot;en dinero&quot; (cuánto pagaría el cliente por evitar una apuesta sobre su ingreso) sirve para:','Convertir la aversión al riesgo a términos monetarios concretos (como en el &quot;quiz del demonio&quot; de Campbell) hace operativa una variable difusa y ayuda a alinear la cartera con la disposición —no solo la capacidad— del cliente (ver Sección 6, capacidad vs. disposición).');
insert into questions(id,section_id,prompt,justification) values (323,14,'Para un inversionista joven mexicano, una lectura razonable de los hallazgos de ACO sería:','El espíritu del paper —más renta variable, bien diversificada globalmente, durante más tiempo— se implementa con productos de mercado amplio. No implica concentración ni abandonar la gestión del riesgo conductual del cliente.');
insert into questions(id,section_id,prompt,justification) values (324,14,'¿Qué tensión genera el paper de ACO frente al glidepath de las Siefores generacionales (Sección 10)?','Hay una tensión genuina: la evidencia del paper apunta a más renta variable por más tiempo, pero el diseño regulatorio prioriza la protección del pensionado y opera bajo restricciones legales y conductuales. Reconocer esa tensión —sin resolverla dogmáticamente— es parte del juicio del asesor.');
insert into questions(id,section_id,prompt,justification) values (325,14,'Síntesis (capstone). ¿Cuál es la conclusión profesional más equilibrada que un asesor debe extraer del debate sobre el &quot;all-equity lifecycle&quot;?','Integra todo el bloque y el banco: la evidencia de largo plazo desafía el status quo, pero la asignación óptima es específica al cliente. El mayor riesgo no es la volatilidad en sí, sino que el cliente abandone una estrategia agresiva en el peor momento (Secciones 4, 5 y 7). El rol del asesor —médico del dinero— es diseñar una asignación que el cliente pueda <em>sostener</em>.');
insert into questions(id,section_id,prompt,justification) values (326,15,'¿Qué define a una inversión alternativa?','Los ejemplos más comunes son capital privado, deuda privada, desarrollo inmobiliario directo (no FIBRAs), infraestructura, commodities, criptoactivos y hedge funds. Sus rasgos (iliquidez, short, apalancamiento, mercados privados) los separan de las clases tradicionales.');
insert into questions(id,section_id,prompt,justification) values (327,15,'Según datos del London Stock Exchange Group (2024), las inversiones alternativas representan:','Aunque reciben mucha atención, los alternativos son una fracción pequeña (~1.79%) del universo invertible. La mayoría se negocia en mercados privados, con menor regulación y transparencia que los públicos. (Recordatorio: <em>trillion</em> en inglés = billón en español.)');
insert into questions(id,section_id,prompt,justification) values (328,15,'Según la encuesta de miembros de CAIA, las principales razones para invertir en alternativos son:','Los alternativos se buscan por descorrelación con activos tradicionales, potencial de alfa, ingreso y protección inflacionaria; no por seguridad ni liquidez.');
insert into questions(id,section_id,prompt,justification) values (329,15,'La advertencia central de CAIA sobre los activos alternativos es que:','CAIA, pese a creer en los alternativos para capital de largo plazo, advierte que no es seguro que el alfa &quot;aparezca&quot; cuando se necesita; el inversionista debe atravesar ciclos completos para cosechar sus beneficios.');
insert into questions(id,section_id,prompt,justification) values (330,15,'La &quot;prima de iliquidez&quot; esperada de los mercados privados sostiene que los activos ilíquidos deberían rendir más, pero el análisis de JP Morgan AM (1978–2023) sobre FIBRAs vs. bienes raíces privados encontró que:','Las FIBRAs se beneficiaron de mayor exposición a sectores de crecimiento, uso más eficiente del apalancamiento y costos menores. La supuesta prima de iliquidez del activo privado no se materializó frente al vehículo líquido y cotizado.');
insert into questions(id,section_id,prompt,justification) values (331,15,'El &quot;espejismo&quot; de los mercados privados (tesis GBM) consiste en que:','A diferencia de los mercados bursátiles —donde el precio se ve en todo momento— el activo privado solo se &quot;valúa&quot; al comprar y al vender. Esa invisibilidad de la volatilidad genera una ilusión de seguridad que el asesor debe revelar.');
insert into questions(id,section_id,prompt,justification) values (332,15,'El capital privado (private equity) consiste en:','El PE opera en mercados privados, requiere capital sustancial y horizontes largos, y busca crear valor en la empresa adquirida antes de una salida (exit) rentable.');
insert into questions(id,section_id,prompt,justification) values (333,15,'El venture capital (VC) se distingue del private equity en general porque:','El VC apuesta a empresas jóvenes con alto potencial de crecimiento pero alta tasa de fracaso; sus retornos son muy dispersos y concentrados en pocos &quot;ganadores&quot;.');
insert into questions(id,section_id,prompt,justification) values (334,15,'¿Cuál es una característica típica de las inversiones en PE/VC?','El inversionista compromete capital por años sin liquidez, y la creación de valor (y la salida) toma tiempo; por eso la due diligence y el horizonte son críticos.');
insert into questions(id,section_id,prompt,justification) values (335,15,'La &quot;curva J&quot; (J-curve) del private equity describe que:','Las comisiones y el periodo de inversión deprimen los retornos iniciales; el valor se materializa después, dando a la curva de retorno acumulado su forma de &quot;J&quot;.');
insert into questions(id,section_id,prompt,justification) values (336,15,'El &quot;dry powder&quot; en el mercado de capital privado se refiere a:','El dry powder elevado indica abundancia de capital comprometido frente a oportunidades de inversión atractivas; demasiado dry powder puede presionar valuaciones y rendimientos futuros.');
insert into questions(id,section_id,prompt,justification) values (337,15,'La tendencia de que las empresas permanezcan privadas más tiempo implica que:','La formación de capital ocurre cada vez más en privado; esto explica el interés institucional en PE/VC para capturar el crecimiento que antes se daba tras el IPO.');
insert into questions(id,section_id,prompt,justification) values (338,15,'Un &quot;search fund&quot; es:','El search fund financia primero la búsqueda y luego la adquisición de una empresa establecida que el searcher dirigirá. Es una clase de PE estudiada de cerca por Stanford GSB; sus retornos históricos han sido atractivos pero muy dispersos.');
insert into questions(id,section_id,prompt,justification) values (339,15,'La deuda privada (private credit) se caracteriza por:','La deuda privada financia prestatarios que no acuden (o no acceden) a los mercados públicos; ofrece mayor rendimiento a cambio de iliquidez y riesgo de crédito.');
insert into questions(id,section_id,prompt,justification) values (340,15,'En México, una forma común de invertir en deuda privada es a través de las SOFOMes, que:','La tasa atractiva de 11–15% no es &quot;gratis&quot;: refleja el riesgo de fondear préstamos a segmentos no atendidos por la banca tradicional, a tasas que pueden ser de triple dígito. La accesibilidad y la &quot;tasa garantizada&quot; crean otro espejismo de bajo riesgo.');
insert into questions(id,section_id,prompt,justification) values (341,15,'Los hedge funds se caracterizan por:','Su menor regulación les permite usar apalancamiento, cortos y derivados; el desempeño depende fuertemente de la habilidad del gestor, y la opacidad obliga a una diligencia exhaustiva.');
insert into questions(id,section_id,prompt,justification) values (342,15,'Los activos reales (commodities, recursos naturales, infraestructura) se incluyen en portafolios principalmente por:','Los activos reales tienden a comportarse distinto a acciones y bonos y a proteger frente a la inflación, aunque con su propia iliquidez y riesgos específicos.');
insert into questions(id,section_id,prompt,justification) values (343,15,'Un &quot;co-investment&quot; (coinversión) en private equity consiste en:','Según CAIA, ~60% de sus miembros considera que las coinversiones reducen comisiones o dan mayor control; permiten mantener la inversión más allá de la vida del fondo original.');
insert into questions(id,section_id,prompt,justification) values (344,15,'Las inversiones en coleccionables y activos tangibles (arte, vino, monedas) presentan:','Aunque pueden apreciarse, su valuación depende de demanda y modas, son ilíquidos y no generan ingresos, por lo que su papel en un portafolio es marginal y especulativo.');
insert into questions(id,section_id,prompt,justification) values (345,15,'Los CKDs (Certificados de Capital de Desarrollo) son:','Los CKDs &quot;bursatilizan&quot; el acceso al capital privado dentro del marco regulatorio mexicano, permitiendo a inversionistas institucionales como las AFOREs invertir en proyectos privados a través de un certificado listado.');
insert into questions(id,section_id,prompt,justification) values (346,15,'Los CERPIs (Certificados de Proyectos de Inversión) se distinguen de los CKDs principalmente porque:','Los CERPIs se crearon para dar a los inversionistas institucionales (en especial las AFOREs) acceso a estrategias de capital privado internacionales con mayor flexibilidad que los CKDs originales.');
insert into questions(id,section_id,prompt,justification) values (347,15,'La participación de las AFOREs en instrumentos estructurados (CKDs y CERPIs):','Como vimos en la Sección 10, las Siefores destinan una porción (sujeta a límites por tipo de Siefore) a CKDs/CERPIs, canalizando ahorro para el retiro hacia el financiamiento de proyectos privados del país.');
insert into questions(id,section_id,prompt,justification) values (348,15,'¿Por qué existen vehículos listados como los CKDs/CERPIs para el capital privado en México?','Estos vehículos &quot;envuelven&quot; el capital privado en un instrumento listado y supervisado, conciliando el acceso a mercados privados con las exigencias regulatorias de inversionistas como las AFOREs.');
insert into questions(id,section_id,prompt,justification) values (349,15,'La estructura de comisiones clásica de un fondo de PE/hedge fund (&quot;2 and 20&quot;) consiste en:','El &quot;2 y 20&quot; alinea (parcialmente) al gestor con el inversionista vía el carry, pero implica costos elevados que el inversionista debe ponderar contra el valor agregado real del gestor.');
insert into questions(id,section_id,prompt,justification) values (350,15,'El &quot;hurdle rate&quot; (o preferred return) en un fondo de capital privado es:','El hurdle protege a los LPs: el GP solo participa en las ganancias (carry) una vez superado ese umbral de rendimiento preferente, reforzando la alineación de incentivos.');
insert into questions(id,section_id,prompt,justification) values (351,15,'En la estructura de un fondo de PE, el General Partner (GP) y los Limited Partners (LPs) son, respectivamente:','El GP gestiona y asume la responsabilidad operativa (y cobra comisiones/carry); los LPs aportan la mayor parte del capital y limitan su exposición a lo invertido.');
insert into questions(id,section_id,prompt,justification) values (352,15,'¿Por qué la due diligence y la diversificación por &quot;añadas&quot; (vintage years) son especialmente importantes en alternativos?','La enorme dispersión de resultados entre gestores y el efecto del ciclo (timing de la añada) hacen que la selección rigurosa y la diversificación temporal sean determinantes del resultado en mercados privados.');
insert into questions(id,section_id,prompt,justification) values (353,15,'¿Cómo se mide típicamente el desempeño de un fondo de private equity?','Como el GP controla el timing de las llamadas y distribuciones de capital, se usan métricas money-weighted (IRR, múltiplos) y comparaciones PME, en lugar del rendimiento time-weighted típico de los fondos líquidos.');
insert into questions(id,section_id,prompt,justification) values (354,15,'¿Cuál es la tesis central de GBM sobre los activos alternativos para el inversionista mexicano promedio?','México es de los países más emprendedores (OCDE) y donde los negocios familiares pesan más en el PIB (~70%, 3.º global). El asesor —médico del dinero— debe revelar el riesgo oculto de esas posiciones concentradas e ilíquidas, no validar el espejismo de seguridad.');
insert into questions(id,section_id,prompt,justification) values (355,15,'Síntesis (capstone). ¿Cuál es el papel apropiado de los activos alternativos en un portafolio?','Integra el bloque: los alternativos pueden tener un papel legítimo (descorrelación, retorno, cobertura), pero exigen idoneidad, horizonte, due diligence y dimensionamiento. El riesgo no desaparece por no verse; el deber del asesor es hacerlo visible y ponderar costos, iliquidez y la dispersión de resultados.');
insert into questions(id,section_id,prompt,justification) values (356,16,'Según el material de GBM, una nota estructurada se define como:','La esencia de una nota estructurada es la combinación de un componente de renta fija (que ancla el capital o genera el flujo base) con uno o más derivados (que definen el perfil de pago ligado a un subyacente).');
insert into questions(id,section_id,prompt,justification) values (357,16,'Estructuralmente, una nota con capital protegido se construye combinando:','El cupón cero comprado bajo la par crece hasta el nominal al vencimiento (protege el capital), y el remanente del capital se destina a comprar la opción que da el upside. Esta descomposición es clave para entender y valuar la nota.');
insert into questions(id,section_id,prompt,justification) values (358,16,'¿Qué objetivos principales pueden satisfacer las notas estructuradas según GBM?','La flexibilidad de las notas permite &quot;diseñar&quot; el perfil deseado: desde protección de capital hasta amplificación o generación de ingreso, según el objetivo del cliente.');
insert into questions(id,section_id,prompt,justification) values (359,16,'¿Cuáles pueden ser activos subyacentes de las notas estructuradas distribuidas por GBM?','El subyacente puede ser prácticamente cualquier variable de mercado con un derivado líquido asociado, lo que da enorme versatilidad para construir el payoff.');
insert into questions(id,section_id,prompt,justification) values (360,16,'¿Cuál es el rol de GBM en el mercado de notas estructuradas y su valor agregado?','Al no ser emisor, GBM puede comparar (beauty contest) cotizaciones de varios emisores para conseguir mejores términos y diversificar el riesgo de contraparte, alineándose con el cliente en lugar de &quot;colocar producto propio&quot;.');
insert into questions(id,section_id,prompt,justification) values (361,16,'Según el curso de GBM, los tres riesgos principales de las notas estructuradas son:','El riesgo de mercado (el subyacente se mueve en contra), el de iliquidez (difícil vender antes del vencimiento) y el de contraparte (solvencia del emisor) son los tres ejes que el asesor debe explicar siempre.');
insert into questions(id,section_id,prompt,justification) values (362,16,'Una nota con capital protegido (principal-protected) ofrece:','Protege el nominal a vencimiento y da upside parcial; pero la &quot;protección&quot; depende de que el emisor pague (riesgo de contraparte) y normalmente aplica solo al vencimiento, no antes.');
insert into questions(id,section_id,prompt,justification) values (363,16,'La &quot;tasa de participación&quot; (participation rate) de una nota indica:','La participación calibra cuánto del movimiento del subyacente se traslada al inversionista; una mayor protección de capital suele implicar menor participación, y viceversa.');
insert into questions(id,section_id,prompt,justification) values (364,16,'Un &quot;cap&quot; (tope) en una nota estructurada significa que:','El cap es la contraparte de un beneficio: el inversionista renuncia al alza por encima de cierto nivel a cambio de mejores condiciones en otra dimensión de la nota.');
insert into questions(id,section_id,prompt,justification) values (365,16,'Una nota de yield enhancement / reverse convertible se caracteriza por:','El cupón atractivo no es gratis: el inversionista vende implícitamente una opción (asume el downside del subyacente). Es lo opuesto a una nota de capital protegido.');
insert into questions(id,section_id,prompt,justification) values (366,16,'Una nota autollamable (autocallable) funciona así:','La autollamable busca generar ingreso en mercados laterales o moderadamente alcistas; el cupón puede tener &quot;memoria&quot; (recupera cupones no pagados), pero si el subyacente cae bajo la barrera al final, el inversionista absorbe la pérdida.');
insert into questions(id,section_id,prompt,justification) values (367,16,'Una nota &quot;worst-of&quot; (peor de) ligada a varios subyacentes:','Atar el pago al peor de varios activos eleva la probabilidad de un resultado adverso (basta que uno caiga), por lo que el emisor compensa con un cupón mayor. Es una fuente común de riesgo subestimado.');
insert into questions(id,section_id,prompt,justification) values (368,16,'La diferencia entre un &quot;buffer&quot; y una &quot;barrera&quot; (barrier) de protección es que:','El buffer da una protección robusta pero limitada (p. ej., absorbe la primera caída del 20%); la barrera protege más mientras no se toque, pero si se vulnera el inversionista queda expuesto a toda la caída. Es una distinción crítica de riesgo.');
insert into questions(id,section_id,prompt,justification) values (369,16,'Una nota apalancada (leveraged) busca:','El apalancamiento multiplica tanto las ganancias como —si no hay protección— las pérdidas; suele combinarse con un cap que limita el alza amplificada.');
insert into questions(id,section_id,prompt,justification) values (370,16,'Una nota digital (binaria) paga:','El pago digital es de tipo &quot;todo o nada&quot; sobre una condición; útil para expresar una visión binaria del mercado, pero con un perfil de pago discontinuo que el cliente debe entender.');
insert into questions(id,section_id,prompt,justification) values (371,16,'Un costo frecuentemente oculto de las notas ligadas a acciones o índices es que:','Renunciar a los dividendos (rendimiento total vs. de precio) es un costo real que abarata la estructura para el emisor y que el inversionista a menudo no percibe; el asesor debe hacerlo explícito.');
insert into questions(id,section_id,prompt,justification) values (372,16,'El riesgo más subestimado de una nota &quot;con capital protegido&quot; es:','La &quot;protección de capital&quot; es solo tan buena como la solvencia del emisor. El colapso de las notas de Lehman es el caso emblemático: la protección era frente al mercado, no frente a la quiebra del emisor.');
insert into questions(id,section_id,prompt,justification) values (373,16,'El riesgo de iliquidez en una nota estructurada implica que:','A diferencia de un ETF, una nota no se negocia en un mercado líquido; el horizonte debe coincidir con el vencimiento, y la salida anticipada raramente es eficiente.');
insert into questions(id,section_id,prompt,justification) values (374,16,'Respecto a la complejidad y los costos de las notas estructuradas:','Los costos no se cobran aparte, sino que están embebidos en los parámetros (participación, cap, barrera). Comparar emisores y descomponer la nota es la mejor defensa del inversionista.');
insert into questions(id,section_id,prompt,justification) values (375,16,'La &quot;protección de capital&quot; de una nota estructurada debe entenderse como:','Hay que matizar la palabra &quot;protegido&quot;: protege el nominal a vencimiento contra el movimiento del subyacente, pero no contra el default del emisor ni contra la pérdida de poder adquisitivo. Sobrevender la &quot;garantía&quot; es un error de asesoría.');
insert into questions(id,section_id,prompt,justification) values (376,16,'En la valuación de una nota, el entorno de tasas de interés influye porque:','Cuando las tasas bajan, el cupón cero necesario para devolver el nominal cuesta más, por lo que queda menos para comprar upside; por eso las notas de capital protegido ofrecen mejores términos en entornos de tasas altas.');
insert into questions(id,section_id,prompt,justification) values (377,16,'Para que una nota estructurada sea adecuada para un cliente, el asesor debe:','Por su complejidad, las notas exigen una explicación rigurosa de escenarios y riesgos, y un dimensionamiento prudente dentro del plan integral del cliente. Transparencia total es parte del deber fiduciario.');
insert into questions(id,section_id,prompt,justification) values (378,16,'¿Para qué tipo de cliente y contexto es más apropiada una nota con capital protegido?','La nota de capital protegido encaja con un perfil averso a perder el nominal pero dispuesto a renunciar a parte del alza y a la liquidez, siempre que comprenda que la &quot;protección&quot; está condicionada a la solvencia del emisor.');
insert into questions(id,section_id,prompt,justification) values (379,16,'Una nota de yield enhancement / autollamable es apropiada para, y peligrosa si:','Estas notas cambian protección por ingreso: brillan en mercados estables, pero exponen al capital si el subyacente cae bajo la barrera. Vendérselas a un cliente que cree tener &quot;capital seguro&quot; es un desajuste grave de idoneidad.');
insert into questions(id,section_id,prompt,justification) values (380,16,'Síntesis (capstone). ¿Cómo debe un asesor presentar una nota estructurada a su cliente?','Integra el bloque: una nota no es &quot;mágica&quot; ni &quot;garantizada&quot;; es un bono más uno o varios derivados, con riesgos concretos (emisor, iliquidez, mercado) y costos ocultos. El asesor agrega valor al traducir esa complejidad en escenarios claros y al dimensionarla correctamente dentro del plan —nunca vendiendo la &quot;protección&quot; sin el matiz del riesgo de contraparte—.');
insert into questions(id,section_id,prompt,justification) values (381,17,'El hallazgo más citado de Bessembinder (2018) es que:','Contra la creencia popular de que &quot;las acciones siempre ganan a largo plazo&quot;, la mayoría de las acciones individuales ni siquiera supera a las letras del Tesoro a lo largo de su vida cotizada. La &quot;verdad&quot; del premio accionario aplica al mercado agregado, no a la acción típica.');
insert into questions(id,section_id,prompt,justification) values (382,17,'En términos de creación de riqueza en dólares, Bessembinder encontró que:','La creación de riqueza está extraordinariamente concentrada: un puñado de grandes ganadoras genera toda la ganancia neta sobre los T-bills, mientras el resto, agregado, solo empata con las letras.');
insert into questions(id,section_id,prompt,justification) values (383,17,'La creación de riqueza neta (lifetime dollar wealth creation) del mercado accionario de EE.UU. estimada en el estudio original (1926–2016) fue aproximadamente:','El estudio cuantifica ≈$34.8 billones de creación de riqueza neta a diciembre de 2016 (actualizaciones posteriores del autor elevan la cifra). Toda esa ganancia neta proviene del 4.3% superior de las acciones. (Recordatorio: <em>trillion</em> en inglés = billón en español.)');
insert into questions(id,section_id,prompt,justification) values (384,17,'La metodología del estudio se basa en:','El uso de prácticamente todas las acciones de CRSP durante ~90 años, con rendimientos compuestos de por vida, es lo que permite observar la distribución completa de resultados —incluidas las muchas acciones que desaparecieron—.');
insert into questions(id,section_id,prompt,justification) values (385,17,'Respecto a la distribución de los rendimientos de por vida de las acciones individuales:','La enorme asimetría positiva implica que el promedio (jalado por unas pocas ganadoras extremas) está muy por encima de la mediana; la acción típica pierde frente a los T-bills, aunque el promedio del mercado sea positivo.');
insert into questions(id,section_id,prompt,justification) values (386,17,'¿Cuál es la explicación central de por qué pocas acciones generan toda la riqueza?','La skewness es el corazón del paper: el rendimiento del mercado depende de la cola derecha (las pocas grandes ganadoras), no del desempeño de la acción mediana.');
insert into questions(id,section_id,prompt,justification) values (387,17,'Según Bessembinder, la asimetría positiva de los rendimientos de por vida proviene de:','Componer rendimientos positivos durante décadas estira la cola derecha (un acierto sostenido se multiplica), mientras que lo peor que puede pasar es perder el 100%. La combinación de skewness mensual + compounding produce la extrema asimetría de por vida.');
insert into questions(id,section_id,prompt,justification) values (388,17,'¿Por qué la mayoría de las acciones queda por debajo del rendimiento promedio?','El límite inferior (-100%) y el potencial ilimitado al alza generan asimetría: la mayoría de las observaciones cae por debajo de una media inflada por la cola derecha. Es estadística, no pesimismo.');
insert into questions(id,section_id,prompt,justification) values (389,17,'¿Cómo reconcilia el paper que el mercado supere a los T-bills aunque la mayoría de las acciones no lo haga?','Es la resolución de la paradoja: el premio accionario es real a nivel de mercado precisamente porque el índice captura a las grandes ganadoras; quien no las posee (carteras concentradas) probablemente se queda corto.');
insert into questions(id,section_id,prompt,justification) values (390,17,'La implicación principal del paper para la gestión de portafolios es que:','Si la riqueza la crea el 4% superior, una cartera de pocas acciones tiene alta probabilidad de perderse a las ganadoras y quedar rezagada. El paper ofrece un sustento estadístico, más allá de las comisiones, para diversificar.');
insert into questions(id,section_id,prompt,justification) values (391,17,'¿Cómo refuerza Bessembinder el argumento a favor de la indexación amplia?','Conecta con la Sección 12 (indexación) y la 1/3 (activa vs. pasiva): la diversificación amplia asegura capturar la cola derecha que define el rendimiento del mercado, en lugar de apostar a identificarla de antemano.');
insert into questions(id,section_id,prompt,justification) values (392,17,'Para un cliente con la mayor parte de su patrimonio en una sola acción (p. ej., la empresa que fundó o donde trabaja), el paper sugiere que:','Es una aplicación directa y muy relevante para México (fundadores, negocios familiares, posiciones heredadas): la asimetría implica que apostar todo a una sola acción tiene alta probabilidad de decepcionar. Enlaza con el &quot;espejismo&quot; de la concentración (Sección 15).');
insert into questions(id,section_id,prompt,justification) values (393,17,'¿Por qué el paper hace el caso contra la gestión activa aún más fuerte de lo que se pensaba?','El estudio sugiere que el reto de la gestión activa no es solo de costos, sino de la propia forma de la distribución: omitir las ganadoras extremas penaliza fuertemente, elevando lo que está en juego al seleccionar gestores.');
insert into questions(id,section_id,prompt,justification) values (394,17,'¿Qué NO afirma el paper de Bessembinder (lectura cuidadosa)?','Es importante no sobreinterpretar: el hallazgo no es anti-acciones, sino pro-diversificación. El premio por riesgo de la renta variable a nivel de mercado sigue siendo real; lo frágil es apostar a acciones individuales.');
insert into questions(id,section_id,prompt,justification) values (395,17,'Síntesis (capstone). ¿Cómo usa un asesor el paper de Bessembinder con un cliente?','Integra el bloque y enlaza con el club de lectura y la filosofía &quot;médico del dinero&quot;: la evidencia de Bessembinder es una de las herramientas más poderosas para combatir la sobreconfianza y la concentración, y para explicar —con datos— por qué la diversificación amplia no es mediocridad, sino la forma racional de capturar el premio accionario.');
insert into questions(id,section_id,prompt,justification) values (396,18,'El hallazgo agregado central de Fama-French (2010) es que:','En conjunto, los fondos activos &quot;son&quot; aproximadamente el mercado antes de costos; lo que los hunde frente al inversionista es el costo de gestionarlos. El alfa bruto agregado ronda cero y el neto es negativo por el monto de los costos.');
insert into questions(id,section_id,prompt,justification) values (397,18,'El principio de &quot;equilibrium accounting&quot; que aplican Fama y French sostiene que:','Por contabilidad de equilibrio, el conjunto de inversionistas activos no puede, en agregado, superar al mercado antes de costos (lo que uno gana otro lo pierde); tras descontar comisiones, el agregado necesariamente queda por debajo.');
insert into questions(id,section_id,prompt,justification) values (398,18,'¿Por qué Fama y French utilizan simulaciones de bootstrap?','El bootstrap es la innovación metodológica clave: permite preguntar si la cola de fondos &quot;ganadores&quot; es mayor de lo que la pura suerte produciría, distinguiendo habilidad genuina de azar.');
insert into questions(id,section_id,prompt,justification) values (399,18,'Los modelos de referencia (benchmark) que utiliza el paper para medir el alfa son:','Al ajustar por mercado, tamaño, valor (y momentum en el de cuatro factores), el alfa mide el desempeño que no se explica por exposiciones a factores conocidos —es decir, la habilidad &quot;real&quot; del gestor—. Conecta con las Secciones 3 y 13.');
insert into questions(id,section_id,prompt,justification) values (400,18,'¿Por qué evalúan los fondos usando el t-estadístico del alfa, t(α), y no solo el alfa?','Estandarizar por la precisión evita confundir un golpe de suerte de corta data con habilidad sostenida; el t(α) hace comparables fondos con historiales y volatilidades distintas.');
insert into questions(id,section_id,prompt,justification) values (401,18,'Respecto a los rendimientos NETOS (después de comisiones), el bootstrap encontró que:','Para el inversionista (neto de comisiones), el desempeño de la gran mayoría de los fondos es indistinguible de la suerte —o peor—; pocos cubren siquiera sus propios costos.');
insert into questions(id,section_id,prompt,justification) values (402,18,'Respecto a los rendimientos BRUTOS (sumando de vuelta las comisiones), el paper encontró que:','Antes de costos, las colas se ensanchan más de lo que la suerte explicaría: sí hay habilidad (y falta de ella) genuina. El matiz crítico es que esa habilidad existe en bruto, pero no necesariamente llega al inversionista.');
insert into questions(id,section_id,prompt,justification) values (403,18,'¿Cómo se reconcilia &quot;existe habilidad (bruto)&quot; con &quot;los inversionistas no la capturan (neto)&quot;?','Es el corazón del título &quot;suerte vs. habilidad&quot;: la habilidad existe pero es escasa y, neto de costos, prácticamente desaparece para el inversionista; distinguir ex ante al gestor hábil del afortunado es extremadamente difícil.');
insert into questions(id,section_id,prompt,justification) values (404,18,'La implicación práctica del paper para el inversionista es que:','Conecta con Bogle y la indexación (Sección 12), el costo en Advisor&#x27;s Alpha (Sección 5) y Bessembinder (Sección 17): si la habilidad neta es escasa e impredecible, la opción robusta es minimizar costos y diversificar, en lugar de apostar a seleccionar al ganador.');
insert into questions(id,section_id,prompt,justification) values (405,18,'Síntesis (capstone). ¿Qué afirma —y qué NO afirma— Fama-French (2010), y cómo lo usa un asesor?','Integra el bloque y el club de lectura: el paper es matizado, no nihilista. Sí existe habilidad (en bruto, en las colas), pero el costo y la dificultad de identificarla ex ante hacen que, para la mayoría de los inversionistas, un núcleo indexado de bajo costo sea la decisión racional. El asesor agrega valor gestionando costos, diversificación y conducta —no prometiendo &quot;el próximo fondo estrella&quot;—.');
insert into questions(id,section_id,prompt,justification) values (406,19,'Un bono (instrumento de renta fija) es esencialmente:','El tenedor de un bono es acreedor (no propietario): tiene derecho a flujos contractuales (cupones + principal), con prelación sobre los accionistas en caso de quiebra, pero sin participación en las utilidades.');
insert into questions(id,section_id,prompt,justification) values (407,19,'La relación entre el precio de un bono y las tasas de interés es:','Un bono con cupón fijo se vuelve menos atractivo cuando las nuevas emisiones pagan más, así que su precio cae hasta que su rendimiento iguala al de mercado. Esta relación inversa es el corazón del riesgo de tasa.');
insert into questions(id,section_id,prompt,justification) values (408,19,'Un bono cotiza &quot;a premio&quot; (sobre par) cuando:','Si el cupón supera al rendimiento exigido, el bono paga &quot;de más&quot; y el mercado lo valora por encima de la par; si el cupón es menor, cotiza a descuento; si son iguales, a la par.');
insert into questions(id,section_id,prompt,justification) values (409,19,'La diferencia entre la tasa cupón, el rendimiento corriente y el rendimiento al vencimiento (YTM) es:','El YTM es la medida más completa porque integra cupones, reinversión y la diferencia entre precio y valor nominal; el rendimiento corriente solo considera el flujo de cupón sobre el precio.');
insert into questions(id,section_id,prompt,justification) values (410,19,'Un bono cupón cero (como los CETES o ciertos instrumentos en GBMGUB):','Al concentrar todo el flujo en el vencimiento, el cupón cero tiene una duración igual a su plazo y, por tanto, mayor sensibilidad a tasas que un bono con cupones del mismo vencimiento.');
insert into questions(id,section_id,prompt,justification) values (411,19,'El rendimiento total de una inversión en bonos proviene de:','Descomponer el rendimiento en cupón + reinversión + precio es clave para entender por qué el resultado realizado puede diferir del YTM inicial (si las tasas de reinversión o de salida cambian).');
insert into questions(id,section_id,prompt,justification) values (412,19,'Un bono o fondo de tasa flotante (como la posición preponderante del GBMF3) se distingue porque:','Como el cupón &quot;sigue&quot; a las tasas, el precio de un flotante fluctúa poco ante cambios de tasa (baja duración); por eso GBMF3, preponderantemente flotante, tiene una duración efectiva corta (~3 meses).');
insert into questions(id,section_id,prompt,justification) values (413,19,'La duración de un fondo de deuda, según el material de GBM, mide:','Es la definición canónica de GBM: mayor duración = mayor sensibilidad del precio a las tasas (más riesgo de tasa), pero potencialmente mayor rendimiento como compensación.');
insert into questions(id,section_id,prompt,justification) values (414,19,'La regla práctica de GBM para mitigar el riesgo de tasa de interés al invertir en un fondo de deuda es:','Si el horizonte ≥ duración, las pérdidas temporales por alzas de tasa tienden a compensarse con la mayor reinversión, de modo que el inversionista captura aproximadamente el rendimiento esperado. Es la lógica de la inmunización.');
insert into questions(id,section_id,prompt,justification) values (415,19,'La duración modificada de un bono indica:','Un bono con duración modificada de 5 perderá ~5% si las tasas suben 1% (y ganará ~5% si bajan 1%). Es la herramienta central para cuantificar el riesgo de tasa.');
insert into questions(id,section_id,prompt,justification) values (416,19,'El GBMGUB tiene una duración efectiva de ~2 meses y el GBMDIV2 de ~11 meses. Esto implica que:','La diferencia de duración (≈2 vs ≈11 meses) explica por qué el DIV2 oscila más ante cambios de tasa; sumado a que el DIV2 asume riesgo de crédito (alto rendimiento), su perfil de riesgo es claramente mayor.');
insert into questions(id,section_id,prompt,justification) values (417,19,'La duración efectiva (en lugar de la de Macaulay o modificada) se usa cuando:','Cuando hay opcionalidad (call, put, prepago), los flujos no son fijos; la duración efectiva captura la sensibilidad real del precio considerando que los flujos pueden cambiar con las tasas.');
insert into questions(id,section_id,prompt,justification) values (418,19,'El &quot;DV01&quot; (o valor del punto base, PVBP) de un bono mide:','El DV01 traduce la sensibilidad a tasas a términos monetarios, útil para dimensionar y cubrir posiciones de renta fija; complementa a la duración (que se expresa en porcentaje).');
insert into questions(id,section_id,prompt,justification) values (419,19,'La convexidad de un bono describe que:','Por la convexidad, el precio cae menos de lo que predice la duración cuando las tasas suben, y sube más cuando bajan. La duración es una aproximación lineal; la convexidad corrige esa aproximación, especialmente ante grandes movimientos de tasa.');
insert into questions(id,section_id,prompt,justification) values (420,19,'El riesgo de reinversión y el riesgo de tasa (precio) se relacionan así:','Esta compensación es la base teórica de la regla &quot;horizonte ≥ duración&quot;: al igualar horizonte y duración, la pérdida de precio por alzas de tasa se equilibra con la mayor reinversión de los cupones.');
insert into questions(id,section_id,prompt,justification) values (421,19,'El riesgo de crédito y las calificaciones se relacionan en que:','A menor calificación, mayor rendimiento exigido (mayor riesgo de impago y menor recuperación esperada). Un fondo 100% gubernamental local AAA, como GBMGUB, prácticamente elimina ese riesgo (queda el de tasa).');
insert into questions(id,section_id,prompt,justification) values (422,19,'El &quot;spread de crédito&quot; (sobretasa) es:','El spread es la prima por asumir riesgo de crédito. Fondos como el GBMDIV2 (deuda corporativa de alto rendimiento) capturan spreads mayores asumiendo, explícitamente, un riesgo de crédito importante.');
insert into questions(id,section_id,prompt,justification) values (423,19,'Un bono redimible anticipadamente (callable) implica para el inversionista que:','La opción de recompra beneficia al emisor: cuando refinanciarse es conveniente (tasas a la baja), &quot;llama&quot; el bono y el inversionista debe reinvertir a tasas menores. Por ese riesgo, los callables suelen ofrecer mayor rendimiento.');
insert into questions(id,section_id,prompt,justification) values (424,19,'La forma de la curva de rendimiento (yield curve) y su lectura:','La curva refleja expectativas de tasas, inflación y crecimiento. La inversión de la curva (corto &gt; largo) ha precedido a varias recesiones, por lo que es una señal macro vigilada de cerca.');
insert into questions(id,section_id,prompt,justification) values (425,19,'Entre las teorías de la estructura temporal de tasas:','Estas teorías son complementarias: las expectativas explican el &quot;centro&quot; de la curva, la prima por liquidez su pendiente positiva habitual, y la segmentación los desajustes por tramos según oferta y demanda específicas.');
insert into questions(id,section_id,prompt,justification) values (426,19,'La tasa de referencia de Banxico influye en la renta fija porque:','La política monetaria mueve toda la curva (especialmente el corto plazo). Un ciclo de recortes reduce el costo de capital y eleva el valor presente de los flujos futuros, beneficiando a bonos y a activos de larga duración. (Verificar el nivel vigente de la tasa al usar el material.)');
insert into questions(id,section_id,prompt,justification) values (427,19,'Los CETES (Certificados de la Tesorería) son:','Los CETES son el activo de referencia del mercado de dinero mexicano; muchos fondos y SMAs de liquidez/renta fija (Smart Income, Deuda gubernamental) se comparan precisamente contra CETES de 28 días.');
insert into questions(id,section_id,prompt,justification) values (428,19,'Los Bonos M se caracterizan por:','Al ser de tasa fija y largo plazo, los Bonos M concentran el riesgo de tasa: pequeños cambios en el rendimiento mueven mucho su precio. Son la contraparte &quot;larga&quot; de los CETES.');
insert into questions(id,section_id,prompt,justification) values (429,19,'Los Udibonos sirven para:','Los Udibonos cubren el riesgo de inflación al entregar un rendimiento real fijo. La diferencia entre el rendimiento nominal (Bono M) y el real (Udibono) del mismo plazo aproxima la inflación implícita (breakeven).');
insert into questions(id,section_id,prompt,justification) values (430,19,'Los Bondes (p. ej., Bondes F) y los BPAs son ejemplos de:','Al ser de tasa revisable, su precio se mantiene cerca del par ante cambios de tasa (baja duración). Son útiles para reducir el riesgo de tasa de un portafolio de deuda, igual que la porción flotante del GBMF3.');
insert into questions(id,section_id,prompt,justification) values (431,19,'La deuda corporativa y bancaria en México (certificados bursátiles, papel comercial):','El emisor corporativo/bancario paga una sobretasa (spread) sobre el gobierno por su riesgo de crédito. Fondos como GBMF2, GBMF3 y GBMM3 combinan deuda gubernamental con corporativa/bancaria de alta calidad para mejorar el rendimiento controlando el riesgo.');
insert into questions(id,section_id,prompt,justification) values (432,19,'Entre GBMGUBL, GBMF2 y GBMF3, ¿cuál es la diferencia clave?','El anaquel se escala por riesgo de crédito y duración: de lo más conservador (GUBL, 100% gubernamental) a mezclas gubernamental/corporativo (F2 para liquidez, F3 mediano plazo flotante), permitiendo ubicar al cliente según su horizonte y tolerancia.');
insert into questions(id,section_id,prompt,justification) values (433,19,'Los fondos GBMDOL/CASH y el GBMDINT se distinguen porque:','Para exposición dolarizada directa están DOL/CASH; para renta fija global con ventaja fiscal (tributar como RV, tasa menor) está GBMDINT. El asesor elige según la moneda objetivo y la eficiencia fiscal buscada (enlaza con asset location, Sección 5).');
insert into questions(id,section_id,prompt,justification) values (434,19,'Para un cliente conservador que prioriza liquidez y preservación de capital, frente a uno que tolera más riesgo por mayor rendimiento, el anaquel GBM sugiere:','La idoneidad manda: liquidez/seguridad (F2, GUBL, M3 para morales exentas) vs. mayor rendimiento con más volatilidad y horizonte &gt; 1 año (RETO, DIV2, PAT). El asesor empata el fondo con el objetivo, el horizonte y la tolerancia del cliente.');
insert into questions(id,section_id,prompt,justification) values (435,19,'Síntesis (capstone). ¿Cómo construye un asesor el componente de renta fija de un portafolio?','Integra el bloque: la renta fija no es &quot;sin riesgo&quot;. El asesor gestiona duración vs. horizonte, calidad crediticia, y selecciona el fondo correcto del anaquel según la meta, comunicando con claridad que existen riesgos de tasa y de crédito —pieza esencial de una asesoría honesta y técnica—.');
insert into questions(id,section_id,prompt,justification) values (436,20,'El hallazgo central del paper de DeMiguel, Garlappi y Uppal es que:','El resultado es contraintuitivo y demoledor: las estrategias &quot;óptimas&quot; sofisticadas no logran batir de forma robusta a simplemente repartir por igual entre los activos, una vez que se mide el desempeño fuera de muestra.');
insert into questions(id,section_id,prompt,justification) values (437,20,'La regla &quot;1/N&quot; (diversificación ingenua) consiste en:','El 1/N no requiere estimar parámetros (su gran ventaja): evita por completo el error de estimación que aqueja a la optimización. Tiene raíces antiguas (la regla &quot;talmúdica&quot; de repartir en tercios).');
insert into questions(id,section_id,prompt,justification) values (438,20,'¿Por qué los modelos óptimos no logran superar al 1/N fuera de muestra?','En teoría (con parámetros conocidos) la optimización domina; en la práctica, hay que estimar medias y covarianzas con datos ruidosos, y esos errores destruyen las ganancias. Conecta con la &quot;maximización de errores&quot; de la optimización (Sección 8).');
insert into questions(id,section_id,prompt,justification) values (439,20,'El resultado sobre la &quot;ventana de estimación&quot; necesaria indica que:','Es la cifra más citada del paper: la cantidad de datos requerida para estimar los parámetros con suficiente precisión es absurdamente larga, lo que ilustra por qué la optimización falla con muestras realistas. &quot;Quedan muchas millas por recorrer&quot; antes de que sus promesas se materialicen.');
insert into questions(id,section_id,prompt,justification) values (440,20,'El alcance de la crítica del paper es amplio porque demostró que NO superan al 1/N:','La fortaleza del estudio es su amplitud: no derriba un solo modelo, sino toda una familia de enfoques sofisticados (incluidos los más modernos), usando tres métricas y siete conjuntos de datos.');
insert into questions(id,section_id,prompt,justification) values (441,20,'Las tres métricas de desempeño fuera de muestra que utilizó el estudio son:','Evaluar Sharpe (rendimiento ajustado por riesgo), CEQ (bienestar del inversionista) y turnover (costos de operar) da una imagen integral; el 1/N gana o empata en las tres de forma robusta.');
insert into questions(id,section_id,prompt,justification) values (442,20,'El factor del turnover es relevante porque:','Los pesos &quot;óptimos&quot; cambian mucho cuando cambian las estimaciones ruidosas, generando operación costosa. El bajo turnover del 1/N es otra de sus ventajas prácticas, especialmente después de costos.');
insert into questions(id,section_id,prompt,justification) values (443,20,'Respecto a por qué los rendimientos esperados son el principal culpable:','El error en las medias se amplifica enormemente en los pesos óptimos. Ignorarlas (mínima varianza) ayuda, pero no basta para vencer de forma robusta al 1/N: el error de estimación sigue dominando.');
insert into questions(id,section_id,prompt,justification) values (444,20,'¿Qué NO afirma el paper (lectura cuidadosa)?','Matiz importante: el paper es una crítica a la implementación práctica, no a la teoría de Markowitz. Motiva respuestas como el shrinkage, las restricciones de pesos y Black-Litterman (Sección 8), que buscan domar el error de estimación.');
insert into questions(id,section_id,prompt,justification) values (445,20,'Síntesis (capstone). ¿Qué lección extrae un asesor del paper 1/N?','Integra el bloque y se conecta con Bessembinder, Fama-French (2010) y la indexación: la sofisticación no garantiza mejores resultados fuera de muestra. La diversificación amplia, de bajo costo y baja rotación, mantenida con disciplina, es una base robusta; la optimización aporta valor solo si se controla rigurosamente el error de estimación.');
insert into questions(id,section_id,prompt,justification) values (446,21,'¿Qué es Smart Cash?','Smart Cash es una cuenta de depósito sin comisiones, pensada para el efectivo: genera rendimiento diario manteniendo alta disponibilidad en días hábiles, a diferencia de un fondo de inversión tradicional o una chequera bancaria.');
insert into questions(id,section_id,prompt,justification) values (447,21,'¿Cuál es la inversión inicial de Smart Cash y en qué invierte?','Con apenas $100 MXN de inversión inicial, Smart Cash coloca los recursos en instrumentos de bajo riesgo (reporto de CETES), lo que sustenta su perfil conservador y de alta disponibilidad.');
insert into questions(id,section_id,prompt,justification) values (448,21,'¿Cuál es la tasa de rendimiento de Smart Cash?','La tasa se ubica en el rango 4.00%–4.75%, escalonada por el monto total invertido en GBM y referenciada a Banxico; al no ser garantizada, puede ajustarse cuando cambian las condiciones de mercado.');
insert into questions(id,section_id,prompt,justification) values (449,21,'¿Cómo se relacionan los niveles de inversión total en GBM con la tasa de Smart Cash?','El esquema premia el mayor saldo total en GBM con una mejor tasa, escalando de Plus a Private. Es un incentivo a consolidar el patrimonio del cliente dentro de la plataforma.');
insert into questions(id,section_id,prompt,justification) values (450,21,'Para aumentar los rendimientos en Smart Cash, el cliente debe:','Como la tasa depende del nivel (inversión total en GBM), la forma de mejorarla es incrementar ese saldo total para alcanzar el siguiente escalón (Personal, Premium o Private).');
insert into questions(id,section_id,prompt,justification) values (451,21,'¿Qué ocurre si el cliente baja de nivel de inversión?','Hay un periodo de gracia de 30 días tras bajar de nivel: si en ese lapso el cliente recupera el saldo, conserva la tasa; de lo contrario, esta se ajusta al nuevo nivel.');
insert into questions(id,section_id,prompt,justification) values (452,21,'¿Cada cuánto se generan los rendimientos en Smart Cash?','El rendimiento se devenga a diario, pero su reflejo en la cuenta sigue el calendario de días hábiles, por lo que lo generado en fin de semana se acumula y aparece el siguiente día hábil.');
insert into questions(id,section_id,prompt,justification) values (453,21,'¿Cuál es el horario para retirar dinero de Smart Cash y qué implica?','El corte operativo es la 1:30 p.m. (hora CDMX) en días hábiles: las solicitudes antes de esa hora se procesan en minutos; las posteriores, al siguiente día hábil.');
insert into questions(id,section_id,prompt,justification) values (454,21,'¿Qué es la &quot;Regla de permanencia&quot; que aplica a Smart Cash?','La Regla de permanencia es regulatoria (no una comisión): como los recursos se invierten al instante en reportos a un día, el retiro de esos fondos debe esperar a que ese día se cumpla.');
insert into questions(id,section_id,prompt,justification) values (455,21,'Si un cliente deposita en Smart Cash hoy, ¿cuándo puede retirar ese dinero?','Por la Regla de permanencia, el dinero recién depositado queda invertido en reportos a un día; el momento del depósito respecto al corte de la 1:30 p.m. determina si la disponibilidad es al día hábil siguiente o a los dos días hábiles. Aun así, ese saldo sí puede usarse de inmediato para invertir en otras estrategias.');
insert into questions(id,section_id,prompt,justification) values (456,21,'¿A qué destinos puede transferir un cliente desde Smart Cash en la app de GBM?','El flujo de retiro en la app permite transferir a cuentas propias dentro de GBM, a cuentas bancarias del propio cliente o a terceros, verificando que el origen de la operación sea Smart Cash.');
insert into questions(id,section_id,prompt,justification) values (457,21,'Aplicación: ¿en qué situación es más adecuado recomendar Smart Cash a un cliente?','Smart Cash resuelve el &quot;costo del efectivo ocioso&quot; (Advisor&#x27;s Alpha, Sección 5): convierte el dinero que esperaría en una chequera de bajo rendimiento en un saldo que rinde a diario y se mantiene disponible. Es un componente de liquidez, no un motor de crecimiento de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (458,22,'¿Qué es Smart Cash Dólares?','Smart Cash Dólares da exposición a instrumentos de bajo riesgo denominados en dólares (vía GBMDOL) y, además, al movimiento del tipo de cambio peso-dólar, desde un depósito inicial accesible.');
insert into questions(id,section_id,prompt,justification) values (459,22,'¿Qué significa que Smart Cash Dólares sea una cuenta &quot;discrecional&quot;?','En una cuenta discrecional, la gestión operativa (adquisición y manejo del fondo) la realiza GBM por el cliente; &quot;discrecional&quot; se refiere al manejo del fondo, no a un uso libre de los recursos.');
insert into questions(id,section_id,prompt,justification) values (460,22,'¿Qué requisitos se necesitan para abrir Smart Cash Dólares?','Los dos requisitos son el cuestionario de apertura (idoneidad/perfil) y el depósito inicial mínimo de $100 MXN, lo que mantiene el producto accesible.');
insert into questions(id,section_id,prompt,justification) values (461,22,'¿En qué fondo invierte Smart Cash Dólares?','El vehículo subyacente es GBMDOL (bonos estadounidenses de bajo riesgo en dólares), lo que define tanto el perfil de bajo riesgo como la denominación en dólares del producto.');
insert into questions(id,section_id,prompt,justification) values (462,22,'¿Cuáles son las diferencias clave entre Smart Cash y Smart Cash Dólares?','Las diferencias abarcan comisión, referencia de tasa (Banxico vs. Fed), instrumento (CETES vs. GBMDOL), naturaleza de la tasa (fija vs. no fija) y, de manera central, la exposición al tipo de cambio en la versión en dólares.');
insert into questions(id,section_id,prompt,justification) values (463,22,'¿Qué comisión tiene Smart Cash Dólares?','El único cargo es el arancel de manejo del fondo (1.5% anual + IVA, prorrateado diariamente sobre el saldo). A diferencia de Smart Cash (sin comisiones), aquí sí hay un costo de gestión, aunque no por transacciones.');
insert into questions(id,section_id,prompt,justification) values (464,22,'La tasa de rendimiento de Smart Cash Dólares se caracteriza porque:','Al invertir en instrumentos en dólares, su rendimiento se ancla a la tasa libre de riesgo estadounidense (Fed) y no es fijo, a diferencia de la tasa fija referenciada a Banxico de Smart Cash.');
insert into questions(id,section_id,prompt,justification) values (465,22,'¿Cómo afecta el tipo de cambio a una inversión en Smart Cash Dólares?','El componente cambiario es la diferencia esencial: además del rendimiento en dólares, el resultado medido en pesos depende del movimiento del tipo de cambio, que puede beneficiar o perjudicar al inversionista.');
insert into questions(id,section_id,prompt,justification) values (466,22,'¿Qué tipo de cambio utiliza Smart Cash Dólares?','El uso del Valmer Spot 48 h (fuente regulada por la CNBV) da una referencia objetiva; el saldo mostrado usa el cierre del día previo para estabilidad, pero las operaciones aplican el tipo de cambio vigente, lo que explica posibles variaciones.');
insert into questions(id,section_id,prompt,justification) values (467,22,'¿Qué ocurre con los rendimientos de Smart Cash y Smart Cash Dólares?','En ambos productos la reinversión automática permite que el interés compuesto trabaje sobre el saldo creciente, sin que el cliente deba reinvertir manualmente.');
insert into questions(id,section_id,prompt,justification) values (468,22,'¿En cuánto tiempo llega un retiro de Smart Cash Dólares?','A diferencia de Smart Cash (minutos/siguiente día), Smart Cash Dólares requiere más tiempo porque hay que vender los títulos del fondo y liquidar; el corte de la 1:30 p.m. determina si son 2 o 3 días hábiles. Si hay una solicitud de retiro activa, debe completarse antes de procesar una nueva.');
insert into questions(id,section_id,prompt,justification) values (469,22,'¿Cómo funciona la mecánica de los retiros de Smart Cash Dólares?','El plazo de liquidación de un día hábil del fondo GBMDOL es lo que marca los tiempos del retiro: venta de títulos → liquidación → transferencia. Entender esta secuencia explica por qué el dinero no está disponible de inmediato.');
insert into questions(id,section_id,prompt,justification) values (470,22,'Aplicación: ¿para qué cliente es más adecuado Smart Cash Dólares frente a Smart Cash?','Smart Cash Dólares encaja con objetivos o coberturas en dólares y diversificación cambiaria, asumiendo el riesgo/oportunidad del tipo de cambio y un costo de gestión; para pura liquidez en pesos, sin costo y con disponibilidad casi inmediata, Smart Cash es la opción. El asesor elige según la moneda objetivo, el horizonte y la tolerancia del cliente.');
insert into questions(id,section_id,prompt,justification) values (471,23,'¿Qué es un PPR (Plan Personal para el Retiro)?','El PPR es un vehículo de ahorro/inversión para el retiro que complementa al AFORE y ofrece un incentivo fiscal (deducibilidad de aportaciones), enmarcado en el Art. 151 LISR visto en la Sección 9.');
insert into questions(id,section_id,prompt,justification) values (472,23,'¿Cuál es el monto inicial para abrir el PPR digital de GBM?','El monto inicial del PPR digital es de $10,000 MXN, superior al de productos de liquidez como Smart Cash ($100 MXN), acorde con su naturaleza de inversión de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (473,23,'¿Cómo funciona el PPR de GBM en cuanto a aportaciones y gestión?','Las aportaciones son flexibles (monto y momento a elección del cliente) y la gestión del portafolio (según perfil de riesgo y objetivo) la realiza GBM, con transparencia para consultarlo en la plataforma.');
insert into questions(id,section_id,prompt,justification) values (474,23,'¿Qué ocurre al retirar el PPR a los 65 años?','El retiro a los 65 años es el escenario &quot;natural&quot; del PPR: está exento de retención hasta el monto exento aplicable (ligado a la UMA, como vimos en la Sección 9), lo que premia mantener el ahorro hasta el retiro.');
insert into questions(id,section_id,prompt,justification) values (475,23,'¿Cuál es el beneficio fiscal del PPR?','La deducción de aportaciones está limitada por dos parámetros: 10% del ingreso anual y el equivalente a 5 UMAs anuales, conforme al Art. 151 LISR.');
insert into questions(id,section_id,prompt,justification) values (476,23,'¿Cómo se calcula el máximo deducible de las aportaciones al PPR?','El deducible es el <strong>menor</strong> entre el 10% del ingreso bruto anual estimado y las 5 UMAs anuales: para ingresos altos manda el tope de 5 UMAs, y para ingresos menores manda el 10%.');
insert into questions(id,section_id,prompt,justification) values (477,23,'¿Cuáles son requisitos para abrir el PPR digital de GBM?','El PPR requiere edad entre 18 y 64 años (para que tenga sentido el horizonte al retiro), el monto mínimo, ausencia de cotitulares y datos fiscales completos —indispensables para emitir la constancia deducible—.');
insert into questions(id,section_id,prompt,justification) values (478,23,'Entre los requisitos operativos para abrir el PPR digital, el cliente debe:','Dos condiciones operativas frecuentes son: contar con una Cuenta sin límite (quitar el límite toma 2 días hábiles) y que no exista ya un portafolio con el nombre &#x27;PPR&#x27;, para evitar conflictos al crear el plan.');
insert into questions(id,section_id,prompt,justification) values (479,23,'¿En qué invierte el PPR de GBM?','El PPR es un portafolio multifondo (GBMGUBL, GBMINT, GBMTRV, GMP+, GBMAA) que combina renta fija y variable y se pondera según el perfil del cliente, en línea con la lógica de asset allocation por objetivo.');
insert into questions(id,section_id,prompt,justification) values (480,23,'¿Se puede retirar del PPR antes de los 65 años?','El retiro anticipado es posible pero penalizado fiscalmente (retención del 20% como pago provisional de ISR), lo que desincentiva usar el PPR antes del retiro; actualmente no se gestiona desde la app.');
insert into questions(id,section_id,prompt,justification) values (481,23,'Si una persona tiene varios PPR, ¿puede deducir más?','El límite de deducción (10% del ingreso / 5 UMAs) aplica por contribuyente, no por cuenta: abrir varios PPR no incrementa el monto deducible total.');
insert into questions(id,section_id,prompt,justification) values (482,23,'¿Cuántos PPR digitales se pueden abrir en la app de GBM actualmente?','Actualmente la app permite abrir un único PPR digital; aun cuando en el futuro se permitan más, el beneficio fiscal permanecerá siendo único por persona.');
insert into questions(id,section_id,prompt,justification) values (483,23,'¿Cómo y cuándo obtiene el cliente la constancia fiscal (CFDI) de sus aportaciones al PPR?','La constancia (CFDI) que ampara la deducción se descarga directamente desde la app, en la sección de estados de cuenta y constancias del PPR; es el documento que respalda el beneficio fiscal ante el SAT.');
insert into questions(id,section_id,prompt,justification) values (484,23,'¿Cómo se integra el PPR con el resto del plan de retiro del cliente?','Conecta con la Sección 10: dado que la tasa de reemplazo del AFORE suele ser insuficiente, el PPR (ahorro voluntario con beneficio fiscal) es una pieza clave para complementar el retiro, no un sustituto del sistema obligatorio.');
insert into questions(id,section_id,prompt,justification) values (485,23,'Aplicación: ¿para qué cliente y con qué advertencia es más adecuado el PPR?','Integra el bloque: el PPR brilla para el ahorro de retiro de largo plazo con beneficio fiscal, siempre que el cliente no necesite esos recursos antes de los 65. El asesor agrega valor calibrando la aportación al máximo deducible, asegurando los datos fiscales y reforzando la disciplina de permanencia.');
insert into questions(id,section_id,prompt,justification) values (486,24,'¿Qué son los Invesco Dynamic ETF Portfolios?','Son portafolios modelo (cuentas gestionadas) que acceden a clases de activo vía ETFs eficientes en costo, con diversificación amplia y varios niveles de riesgo para distintos perfiles de inversionista.');
insert into questions(id,section_id,prompt,justification) values (487,24,'En la nomenclatura &quot;X/Y&quot; de estos portafolios (p. ej., 60/40), los números representan:','El primer número es la exposición a renta variable y el segundo a renta fija. Así, 100/0 es 100% acciones; 0/100 es 100% renta fija; y los intermedios escalan el balance entre ambos.');
insert into questions(id,section_id,prompt,justification) values (488,24,'¿Qué significa el componente &quot;Dynamic&quot; (dinámico) de la estrategia?','&quot;Dynamic&quot; se refiere a la mezcla de lo estratégico (la ancla de largo plazo por clase de activo) con lo táctico (desviaciones de corto plazo según las condiciones), buscando adaptarse a través del ciclo completo.');
insert into questions(id,section_id,prompt,justification) values (489,24,'¿Cuál es el objetivo de inversión de estos portafolios?','Cada portafolio opera dentro de un nivel de riesgo definido (por su mezcla acciones/renta fija) y busca optimizar el rendimiento ajustado por riesgo, no el rendimiento absoluto sin restricciones.');
insert into questions(id,section_id,prompt,justification) values (490,24,'¿Cómo logran estos portafolios su diversificación y bajo costo?','Al construirse con ETFs (vehículos diversificados y baratos), el portafolio obtiene exposición amplia a múltiples clases de activo y factores con costos contenidos, en línea con la filosofía indexada de bajo costo.');
insert into questions(id,section_id,prompt,justification) values (491,24,'La gama ofrece varios niveles de riesgo. ¿Cómo se ordenan del más agresivo al más conservador?','La &quot;escalera&quot; de riesgo va de 100% acciones (100/0, el más agresivo) a 100% renta fija (0/100, el más conservador). La gama permite al asesor &quot;marcar&quot; el nivel de riesgo adecuado al cliente.');
insert into questions(id,section_id,prompt,justification) values (492,24,'El Invesco Dynamic UCITS ETF 100/0 Portfolio es más adecuado para:','Al ser 100% renta variable global, el 100/0 ofrece el mayor potencial de crecimiento y la mayor volatilidad de la gama; es apropiado para perfiles agresivos con horizonte largo y capacidad de tolerar caídas.');
insert into questions(id,section_id,prompt,justification) values (493,24,'El Invesco Dynamic UCITS ETF 0/100 Portfolio se caracteriza por:','El 0/100 es el extremo conservador (toda renta fija): menor volatilidad y menor rendimiento esperado que las variedades con acciones, para clientes que priorizan preservación y estabilidad (sin que ello implique ausencia de riesgo de tasa/crédito).');
insert into questions(id,section_id,prompt,justification) values (494,24,'¿Por qué es relevante que estos portafolios usen ETFs UCITS para un inversionista mexicano (no estadounidense)?','Para un inversionista no estadounidense, los ETFs UCITS (domiciliados típicamente en Europa, p. ej., Irlanda) suelen ofrecer ventajas fiscales y un marco regulatorio robusto frente a los ETFs estadounidenses (enlaza con la Sección 12 sobre UCITS).');
insert into questions(id,section_id,prompt,justification) values (495,24,'Aplicación: ¿cómo elige un asesor la variedad adecuada de la gama para un cliente?','La gama está diseñada precisamente para &quot;marcar&quot; el nivel de riesgo: el asesor selecciona la variedad cuya proporción acciones/renta fija corresponda al perfil de riesgo, los objetivos y el horizonte del cliente, dentro de una solución diversificada, de bajo costo y gestionada dinámicamente.');
insert into questions(id,section_id,prompt,justification) values (496,25,'¿Qué es la Cartera Modelo Siegel-WisdomTree Global Equity (UCITS)?','Es una cartera modelo de renta variable global (multi-ETF UCITS) desarrollada con Jeremy Siegel (autor de <em>Stocks for the Long Run</em>), pensada para cuestionar el 60/40 tradicional y mejorar los perfiles de ingreso y longevidad —en sintonía con el debate de lifecycle investing de la Sección 14—.');
insert into questions(id,section_id,prompt,justification) values (497,25,'La filosofía de inversión de WisdomTree (&quot;Modern Alpha®&quot;) sostiene que:','WisdomTree es pionero de la inversión por factores/ponderación fundamental: &quot;Modern Alpha&quot; busca un punto medio entre el &quot;Legado Alpha&quot; (activo, costoso, subjetivo, con riesgo de hombre clave) y el &quot;Legado Beta&quot; (indexación por capitalización), con un proceso transparente, sistemático y de bajo costo. Conecta con factor investing (Sección 13) y el debate activa vs. pasiva (Secciones 18 y 20).');
insert into questions(id,section_id,prompt,justification) values (498,25,'¿Qué significa que la cartera tenga &quot;arquitectura abierta&quot;?','La arquitectura abierta permite elegir los mejores vehículos disponibles, sean o no de la propia casa, lo que alinea al gestor con el resultado del cliente (mismo principio del &quot;beauty contest&quot; de las notas estructuradas, Sección 16, y la oferta de Invesco de la Sección 24).');
insert into questions(id,section_id,prompt,justification) values (499,25,'¿Cómo está compuesta y caracterizada esta cartera modelo?','La cartera es de renta variable global con inclinaciones a calidad/dividendos/ingreso (a través de ETFs como Quality Dividend Growth, Equity Income, etc.), diversificada por geografía y capitalización, y con un costo promedio contenido —coherente con la filosofía de bajo costo y ponderación fundamental—.');
insert into questions(id,section_id,prompt,justification) values (500,25,'Síntesis (capstone). ¿Cómo usa un asesor esta cartera modelo dentro de un plan?','Integra el bloque y todo el banco: es una solución de renta variable global, basada en factores y de bajo costo, en formato UCITS (idóneo para el inversionista mexicano, ver Secciones 12 y 24). El asesor la usa como el &quot;cajón&quot; de acciones de un perfil adecuado, con honestidad sobre el riesgo y el desempeño relativo (que puede quedar por encima o por debajo del benchmark), y dimensionada a la tolerancia y los objetivos del cliente —el cierre natural de un banco que enfatiza diversificación, costo, evidencia y juicio aplicado—.');
insert into questions(id,section_id,prompt,justification) values (501,26,'¿Qué es y qué objetivo tiene la estrategia Euro Yield?','Euro Yield da exposición en euros vía bonos de la Eurozona, pensada como cobertura/diversificación frente al tipo de cambio, con un perfil conservador (baja volatilidad, alta calidad, corto plazo). Es la contraparte en euros de Dollar Yield (Sección 19).');
insert into questions(id,section_id,prompt,justification) values (502,26,'¿Cómo está compuesta la cartera de Euro Yield?','La cartera se concentra en deuda gubernamental europea de corto plazo más corporativos europeos de grado de inversión, lo que explica su baja volatilidad, su corta duración (~8.3 meses) y su carácter conservador dentro de la renta fija en euros.');
insert into questions(id,section_id,prompt,justification) values (503,26,'Aplicación: ¿para qué cliente es más adecuada Euro Yield?','Euro Yield encaja con objetivos o coberturas en euros y diversificación cambiaria, con un perfil conservador. El asesor debe explicar que el resultado en pesos depende del tipo de cambio EUR/MXN y que la renta fija conlleva riesgo de tasa y crédito (Sección 19), eligiendo la divisa según la meta y el perfil del cliente —junto con Dollar Yield/Smart Cash Dólares para exposición en dólares—.');
insert into questions(id,section_id,prompt,justification) values (504,27,'¿Por qué una cartera de bonos del Tesoro de EUA (que rinde ~4% en USD), cubierta a pesos, termina rindiendo aproximadamente como los CETES (~8-10%) y no ~4%?','Es el resultado central de la CIP: cubrir un activo en dólares de vuelta a una moneda de mayor tasa (el peso) incorpora el diferencial de tasas a través del forward, llevando el rendimiento cubierto a ≈ la tasa doméstica (CETES). No se &quot;gana&quot; el rendimiento del Tesoro: se transforma en rendimiento en pesos.');
insert into questions(id,section_id,prompt,justification) values (505,27,'La condición de paridad de tasas de interés cubierta se expresa como (1 + r_peso) = (1 + r_dólar) × (Forward / Spot). ¿Qué implica para el hedge?','Los puntos forward reflejan el diferencial de tasas. Al cubrir, el inversionista no captura ni la depreciación ni la apreciación del peso: fija ≈ CETES. El &quot;costo&quot; del hedge es renunciar a la posible ganancia cambiaria (a cambio de eliminar también el riesgo cambiario).');
insert into questions(id,section_id,prompt,justification) values (506,27,'En la descomposición del rendimiento de la estrategia, ¿por qué R_IPH ≈ r(T,MXN)?','Algebraicamente: r(T,USD) + r_FX − r_FX + r(T,MXN) − r(T,USD) = r(T,MXN). El hedge anula la exposición cambiaria (r_FX) y &quot;intercambia&quot; la tasa en dólares por la tasa en pesos; de ahí que el resultado se aproxime a CETES.');
insert into questions(id,section_id,prompt,justification) values (507,27,'¿Qué fuerza de mercado garantiza que la paridad de tasas cubierta se cumpla en la práctica?','La posibilidad de ganancia sin riesgo (p. ej., +1.87% sobre el capital si el forward estuviera a $19.80 en lugar de $19.3955) atrae arbitrajistas cuya operación corrige la distorsión. Este mecanismo autocorrectivo es el que mantiene la CIP y, con ella, que el rendimiento de la IPH ≈ CETES.');
insert into questions(id,section_id,prompt,justification) values (508,27,'Síntesis (capstone). ¿Cuál es la propuesta de valor real de la International Peso-Hedged y para quién es adecuada?','Integra el bloque: la IPH no es una apuesta cambiaria ni un &quot;yield pickup&quot; en dólares; &quot;importa&quot; las condiciones del país donde se invierte (calidad crediticia, diversificación) pero se paga el &quot;precio&quot; del riesgo del país donde se vive (el rendimiento queda ≈ CETES). Su valor está en la calidad AAA, la descorrelación con México, la eficiencia fiscal vía UCITS y la operación profesional del hedge —no en superar a los CETES—. El asesor elige corto vs. mediano plazo según el perfil del cliente.');
insert into questions(id,section_id,prompt,justification) values (509,28,'¿Cómo se describe mejor la planeación financiera?','La planeación financiera es un proceso (no un producto): se define la relación y el alcance, se recopilan datos, se analiza, se recomienda, se implementa y se monitorea de forma recurrente. Coincide con la lógica de Invierte con Propósito.');
insert into questions(id,section_id,prompt,justification) values (510,28,'¿Cuál es el primer paso del proceso de planeación financiera?','Antes de recopilar datos o recomendar, se acuerda el alcance del trabajo y las responsabilidades de cada parte. Esto alinea expectativas y delimita el servicio.');
insert into questions(id,section_id,prompt,justification) values (511,28,'La recopilación de datos del cliente debe incluir:','Un buen plan requiere los números y también lo cualitativo: qué quiere lograr el cliente, cuándo, y cómo se siente frente al riesgo. Lo cualitativo suele ser tan determinante como lo cuantitativo.');
insert into questions(id,section_id,prompt,justification) values (512,28,'En el orden correcto del proceso, el análisis de la situación del cliente:','El flujo lógico es diagnosticar (analizar) → recomendar → implementar → monitorear. Recomendar sin analizar primero llevaría a soluciones desalineadas con la situación real del cliente.');
insert into questions(id,section_id,prompt,justification) values (513,28,'¿Cuándo debe revisarse un plan financiero?','Las circunstancias del cliente y del mercado cambian, así que el monitoreo y la revisión periódica (y tras eventos de vida) son parte esencial del proceso. Un plan es un documento vivo.');
insert into questions(id,section_id,prompt,justification) values (514,28,'El balance personal (estado de situación patrimonial) se calcula como:','El balance personal es una &quot;foto&quot; a una fecha: activos (lo que se tiene) menos pasivos (lo que se debe) = patrimonio neto. Mide la riqueza acumulada, no el flujo.');
insert into questions(id,section_id,prompt,justification) values (515,28,'Un cliente tiene activos por $3,800,000 (casa $2,500,000; auto $300,000; inversiones $800,000; efectivo $200,000) y pasivos por $1,600,000 (hipoteca $1,400,000; crédito automotriz $150,000; tarjetas $50,000). ¿Cuál es su patrimonio neto?','Patrimonio neto = activos − pasivos = $3,800,000 − $1,600,000 = <strong>$2,200,000</strong>. Es el indicador central del balance personal.');
insert into questions(id,section_id,prompt,justification) values (516,28,'El estado de flujo de efectivo personal mide:','A diferencia del balance (una foto), el flujo de efectivo es una &quot;película&quot; del periodo: cuánto entra y cuánto sale. El superávit es la materia prima del ahorro y la inversión.');
insert into questions(id,section_id,prompt,justification) values (517,28,'Si un cliente tiene ingresos mensuales por $60,000 y gastos por $45,000, ¿cuál es su superávit mensual disponible para ahorrar?','Superávit = ingresos − gastos = $60,000 − $45,000 = <strong>$15,000</strong>. Ese excedente es lo que puede destinarse a metas, aplicando &quot;págate a ti primero&quot;.');
insert into questions(id,section_id,prompt,justification) values (518,28,'La razón de liquidez (meses de cobertura) se interpreta como:','La razón de liquidez vincula el fondo de emergencia con los gastos: activos líquidos / gastos mensuales = meses de colchón. Se busca cubrir de 3 a 6 meses.');
insert into questions(id,section_id,prompt,justification) values (519,28,'Si un cliente ahorra $9,000 de un ingreso mensual de $45,000, ¿cuál es su tasa de ahorro?','Tasa de ahorro = ahorro / ingreso = $9,000 / $45,000 = <strong>20%</strong>. Es un indicador clave de la salud financiera y del avance hacia las metas.');
insert into questions(id,section_id,prompt,justification) values (520,28,'Respecto a la &quot;buena&quot; y la &quot;mala&quot; deuda, la recomendación general de planeación es:','Pagar una tarjeta al 40% es un &quot;rendimiento garantizado&quot; del 40%, muy superior al esperado de una cartera. Por eso la deuda cara se liquida antes de invertir; la deuda barata y productiva (p. ej., hipoteca) puede convivir con la inversión.');
insert into questions(id,section_id,prompt,justification) values (521,28,'Si los pagos mensuales de deuda de un cliente suman $18,000 y su ingreso bruto mensual es de $60,000, ¿cuál es su razón deuda-ingreso (DTI)?','DTI = pagos de deuda / ingreso bruto = $18,000 / $60,000 = <strong>30%</strong>. Es una medida de carga de deuda; niveles altos comprometen la capacidad de ahorro y de obtener crédito.');
insert into questions(id,section_id,prompt,justification) values (522,28,'La diferencia entre el método &quot;avalancha&quot; y el de &quot;bola de nieve&quot; para pagar deudas es:','Matemáticamente, la avalancha (mayor tasa primero) minimiza el interés; conductualmente, la bola de nieve (menor saldo primero) puede sostener mejor la motivación. El asesor elige según el perfil del cliente.');
insert into questions(id,section_id,prompt,justification) values (523,28,'¿Cuál es la jerarquía de prioridades financieras generalmente recomendada?','Primero se asegura el colchón de liquidez y se elimina la deuda cara (rendimiento garantizado), luego se aprovecha el ahorro fiscalmente eficiente para el retiro y, después, las demás metas. Es la secuencia que más valor crea con menos riesgo.');
insert into questions(id,section_id,prompt,justification) values (524,28,'El principio del valor del dinero en el tiempo establece que:','El dinero presente tiene un costo de oportunidad: invertido, crece. Por eso descontamos los flujos futuros (valor presente) y capitalizamos los actuales (valor futuro). Es la base de toda la planeación cuantitativa.');
insert into questions(id,section_id,prompt,justification) values (525,28,'¿Cuál será el valor futuro de $100,000 invertidos durante 10 años a una tasa anual del 8%?','VF = VP × (1 + r)ⁿ = 100,000 × 1.08<sup>10</sup> ≈ 100,000 × 2.1589 = <strong>$215,892</strong>. El interés compuesto, no el simple ($180,000), explica la diferencia. <em>(Tolerancia ±$500.)</em>');
insert into questions(id,section_id,prompt,justification) values (526,28,'¿Cuánto debe invertirse hoy para tener $500,000 en 10 años, si la tasa anual es del 7%?','VP = VF / (1 + r)ⁿ = 500,000 / 1.07<sup>10</sup> ≈ 500,000 / 1.9672 = <strong>$254,174</strong>. Es el valor presente: cuánto vale hoy una meta futura descontada a la tasa esperada. <em>(Tolerancia ±$1,000.)</em>');
insert into questions(id,section_id,prompt,justification) values (527,28,'Usando la &quot;regla del 72&quot;, ¿en cuántos años se duplica aproximadamente una inversión que rinde 8% anual?','La regla del 72 aproxima el tiempo de duplicación dividiendo 72 entre la tasa: 72 / 8 = <strong>9 años</strong>. Es una herramienta mental rápida derivada del interés compuesto.');
insert into questions(id,section_id,prompt,justification) values (528,28,'Un cliente ahorra $50,000 al final de cada año durante 10 años a una tasa del 6% anual. ¿Cuánto acumulará?','VF de una anualidad = PMT × [((1 + r)ⁿ − 1) / r] = 50,000 × [(1.06<sup>10</sup> − 1) / 0.06] ≈ 50,000 × 13.181 = <strong>$659,039</strong>. Lo aportado ($500,000) más los intereses compuestos. <em>(Tolerancia ±$2,000.)</em>');
insert into questions(id,section_id,prompt,justification) values (529,28,'¿Cuánto debe ahorrar un cliente al final de cada año para acumular $2,000,000 en 15 años, a una tasa del 7% anual?','PMT = VF / [((1 + r)ⁿ − 1) / r] = 2,000,000 / [(1.07<sup>15</sup> − 1) / 0.07] ≈ 2,000,000 / 25.129 = <strong>$79,589 al año</strong>. Despejar el pago de la fórmula de anualidad es la base de la planeación de metas. <em>(Tolerancia ±$1,000.)</em>');
insert into questions(id,section_id,prompt,justification) values (530,28,'La diferencia entre interés simple y compuesto es:','El interés compuesto genera &quot;interés sobre interés&quot;, lo que acelera el crecimiento frente al simple, sobre todo en horizontes largos. Capitalizar con mayor frecuencia (mensual vs. anual) eleva la tasa efectiva.');
insert into questions(id,section_id,prompt,justification) values (531,28,'Si una inversión rinde 9% nominal y la inflación es de 4%, ¿cuál es el rendimiento real (fórmula de Fisher)?','Rendimiento real = [(1 + nominal) / (1 + inflación)] − 1 = (1.09 / 1.04) − 1 ≈ <strong>4.81%</strong>. La resta simple (9% − 4% = 5%) es solo una aproximación; la fórmula de Fisher es la correcta. <em>(Tolerancia ±0.2 pp.)</em>');
insert into questions(id,section_id,prompt,justification) values (532,28,'Una colegiatura cuesta hoy $400,000. Si la inflación educativa es del 6% anual, ¿cuánto costará en 10 años?','Costo futuro = costo actual × (1 + inflación)ⁿ = 400,000 × 1.06<sup>10</sup> ≈ 400,000 × 1.7908 = <strong>$716,339</strong>. Planear una meta exige primero inflactarla a su valor futuro. <em>(Tolerancia ±$3,000.)</em>');
insert into questions(id,section_id,prompt,justification) values (533,28,'¿Por qué es tan importante empezar a invertir temprano?','En el interés compuesto, los años importan más que el monto. Empezar temprano permite que los rendimientos generen, a su vez, rendimientos durante más tiempo, superando a quien empieza tarde aunque este aporte más.');
insert into questions(id,section_id,prompt,justification) values (534,28,'La &quot;tasa de reemplazo&quot; en la planeación del retiro se refiere a:','La tasa de reemplazo dimensiona cuánto ingreso hará falta en el retiro respecto al ingreso laboral. Como el AFORE suele ofrecer una tasa baja, el ahorro voluntario (PPR) cierra la diferencia (Secciones 10 y 23).');
insert into questions(id,section_id,prompt,justification) values (535,28,'Si un cliente desea un ingreso anual de $720,000 en el retiro y se usa la regla del 4% (retiro sostenible), ¿qué capital necesita acumular?','Capital = gasto anual / tasa de retiro = $720,000 / 0.04 = <strong>$18,000,000</strong> (equivalente a 25 veces el gasto anual). La regla del 4% es una guía de planeación, no una garantía, y debe ajustarse por horizonte y supuestos. <em>(Tolerancia ±$100,000.)</em>');
insert into questions(id,section_id,prompt,justification) values (536,28,'Para reunir los ≈ $716,000 de la colegiatura futura en 10 años, invirtiendo al 7% anual, ¿cuánto debe ahorrarse al año (aproximadamente)?','PMT = meta / [((1 + r)ⁿ − 1) / r] = 716,000 / [(1.07<sup>10</sup> − 1) / 0.07] ≈ 716,000 / 13.816 = <strong>$51,823 al año</strong>. Planear una meta es un proceso de dos pasos: inflactar el costo y luego calcular el ahorro requerido. <em>(Tolerancia ±$1,500.)</em>');
insert into questions(id,section_id,prompt,justification) values (537,28,'El &quot;análisis de brecha&quot; (gap analysis) en la planeación del retiro consiste en:','El gap analysis cuantifica cuánto falta: capital necesario − capital proyectado = brecha. Esa brecha define cuánto debe ahorrar el cliente (vía PPR y otras metas) para alcanzar su objetivo de retiro.');
insert into questions(id,section_id,prompt,justification) values (538,28,'El rebalanceo de una cartera consiste en:','El rebalanceo mantiene el riesgo alineado con el plan y, de forma disciplinada, induce a &quot;comprar barato y vender caro&quot;. Puede hacerse por calendario (p. ej., anual) o por umbral (cuando una clase se desvía más de cierto porcentaje). Es una fuente de valor del Advisor&#x27;s Alpha (Sección 5).');
insert into questions(id,section_id,prompt,justification) values (539,29,'La idea central de la inversión por objetivos (goals-based investing) es que:','Desde Bernoulli (1738) —y reforzado por Shiller— se reconoce que valoramos lo que el dinero nos permite hacer, no su monto abstracto. Es la premisa de Invierte con Propósito: primero las metas, luego el portafolio.');
insert into questions(id,section_id,prompt,justification) values (540,29,'La paradoja de Friedman-Savage (1948) —que la misma persona compre seguros y billetes de lotería— se explica porque:','La curva &quot;ondulada&quot; anticipa la lógica por capas: protección abajo, aspiración arriba. La cuenta mental (mental accounting) la resuelve de forma natural al asignar distintas tolerancias al riesgo a distintos objetivos.');
insert into questions(id,section_id,prompt,justification) values (541,29,'En la teoría por objetivos, el término &quot;mental accounting&quot; (cuentas mentales) de Thaler tiene dos lecturas. ¿Cuál corresponde a la base de Invierte con Propósito?','Hay un mental accounting que es sesgo (no tratar el dinero como fungible) y otro que es racional (dedicar la riqueza a objetivos con riesgos distintos). La teoría por objetivos —y los cajones de GBM— se basan en el segundo, que Brunel (2006) y Das et al. (2010) mostraron que no es irracional ni ineficiente.');
insert into questions(id,section_id,prompt,justification) values (542,29,'El aporte central de la Behavioral Portfolio Theory (Shefrin-Statman, 2000) es redefinir el riesgo como:','Frente al &quot;riesgo = varianza&quot; de Markowitz, la BPT define el riesgo como la probabilidad de fallar el umbral de la meta. Esta es exactamente la noción de riesgo que usa Invierte con Propósito: el riesgo es no alcanzar el objetivo de cada cajón.');
insert into questions(id,section_id,prompt,justification) values (543,29,'Según la BPT, los portafolios óptimos de los inversionistas se asemejan a:','Shefrin-Statman muestran que los portafolios óptimos son combinaciones de &quot;bonos y billetes de lotería&quot; (consistente con Friedman-Savage), organizadas como pirámides por capas. Es el reflejo teórico de los cajones: liquidez/seguridad abajo, crecimiento/aspiración arriba.');
insert into questions(id,section_id,prompt,justification) values (544,29,'La BPT presenta dos versiones, BPT-SA y BPT-MA. ¿Cuál describe mejor cómo invierten las personas reales y la lógica de los cajones?','La versión de múltiples cuentas (BPT-MA) corresponde a las &quot;pirámides por capas&quot; y a cómo realmente las personas dividen su dinero por objetivos. Es la formalización académica de los cajones de Invierte con Propósito.');
insert into questions(id,section_id,prompt,justification) values (545,29,'¿Por qué un portafolio construido según la BPT puede parecer &quot;no diversificado&quot; frente a la teoría de Markowitz (MPT)?','Al tratar cada capa/meta de forma aislada (sin considerar las covarianzas entre cajones), el resultado difiere de la cartera única óptima de la MPT. No es un error: es la consecuencia de organizar la inversión por objetivos.');
insert into questions(id,section_id,prompt,justification) values (546,29,'La BPT se apoya en la teoría SP/A de Lopes (1987) y en el criterio safety-first de Roy (1952). ¿Qué capturan estas ideas?','SP/A (Security, Potential, Aspiration) y el safety-first de Roy incorporan las emociones de miedo y esperanza y la prioridad de &quot;no arruinarse&quot; antes que &quot;maximizar&quot;. Es la dimensión conductual que el asesor gestiona meta por meta (enlaza con la Sección 4).');
insert into questions(id,section_id,prompt,justification) values (547,29,'Das, Markowitz, Scheid y Statman (2010) reconciliaron la BPT con la teoría de Markowitz al mostrar que:','Este resultado es clave para Invierte con Propósito: legitima académicamente el enfoque por cajones. El cliente declara la probabilidad máxima de fallo que tolera para cada meta, y esa cifra se traduce en una optimización rigurosa por cuenta, sin sacrificar eficiencia.');
insert into questions(id,section_id,prompt,justification) values (548,29,'Síntesis (capstone). ¿Cómo fundamenta la teoría por objetivos a la metodología Invierte con Propósito?','Integra el bloque y toda la metodología: Invierte con Propósito no es una simplificación comercial, sino la aplicación de la inversión por objetivos con sólido respaldo académico (Bernoulli → Friedman-Savage → Thaler → Shefrin-Statman → Das et al.). El asesor agrega valor definiendo metas, asignando cada cajón a su objetivo y gestionando la conducta meta por meta.');
insert into questions(id,section_id,prompt,justification) values (549,1,'Según GBM Advisory, invertir se trata principalmente de:','La presentación enfatiza que "invertir no se trata solo de productos", sino de contar con un plan que acompañe al inversionista a lo largo del tiempo; invertir sin plan es dejar el futuro al azar.');
insert into questions(id,section_id,prompt,justification) values (550,1,'GBM Advisory ofrece dos formas de acompañamiento. ¿Cuáles son?','Ambas soluciones parten de un plan; la diferencia es el grado de profundidad del acompañamiento.');
insert into questions(id,section_id,prompt,justification) values (551,1,'La diferencia esencial entre Portafolios Recomendados y Gestión Patrimonial 360 es:','La presentación aclara que "ambas opciones parten de un plan. La diferencia es el grado de profundidad".');
insert into questions(id,section_id,prompt,justification) values (552,1,'"Portafolios Recomendados" está diseñado idealmente para:','Es la solución simple, estructurada y profesional para invertir con orden, sin requerir una gestión patrimonial integral.');
insert into questions(id,section_id,prompt,justification) values (553,1,'Gestión Patrimonial 360 es ideal para:','GP360 conecta todas las decisiones patrimoniales en una sola estrategia coherente, con diagnóstico continuo.');
insert into questions(id,section_id,prompt,justification) values (554,1,'¿Cuál de los siguientes NO es un componente de Gestión Patrimonial 360?','GP360 integra plan financiero, ahorro, asignación de activos, selección de instrumentos, optimización fiscal, decisión de moneda, custodia internacional, coaching conductual y servicio de excelencia. Ninguna estrategia seria garantiza rendimientos.');
insert into questions(id,section_id,prompt,justification) values (555,1,'El nivel de asesoría "Digital" está disponible a partir de:','El nivel Digital permite dar el primer paso con estructura y autonomía desde $100 MXN, con herramientas 100% digitales.');
insert into questions(id,section_id,prompt,justification) values (556,1,'Relaciona el nivel de asesoría con su monto de acceso. ¿Cuál es correcta?','Los umbrales son Digital $100, Personal $300,000, Premium $2,000,000 y Private $20,000,000 MXN.');
insert into questions(id,section_id,prompt,justification) values (557,1,'¿A partir de qué nivel de asesoría se ofrece acceso a cuentas de inversión en EE. UU. en dólares?','Personal, Premium y Private mencionan acceso a cuentas en EE. UU. en dólares; el nivel Digital no lo incluye.');
insert into questions(id,section_id,prompt,justification) values (558,1,'¿Qué distingue al nivel "Private" de los demás?','Private (desde $20,000,000 MXN) suma eventos privados y productos exclusivos al acompañamiento 1:1.');
insert into questions(id,section_id,prompt,justification) values (559,2,'¿Cómo funcionan los Portafolios Recomendados?','El flujo es perfilar, construir un portafolio optimizado y dar seguimiento con rebalanceo automático en el tiempo.');
insert into questions(id,section_id,prompt,justification) values (560,2,'En el ejemplo de GP360, ¿qué instrumento ilustra cada portafolio?','La presentación usa el índice MSCI ACWI para acciones, el GBM Global Market Portfolio para la parte balanceada y CETES 28 días para la reserva.');
insert into questions(id,section_id,prompt,justification) values (561,2,'El perfilamiento del inversionista define principalmente:','A partir del perfilamiento (horizonte, tolerancia al riesgo y objetivos) se construye el portafolio a la medida.');
insert into questions(id,section_id,prompt,justification) values (562,2,'¿Cuál es la función del rebalanceo automático?','El rebalanceo devuelve las ponderaciones al objetivo definido por el perfil, sin intentar adivinar el mercado.');
insert into questions(id,section_id,prompt,justification) values (563,6,'En Invierte con Propósito, ¿cuál es el rol del portafolio de "Alto Crecimiento"?','Se enfoca en el crecimiento de empresas en el tiempo, aceptando volatilidad de corto plazo a cambio de mayor potencial de retorno.');
insert into questions(id,section_id,prompt,justification) values (564,6,'¿Cuál es el propósito del portafolio "Fondo de Emergencia"?','Da tranquilidad y estabilidad para que el resto del plan crezca sin interrupciones.');
insert into questions(id,section_id,prompt,justification) values (565,6,'La "Diversificación Global" busca:','Equilibra riesgo y retorno mientras se construye patrimonio de forma consistente.');
insert into questions(id,section_id,prompt,justification) values (566,6,'La estructura de tres portafolios (emergencia, diversificación, crecimiento) refleja el principio de:','Cada portafolio cumple una función distinta (liquidez, equilibrio y crecimiento), coherente con una inversión orientada a objetivos.');
insert into questions(id,section_id,prompt,justification) values (567,28,'La metodología "Págate a ti primero" consiste en:','Convierte el ahorro en una prioridad automática; repetido por años, transforma la vida financiera.');
insert into questions(id,section_id,prompt,justification) values (568,28,'La idea "ahorrar es lineal, invertir es exponencial" se explica principalmente por:','Ahorrar acumula de forma lineal; invertir con interés compuesto hace que cada peso genere rendimientos sobre rendimientos, creciendo de forma exponencial.');
insert into questions(id,section_id,prompt,justification) values (569,28,'Según el ejemplo ilustrativo (invertir $100 al día), la diferencia entre ahorrar e invertir:','En el ejemplo, a 35 años la inversión (~$10.4 M) supera ampliamente al simple ahorro (~$1.28 M); la brecha se amplía con el horizonte.');
insert into questions(id,section_id,prompt,justification) values (570,28,'En "invertir una vez vs. con constancia" (ambos al 10% anual), ¿por qué la Persona B termina con más patrimonio?','Ambos rinden 10% anual; la ventaja de B proviene de las aportaciones periódicas ($10,000/mes) capitalizadas durante 30 años.');
insert into questions(id,section_id,prompt,justification) values (571,28,'Según la presentación, la clave para construir riqueza está en:','La constancia y el tiempo en el mercado son los principales motores del resultado de largo plazo.');
insert into questions(id,section_id,prompt,justification) values (572,28,'El dato citado sobre el S&amp;P 500 indica un rendimiento promedio anual cercano a 10.13% desde:','La presentación usa como referencia el promedio anual de ~10.13% del S&amp;P 500 desde 1957 para ilustrar el rendimiento compuesto.');
insert into questions(id,section_id,prompt,justification) values (573,5,'Según el estudio de Vanguard citado ("Putting a value on your value: Quantifying Advisor''s Alpha"), la asesoría puede aportar hasta:','La presentación cita que contar con asesoría puede aportar hasta ~3% adicional anual, como ejemplo ilustrativo (no garantizado).');
insert into questions(id,section_id,prompt,justification) values (574,5,'¿Cuál de las siguientes es una palanca de "disciplina y comportamiento" del valor de la asesoría?','El valor se agrupa en estructura/estrategia, disciplina/comportamiento y coordinación/optimización; mantenerse invertido y evitar impulsos corresponde a la disciplina conductual.');
insert into questions(id,section_id,prompt,justification) values (575,5,'La "ubicación eficiente de activos" (asset location) se refiere a:','Es una palanca de coordinación/optimización: alinear la ubicación de los activos con la situación fiscal para mejorar el rendimiento neto.');
insert into questions(id,section_id,prompt,justification) values (576,4,'La frase de Warren Buffett citada —"el mercado transfiere dinero de los impacientes a los pacientes"— ilustra:','La cita refuerza que la disciplina y la permanencia superan al <em>timing</em>; los impacientes tienden a transferir valor a los pacientes.');
insert into questions(id,section_id,prompt,justification) values (577,4,'El "coaching conductual" dentro de Gestión Patrimonial 360 busca:','Es el acompañamiento que ayuda a sostener el plan cuando las emociones tienden a desviar las decisiones.');
insert into questions(id,section_id,prompt,justification) values (578,4,'Según la presentación, los principales motores del resultado de largo plazo son:','La estrategia se enfoca en hacer simple, disciplinado y eficiente el proceso de invertir con constancia a lo largo del tiempo.');
insert into questions(id,section_id,prompt,justification) values (579,9,'En el "blindaje del plan", ¿cuál es el papel del seguro de vida?','El seguro de vida no busca rendimiento; busca que el plan siga en pie y las metas se cumplan pase lo que pase.');
insert into questions(id,section_id,prompt,justification) values (580,9,'"Proteger el plan es parte del plan" porque:','La protección financiera resguarda el plan ante imprevistos, de modo que los objetivos importantes se cumplan incluso en escenarios adversos.');
insert into questions(id,section_id,prompt,justification) values (581,7,'En Gestión Patrimonial 360, ¿con qué comienza el acompañamiento integral?','GP360 parte de un diagnóstico continuo, sobre el cual se construye y actualiza el plan financiero integral —análogo a un diagnóstico médico antes del tratamiento.');
insert into questions(id,section_id,prompt,justification) values (582,3,'El "problema de la hipótesis conjunta" en las pruebas de eficiencia implica que:','En el marco de Fama, cualquier prima persistente puede leerse como compensación por riesgo (un factor no identificado) o como ineficiencia; el test conjunto impide atribuir el hallazgo solo a la (in)eficiencia.');
insert into questions(id,section_id,prompt,justification) values (583,3,'El "enigma central" que unifica a value y momentum es que:','La clave del enigma es la coexistencia de continuación de corto plazo y reversión de largo plazo: "un mismo eje temporal, dos signos".');
insert into questions(id,section_id,prompt,justification) values (584,3,'En la defensa <em>racional</em>, ¿cuál es la interpretación de la prima de value como compensación por riesgo?','La lectura racional de value combina riesgo de <em>distress</em> (FF 1996), teoría q/basada en inversión (Zhang) y covarianza con el ciclo/consumo (Lettau-Ludvigson); su talón de Aquiles es la magnitud observada.');
insert into questions(id,section_id,prompt,justification) values (585,4,'La reversión de largo plazo documentada por De Bondt &amp; Thaler (1985) muestra que:','De Bondt-Thaler (1985) hallaron que las carteras de perdedores extremos superan a las de ganadores extremos en horizontes largos: evidencia de sobre-reacción y reversión.');
insert into questions(id,section_id,prompt,justification) values (586,4,'La Porta et al. (1997) muestran que el premio de value se concentra en los días de anuncios de resultados. ¿Qué implica esto?','Que el retorno se materialice justo cuando llegan las noticias sugiere corrección de expectativas erróneas, no una prima de riesgo constante.');
insert into questions(id,section_id,prompt,justification) values (587,4,'La Porta (1996) encontró que las expectativas de crecimiento de los analistas predicen los retornos "al revés". Esto significa que:','La sobre-extrapolación del crecimiento lleva a sobrevalorar <em>glamour</em>; cuando los fundamentos revierten, esos nombres decepcionan (spread ~15% anual, confirmado por Bordalo et al. 2019).');
insert into questions(id,section_id,prompt,justification) values (588,4,'Los tres modelos conductuales seminales (BSV, DHS y Hong-Stein) convergen en una misma narrativa:','Los tres modelos formalizan una secuencia común: la información se incorpora lentamente (sub-reacción → momentum) y luego el precio sobrepasa el valor y revierte (→ value).');
insert into questions(id,section_id,prompt,justification) values (589,4,'El modelo BSV (1998, Barberis-Shleifer-Vishny) explica momentum y reversión a partir de:','En BSV, un único inversor representativo alterna regímenes (proceso de Markov): conservadurismo produce sub-reacción; representatividad, sobre-reacción.');
insert into questions(id,section_id,prompt,justification) values (590,4,'El modelo DHS (1998, Daniel-Hirshleifer-Subrahmanyam) atribuye el patrón a:','En DHS, el inversor confía de más en su información privada y atribuye los aciertos a su talento; el precio sobrepasa el valor y luego revierte.');
insert into questions(id,section_id,prompt,justification) values (591,4,'El modelo Hong-Stein (1999) se distingue porque explica el fenómeno mediante:','Hong-Stein parte de difusión gradual de información entre <em>newswatchers</em> (sub-reacción) que luego los <em>momentum traders</em> llevan al exceso (sobre-reacción).');
insert into questions(id,section_id,prompt,justification) values (592,4,'El conservadurismo, documentado por Edwards (1968), sostiene que:','Al anclar en el estado previo, la actualización insuficiente hace que el precio siga ajustándose semanas después del anuncio (post-earnings-announcement drift).');
insert into questions(id,section_id,prompt,justification) values (593,4,'Que la prospect theory estime un coeficiente de aversión a las pérdidas λ ≈ 2.25 significa que:','La utilidad se mide relativa a un punto de referencia; con λ ≈ 2.25, el dolor de perder supera al placer de ganar una cantidad igual.');
insert into questions(id,section_id,prompt,justification) values (594,4,'Según Shleifer &amp; Vishny (1997), los "límites al arbitraje" implican que:','El arbitraje real es riesgoso y financiado con capital que huye tras pérdidas; por eso los errores no se eliminan al instante y persisten en horizontes medibles.');
insert into questions(id,section_id,prompt,justification) values (595,4,'El "noise trader risk" de De Long, Shleifer, Summers &amp; Waldmann (1990) sostiene que:','Como el sentimiento puede empeorar antes de revertir, apostar contra los <em>noise traders</em> conlleva riesgo; ese riesgo permite que el mispricing persista.');
insert into questions(id,section_id,prompt,justification) values (596,4,'El X-CAPM (Barberis, Greenwood, Jin &amp; Shleifer, 2015) se diferencia del CAPM porque:','El X-CAPM incorpora extrapolación de retornos pasados (los inversionistas esperan que las rachas continúen), generando sobre/sub-reacción endógenas.');
insert into questions(id,section_id,prompt,justification) values (597,13,'Asness, Moskowitz &amp; Pedersen (2013), "Value and Momentum Everywhere", documentan que:','El artículo (Journal of Finance) muestra primas de value y momentum en múltiples clases de activos y una correlación negativa entre ambos estilos.');
insert into questions(id,section_id,prompt,justification) values (598,13,'La ventaja de combinar value y momentum proviene principalmente de:','La "aritmética de la diversificación": el Sharpe combinado depende de la correlación entre estilos; en un año uno sufre y el otro compensa, colapsando la volatilidad sin sacrificar la media (~6%).');
insert into questions(id,section_id,prompt,justification) values (599,13,'El "value spread" se define como:','Es una medida del "cuán barato está lo barato frente a lo caro"; su amplitud informa sobre el retorno esperado futuro del estilo.');
insert into questions(id,section_id,prompt,justification) values (600,13,'La lectura de AQR (Asness; Israel, Laursen &amp; Richardson, 2020–2021) sobre la caída de value sostiene que:','AQR descompone la caída y concluye que fue casi toda <em>spread</em> (valuación), no fundamentos; por eso ubican el punto de "máximo dolor" como el de mayor premio esperado.');
insert into questions(id,section_id,prompt,justification) values (601,13,'Los "momentum crashes" (Daniel &amp; Moskowitz, 2016) se caracterizan porque:','En los rebotes tras caídas fuertes, la cartera de momentum (corta en los perdedores que rebotan) sufre pérdidas abruptas: retornos con sesgo negativo y colas izquierdas.');
insert into questions(id,section_id,prompt,justification) values (602,13,'El hallazgo de McLean &amp; Pontiff (2016) —las anomalías pierden ~la mitad de su prima tras publicarse— se usa como argumento de que:','Que la prima caiga (pero no desaparezca, por límites al arbitraje) al volverse conocida es difícil de conciliar con una compensación por riesgo estable.');
insert into questions(id,section_id,prompt,justification) values (603,13,'La dependencia del sentimiento (Stambaugh-Yu-Yuan) indica que las anomalías:','Si las primas dependieran solo del riesgo, no deberían variar con el sentimiento; su fortalecimiento tras el optimismo sugiere mispricing.');
insert into questions(id,section_id,prompt,justification) values (604,13,'La advertencia "value no es una sola cosa" se refiere a que:','Distintas razones de valuación capturan aspectos diferentes; la elección de métrica altera qué acciones entran y cómo se comporta la estrategia.');
insert into questions(id,section_id,prompt,justification) values (605,13,'En términos de implementación, value y momentum se distinguen porque:','La cartera de momentum se recompone con frecuencia; la de value puede tardar años en dar la razón, lo que pone a prueba la disciplina del inversionista.');
insert into questions(id,section_id,prompt,justification) values (606,13,'La robustez reportada en "Value and Momentum Everywhere" indica que:','La superioridad del combo se sostiene en distintos subperiodos y condiciones de liquidez, reforzando que no es casualidad muestral.');
insert into questions(id,section_id,prompt,justification) values (607,13,'La descripción correcta del <em>Global Equity Factor</em> (GEF) de GBM es:','GEF no es un factor puro <em>long-short</em>: es un portafolio de renta variable global con <em>tilt</em> a momentum (la exposición de mercado sigue dominando), por lo que exhibe el perfil de crecimiento y <em>drawdowns</em> propio del estilo.');
insert into questions(id,section_id,prompt,justification) values (608,5,'La síntesis del rol del asesor frente a value y momentum es que agrega valor:','Las primas de factor nacen de sesgos del mercado; capturarlas exige sostener la estrategia pese a los sesgos del propio cliente —ahí es donde el acompañamiento conductual del asesor es decisivo.');
insert into questions(id,section_id,prompt,justification) values (609,12,'El ETF SPY (SPDR S&amp;P 500) se distingue porque:','SPY, lanzado en 1993 por State Street (marca SPDR), fue el primer ETF estadounidense y sigue al índice S&amp;P 500 de grandes empresas de EE. UU.');
insert into questions(id,section_id,prompt,justification) values (610,12,'El ETF VOO (Vanguard S&amp;P 500):','VOO sigue al S&amp;P 500 con un costo de 0.03%; superó a SPY como el mayor ETF del mundo en 2025 y cruzó US$1 trillion (billón anglosajón) en junio de 2026.');
insert into questions(id,section_id,prompt,justification) values (611,12,'SPY, VOO e IVV coinciden en que:','IVV (iShares Core S&amp;P 500, de BlackRock), VOO (Vanguard) y SPY (State Street) dan la misma exposición al S&amp;P 500; se diferencian en comisión (VOO/IVV 0.03% vs. SPY ~0.09%) y estructura.');
insert into questions(id,section_id,prompt,justification) values (612,12,'Una diferencia estructural de SPY frente a VOO e IVV es que:','Como UIT, SPY mantiene los dividendos en efectivo hasta la distribución trimestral; los fondos abiertos (VOO, IVV) pueden reinvertirlos de inmediato.');
insert into questions(id,section_id,prompt,justification) values (613,12,'El ETF QQQ (Invesco QQQ) da exposición a:','QQQ replica el Nasdaq-100, concentrado en grandes tecnológicas (las "Magnificent Seven" pesan una parte importante).');
insert into questions(id,section_id,prompt,justification) values (614,12,'El VanEck Semiconductor ETF (SMH) invierte en:','SMH es un ETF sectorial concentrado en semiconductores; por ello es más volátil y menos diversificado que un índice amplio.');
insert into questions(id,section_id,prompt,justification) values (615,12,'El iShares Russell 2000 ETF (IWM) ofrece exposición a:','IWM replica el Russell 2000, el referente de <em>small caps</em> estadounidenses.');
insert into questions(id,section_id,prompt,justification) values (616,12,'El iShares MSCI USA Momentum Factor ETF (MTUM) selecciona acciones por:','MTUM sigue el índice MSCI USA Momentum, que sobrepondera acciones de EE. UU. con fuerte momentum de precio.');
insert into questions(id,section_id,prompt,justification) values (617,12,'El iShares Edge MSCI World Momentum Factor UCITS ETF (IWMO):','IWMO (iShares, BlackRock) sigue el MSCI World Momentum —acciones de 23 países desarrollados con alto momentum— bajo estructura UCITS europea.');
insert into questions(id,section_id,prompt,justification) values (618,12,'¿En qué se diferencian MTUM e IWMO, siendo ambos ETFs de momentum?','Comparten el factor (momentum) pero difieren en universo geográfico y marco regulatorio (EE. UU. vs. mundo desarrollado / UCITS).');
insert into questions(id,section_id,prompt,justification) values (619,12,'El iShares MSCI ACWI ETF (ACWI) ofrece exposición a:','ACWI replica el MSCI ACWI, que combina países desarrollados y emergentes en un solo índice accionario global.');
insert into questions(id,section_id,prompt,justification) values (620,12,'El Vanguard Total World Stock ETF (VT) se caracteriza por:','VT sigue el FTSE Global All Cap: prácticamente "el mercado accionario mundial" en un ETF, incluidas <em>small caps</em>.');
insert into questions(id,section_id,prompt,justification) values (621,12,'El Vanguard Total Stock Market ETF (VTI) replica:','A diferencia de VOO (solo S&amp;P 500), VTI abarca todo el espectro de capitalización del mercado estadounidense.');
insert into questions(id,section_id,prompt,justification) values (622,12,'El Vanguard Growth ETF (VUG) invierte en:','VUG sobrepondera acciones <em>growth</em> de gran capitalización de EE. UU.; es el complemento de un ETF de estilo <em>value</em>.');
insert into questions(id,section_id,prompt,justification) values (623,12,'El iShares Bitcoin Trust (IBIT) ofrece:','IBIT mantiene Bitcoin al contado; permite exposición a la criptomoneda dentro de una cuenta de valores tradicional.');
insert into questions(id,section_id,prompt,justification) values (624,12,'El iShares 20+ Year Treasury Bond ETF (TLT) invierte en:','Al concentrar Treasuries de muy largo plazo, TLT tiene una duración elevada: su precio sube o baja con fuerza ante cambios en las tasas.');
insert into questions(id,section_id,prompt,justification) values (625,12,'El Vanguard Total Bond Market ETF (BND) ofrece:','BND replica el "Agg", que agrupa Treasuries, bonos de agencias, corporativos IG y titulizados de EE. UU.; es un núcleo de renta fija diversificado.');
insert into questions(id,section_id,prompt,justification) values (626,12,'¿Cuál es la diferencia clave entre TLT y BND?','TLT es una apuesta de duración larga (Treasuries 20+ años); BND busca exposición amplia y equilibrada a la renta fija estadounidense.');
insert into questions(id,section_id,prompt,justification) values (627,12,'El SPDR Gold Shares (GLD) da exposición a:','GLD está respaldado por oro físico en custodia; su valor sigue el precio del metal, no a empresas mineras.');
insert into questions(id,section_id,prompt,justification) values (628,12,'El iShares NAFTRAC replica:','NAFTRAC (emitido por Nacional Financiera y gestionado por BlackRock México) sigue el S&amp;P/BMV IPC; permite invertir en la bolsa mexicana con un solo instrumento. Excluye FIBRAs del índice.');
